const e=[{id:"party-0001",location:"party",arc:"party-t0-a0",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["election","caretaker","legitimacy"],prompt:"Your helper says you must let a fair, neutral team run the election, or the other side will quit and say you cheated.",left:{id:"a",label:"Refuse and run the election yourself.",tooltip:"A contest I run is a contest I survive.",reveal:"You keep control of the machinery and win the seats. Turnout is thin, the opposition cries fraud, and your mandate carries an asterisk abroad.",effects:{MI:8,GL:-16,EN:-10}},right:{id:"b",label:"Let the fair team run the election.",tooltip:"A legitimate loss beats an illegitimate win.",reveal:"You gamble on a clean vote. The world applauds the rare concession; your own machine panics that you have bet the house on the people.",effects:{GL:8,EN:5,MI:-16}}},{id:"party-0002",location:"party",arc:"party-t0-a0",stage:1,speaker:"General Secretary",portrait:"fixer",tags:["election","caretaker","legitimacy"],prompt:"The votes are close. You can secretly change the counting to make sure you win, but people might notice.",left:{id:"a",label:"Secretly change the votes to win.",tooltip:"A majority is not left to chance.",reveal:"Your majority is secured and unmistakably engineered. Observers document the irregularities; the result is yours and rotten at the root.",effects:{MI:6,GL:-16,EN:-13,FA:3}},right:{id:"b",label:"Let the real counting decide, even if you lose.",tooltip:"A stolen seat is a debt that comes due.",reveal:"You accept the honest tally and a slimmer majority. Governing is harder; the legitimacy you keep may matter more than the seats you lost.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0003",location:"party",arc:"party-t0-a1",stage:0,speaker:"Election Commission Liaison",portrait:"official",tags:["ec","institutions","appointments"],prompt:"You get to pick the new voting judges. You can pick your friends who will let you win, or honest people who might rule against you.",left:{id:"a",label:"Pick your friends to be the judges.",tooltip:"An umpire I pick does not call me out.",reveal:"The Commission becomes an extension of your office. It serves you flawlessly — and the institution's credibility, once spent, will not return when you need it.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Pick honest, fair people.",tooltip:"A referee everyone trusts protects the winner too.",reveal:"You stack the body with respected names. They will sometimes rule against you, but the elections they bless will be believed.",effects:{GL:6,EN:5,MI:-13}}},{id:"party-0004",location:"party",arc:"party-t0-a2",stage:0,speaker:"Street Operations Coordinator",portrait:"fixer",tags:["hartal","blockade","violence"],prompt:"Your enemies are blocking the roads. You can send your own fighters to stop them, but it will be very violent.",left:{id:"a",label:"Send your fighters to stop them.",tooltip:"Meet their streets with ours.",reveal:"Your cadres clear the roads in running battles. Commerce resumes amid the wreckage, and the cycle of street violence now belongs to you both.",effects:{MI:6,EN:-16,FI:3,GL:-10}},right:{id:"b",label:"Let the police handle it safely.",tooltip:"Two mobs are worse than one.",reveal:"You refuse to militarise your supporters and let the police protect the routes. The blockade drags on and the economy bleeds, but no partisan blood is on your hands.",effects:{GL:3,EN:3,MI:-10,FI:-10}}},{id:"party-0005",location:"party",arc:"party-t0-a3",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["defection","coalition","horse-trading"],prompt:"You are losing votes. You can secretly promise bad politicians jobs and safety if they switch to your team.",left:{id:"a",label:"Buy their votes with jobs and safety.",tooltip:"A secured floor is worth a few favours.",reveal:"The MPs cross and your majority is iron. The cabinet bloats with bought men, their cases frozen, and the public reads the price tag.",effects:{MI:6,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Refuse to make secret, bad deals.",tooltip:"I will not staff a government with men I had to bribe.",reveal:"You decline the deal and govern on a knife-edge. Every vote is now a fight, but no minister sits in your cabinet to dodge a courtroom.",effects:{GL:5,EN:3,MI:-13}}},{id:"party-0006",location:"party",arc:"party-t0-a4",stage:0,speaker:"Religious Front Emissary",portrait:"cleric",tags:["islamist","alliance","secularism"],prompt:"A powerful religious group will help you win, but only if you make strict religious laws and take away women's rights.",left:{id:"a",label:"Take their help and make the strict laws.",tooltip:"Their squares are full and my margins are thin.",reveal:"Their mobilisation is yours now, and so are their conditions. The curriculum narrows, reformers despair, and your secular base feels sold.",effects:{MI:8,FA:3,EN:-16,GL:-13}},right:{id:"b",label:"Say no and protect everyone's rights.",tooltip:"I will not trade women's rights for a turnout.",reveal:"You refuse their terms. They can now march against you instead of with you, but the constitution's spine, and your liberal base, hold.",effects:{EN:6,GL:5,MI:-13}}},{id:"party-0007",location:"party",arc:"party-t0-a5",stage:0,speaker:"Tribunal Prosecutor",portrait:"official",tags:["1971","tribunal","justice"],prompt:"You are putting old war criminals on trial. You can rush the trials to punish them fast, or go slowly to be totally fair.",left:{id:"a",label:"Rush the trials to punish them fast.",tooltip:"Justice delayed is the guilty escaping.",reveal:"The convictions land quickly to roaring crowds, and your opposition is gutted. Legal observers question the haste, and the verdicts carry that shadow.",effects:{MI:6,FA:3,GL:-10,EN:3}},right:{id:"b",label:"Go slowly and make sure the trials are fair.",tooltip:"A reckoning built on shortcuts collapses.",reveal:"You demand rigorous trials. The base grows impatient and the weapon is blunter, but the verdicts that come will withstand history's scrutiny.",effects:{GL:6,EN:3,MI:-10}}},{id:"party-0008",location:"party",arc:"party-t0-a6",stage:0,speaker:"Student Wing President",portrait:"fixer",tags:["students","campus","extortion"],prompt:"Your student group is bullying kids at school. They want more power, but some say you need to stop their bullying.",left:{id:"a",label:"Give your student group more power.",tooltip:"The campuses are a fortress I cannot lose.",reveal:"The wing tightens its grip and delivers the campuses. Its abuses grow more brazen, a powder keg awaiting one viral video.",effects:{MI:6,EN:-16,GL:-10}},right:{id:"b",label:"Stop them and punish the bullies.",tooltip:"A wing that tortures students will one day burn me.",reveal:"You discipline the bosses and cut the extortion. The campuses loosen from your grip, but you have defused a bomb under your own house.",effects:{EN:6,GL:3,MI:-13}}},{id:"party-0009",location:"party",arc:"party-t0-a7",stage:0,speaker:"Party Elders' Council",portrait:"official",tags:["succession","dynasty","loyalty"],prompt:"The older leaders want you to name your child as the next boss right now. Others say you should pick the smartest person, not just your family.",left:{id:"a",label:"Name your child as the next boss.",tooltip:"A clear heir prevents a war of knives.",reveal:"The dynasty is secured and the council placated. Capable non-family leaders drift away, and the party's depth thins to a single bloodline.",effects:{MI:5,FA:6,GL:-6,EN:-6}},right:{id:"b",label:"Pick the smartest person instead.",tooltip:"A party is not an inheritance.",reveal:"You refuse to crown an heir and invite a real contest. The family is wounded and the council nervous, but the party keeps its best minds.",effects:{GL:5,EN:3,FA:-13,MI:-6}}},{id:"party-0010",location:"party",arc:"party-t0-a8",stage:0,speaker:"Attorney General",portrait:"official",tags:["opposition","courts","lawfare"],prompt:"A judge will put your biggest enemy in jail for an old crime if you want. This means she can't run against you in the election.",left:{id:"a",label:"Have the judge put her in jail.",tooltip:"Remove the rival, remove the race.",reveal:"She is sentenced and disqualified. Her party erupts and the chanceries issue statements, but the ballot now has no name on it but yours.",effects:{MI:8,GL:-16,EN:-10}},right:{id:"b",label:"Let the judge decide fairly on his own.",tooltip:"A throne with no challenger is a target.",reveal:"You refuse to script the verdict. She may yet stand against you, but no one can say you jailed your way to power.",effects:{GL:6,EN:5,MI:-13}}},{id:"party-0011",location:"party",arc:"party-t0-a8",stage:1,speaker:"Attorney General",portrait:"official",tags:["opposition","courts","lawfare"],prompt:"Your enemy is very sick in jail. If she dies there, everyone will hate you. Her family begs to take her to a hospital.",left:{id:"a",label:"Keep her locked in the jail.",tooltip:"A martyr in a cell is safer than a saint set free.",reveal:"You hold firm and the cell stays locked. Her health worsens in the headlines, and every cough becomes an indictment of you.",effects:{MI:5,GL:-13,EN:-13}},right:{id:"b",label:"Let her go to the hospital.",tooltip:"I will not let a corpse defeat me.",reveal:"You let her convalesce under guard at home. The base grumbles that the snake is loose, but you have denied her the one victory captivity offered.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0012",location:"party",arc:"party-t0-a9",stage:0,speaker:"Telecom Regulator",portrait:"official",tags:["internet","election","censorship"],prompt:"You can turn off the internet on voting day so no one can see if you cheat.",left:{id:"a",label:"Turn off the internet on voting day.",tooltip:"What the cameras cannot upload did not happen.",reveal:"The country goes dark and the count proceeds unwatched. The result is clean-looking and universally disbelieved; the outage itself becomes the story.",effects:{MI:6,GL:-16,FI:-10,EN:-10}},right:{id:"b",label:"Keep the internet on for everyone.",tooltip:"A vote no one can film is a vote no one believes.",reveal:"You let the signal flow. Every irregularity is livestreamed, but so is every honest queue, and the result keeps its credibility.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0013",location:"party",arc:"party-t0-a10",stage:0,speaker:"District Organiser",portrait:"fixer",tags:["vote-buying","patronage","money"],prompt:"A helper wants to hand out secret envelopes of cash and free things to poor people the night before the vote to make them pick you.",left:{id:"a",label:"Give out the secret cash and free things.",tooltip:"An empty stomach has a short memory.",reveal:"The trucks roll out and the margins firm up. The treasury thins, the habit deepens, and your win smells of the bazaar.",effects:{MI:6,FI:-13,EN:-6,GL:-6}},right:{id:"b",label:"Say no and win fairly without bribes.",tooltip:"Buy a vote once and you rent it forever.",reveal:"You forbid the envelopes and campaign on roads and clinics built. The organisers fret over thin margins, but the votes you win, you keep.",effects:{EN:6,GL:5,FI:3,MI:-10}}},{id:"party-0014",location:"party",arc:"party-t0-a11",stage:0,speaker:"Electoral Roll Officer",portrait:"official",tags:["voter-roll","fraud","ghosts"],prompt:"The voting list has thousands of fake names and dead people on it. You can use these fake names to cheat and get more votes.",left:{id:"a",label:"Keep the fake names to get more votes.",tooltip:"A loyal voter need not be a living one.",reveal:"The phantom names stay, ready to be voted. Auditors will find them eventually, and when they do the whole tally is tainted.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Delete the fake names for a fair vote.",tooltip:"Ghosts vote, but they also haunt.",reveal:"You scrub the list to the living. Your stronghold margins shrink honestly, and the register can finally survive a recount.",effects:{GL:6,EN:5,MI:-13}}},{id:"party-0015",location:"party",arc:"party-t0-a12",stage:0,speaker:"Nominations Board Chair",portrait:"fixer",tags:["tickets","candidates","money"],prompt:"Many people want to be on your team. You can let the richest people buy their spots, or pick the people who work the hardest.",left:{id:"a",label:"Let the richest people buy the spots.",tooltip:"A campaign runs on cash, not character.",reveal:"The war chest fills in a week with businessmen-MPs who bought their seats. They will legislate for their own ledgers, and the grassroots see who was passed over.",effects:{FI:8,MI:3,EN:-13,GL:-10}},right:{id:"b",label:"Pick the hardest workers.",tooltip:"A bought candidate serves the buyer, not the booth.",reveal:"You hand seats to organisers who earned them. The campaign chest stays lean, but your benches fill with people the wards actually know.",effects:{EN:6,GL:3,MI:3,FI:-13}}},{id:"party-0016",location:"party",arc:"party-t0-a13",stage:0,speaker:"Media Adviser",portrait:"fixer",tags:["media","propaganda","press"],prompt:"A rich friend offers to buy all the TV stations so they only say nice things about you and ignore your mistakes.",left:{id:"a",label:"Let him buy the TV stations.",tooltip:"He who owns the screen owns the story.",reveal:"The airwaves turn to praise overnight. Dissent migrates to the shadows of the internet, and 'press freedom' becomes a foreign talking point against you.",effects:{MI:6,FA:3,GL:-13,EN:-10}},right:{id:"b",label:"Say no and let the TV stations be honest.",tooltip:"A choir of yes-men cannot warn me of fire.",reveal:"You wave the tycoon off. The critical broadcasts sting nightly, but they are also the only honest mirror your government has.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0017",location:"party",arc:"party-t0-a14",stage:0,speaker:"Cyber Cell Commander",portrait:"shadow",tags:["trolls","disinformation","online"],prompt:"Your computer team wants to make thousands of fake internet accounts to spread lies about your enemies and trick people.",left:{id:"a",label:"Pay the computer team to spread lies.",tooltip:"The first lie of the morning sets the day.",reveal:"Ten thousand sock-puppets march on command. The discourse rots, journalists are doxxed, and when the operation leaks it confirms every accusation of manipulation.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Shut the computer team down.",tooltip:"An army of lies eventually turns its guns inward.",reveal:"You disband the operation. Your opponents own more of the timeline now, but your name is off the next disinformation exposé.",effects:{GL:5,EN:5,MI:-10}}},{id:"party-0018",location:"party",arc:"party-t0-a15",stage:0,speaker:"Coalition Manager",portrait:"official",tags:["coalition","allies","leverage"],prompt:"Your partner team threatens to leave unless you give them big jobs. If they leave, you might lose your power.",left:{id:"a",label:"Give them the big jobs so they stay.",tooltip:"A government standing is worth a crowded cabinet.",reveal:"You hand over the posts and the floor holds. Your partner struts as near-equal, and your own MPs resent the ministries they were promised.",effects:{MI:5,FA:-6,EN:-6,GL:3}},right:{id:"b",label:"Tell them no and let them leave.",tooltip:"I will not be governed by my own junior.",reveal:"You refuse, and they storm out. The arithmetic tightens to a knife's edge, but every remaining minister knows you do not bend to blackmail.",effects:{MI:-13,FA:5,EN:3}}},{id:"party-0019",location:"party",arc:"party-t0-a16",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["parliament","no-confidence","discipline"],prompt:"Some of your own teammates might vote against you because they are angry. You can scare them into obeying, or actually fix what they are angry about.",left:{id:"a",label:"Scare them into obeying you.",tooltip:"Discipline is taught in the dark.",reveal:"The waverers fall back into line, cowed. The motion dies, but a dozen MPs now serve you out of fear, and fear is a thin glue.",effects:{MI:6,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Listen to them and fix the problem.",tooltip:"A backbencher heard is a backbencher kept.",reveal:"You meet the rebels, concede a real reform, and win the floor in daylight. It cost you policy ground, but the loyalty you bought is genuine.",effects:{EN:5,GL:5,MI:-6}}},{id:"party-0020",location:"party",arc:"party-t0-a17",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["constitution","term-limits","power"],prompt:"You can change the rules so you are allowed to be the boss forever. But this shows everyone you never plan to leave.",left:{id:"a",label:"Change the rules to be boss forever.",tooltip:"Reform takes longer than a term allows.",reveal:"The amendment passes and the horizon clears. At home it reads as ambition unmasked; abroad, as one more strongman erasing his own exit.",effects:{MI:6,FA:3,GL:-16,EN:-13}},right:{id:"b",label:"Keep the rules normal.",tooltip:"A door I cannot lock behind me keeps me honest.",reveal:"You let the constraint stand. The dynasty's grip looks less total, but you have spared yourself the label of president-for-life.",effects:{GL:6,EN:5,MI:-6}}},{id:"party-0021",location:"party",arc:"party-t0-a18",stage:0,speaker:"Home Secretary",portrait:"official",tags:["banning","rivals","repression"],prompt:"You have a sneaky excuse to completely ban the enemy team so they can't run against you at all.",left:{id:"a",label:"Ban the enemy team.",tooltip:"A weed pulled does not seed.",reveal:"The party is dissolved and its cadres scattered or jailed. Your dominance is near-total, and so is the proof that you fear a fair fight.",effects:{MI:8,GL:-16,EN:-13}},right:{id:"b",label:"Let them run and try to beat them fairly.",tooltip:"A banned party becomes a legend; a beaten one becomes a footnote.",reveal:"You leave the rival legal and defeat it in the open. It survives to fight again, but your win carries no asterisk.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0022",location:"party",arc:"party-t0-a19",stage:0,speaker:"Party Treasurer",portrait:"fixer",tags:["funding","patrons","graft"],prompt:"A rich man who gave you a lot of money now wants special favors, like a free bank. You need his money for the next election.",left:{id:"a",label:"Give him the special favors.",tooltip:"The hand that feeds expects to be kissed.",reveal:"He gets his licence and his concession. The campaign chest is safe for another cycle, and a single oligarch now owns a wing of your economy.",effects:{FI:6,MI:3,EN:-13,GL:-10}},right:{id:"b",label:"Say no and find honest money instead.",tooltip:"A party owned by one man has only one voter.",reveal:"You turn him down and scramble for funding elsewhere. The next campaign will be leaner and harder, but no single patron holds your leash.",effects:{GL:5,EN:5,FI:-13}}},{id:"party-0023",location:"party",arc:"party-t0-a20",stage:0,speaker:"Ward Boss",portrait:"shadow",tags:["mastan","extortion","control"],prompt:"Your best helper wins lots of votes, but he does it by being a scary bully and stealing from people.",left:{id:"a",label:"Keep the bully because he gets you votes.",tooltip:"A made ward is a won ward.",reveal:"He keeps delivering, and keeps grabbing. His enemies pile up, and one of his victims will eventually find a camera.",effects:{MI:6,EN:-13,GL:-6}},right:{id:"b",label:"Fire the bully to keep things clean.",tooltip:"A boss who owns the booth will one day own me.",reveal:"You strip him of cover and let the cases proceed. The ward's turnout machine sputters, but a liability has been removed before it blew.",effects:{EN:6,GL:3,MI:-13}}},{id:"party-0024",location:"party",arc:"party-t0-a21",stage:0,speaker:"Women's Wing Chief",portrait:"official",tags:["women","representation","reserved-seats"],prompt:"You get to pick women for special government seats. You can pick hard-working leaders, or just pick the wives of your rich friends.",left:{id:"a",label:"Pick the wives of your rich friends.",tooltip:"The seats are a thank-you, not a ladder.",reveal:"Donors' wives take the benches and vote as told. The women's wing seethes, and the reform you boast of abroad rings hollow at home.",effects:{FA:5,FI:3,EN:-10,GL:-6}},right:{id:"b",label:"Pick the hard-working women leaders.",tooltip:"A reserved seat should hold a leader, not a placeholder.",reveal:"You elevate women who built the wards. The donors grumble at the snub, but your benches gain voices that actually represent someone.",effects:{EN:6,GL:5,FA:-6,MI:-3}}},{id:"party-0025",location:"party",arc:"party-t0-a22",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["defection","loyalty","betrayal"],prompt:"A good guy on your team might leave to join the enemies. You can ruin his life with a fake secret, or talk to him nicely to keep him.",left:{id:"a",label:"Ruin his life with a fake secret.",tooltip:"A loud man is silenced before he sings.",reveal:"The file leaks and his reputation buckles before he can cross. He is neutralised, and every honest MP learns what conscience costs in your party.",effects:{MI:6,FA:3,EN:-13,GL:-10}},right:{id:"b",label:"Talk to him nicely and fix his worries.",tooltip:"An honest critic kept is worth ten bought loyalists.",reveal:"You hear him out and act on one grievance. He stays, vocal but yours, and the benches see that integrity has a place after all.",effects:{EN:6,GL:5,MI:-6}}},{id:"party-0026",location:"party",arc:"party-t0-a23",stage:0,speaker:"Rally Coordinator",portrait:"fixer",tags:["rally","spectacle","mobilisation"],prompt:"You can spend a giant amount of money to bus a million people to the city just to cheer for you and look powerful.",left:{id:"a",label:"Spend the money for the giant cheering crowd.",tooltip:"Power unseen is power doubted.",reveal:"The maidan overflows and the footage dominates the week. The cost is staggering and the city paralysed, but no one questions your reach.",effects:{MI:6,FA:3,FI:-13,EN:-6}},right:{id:"b",label:"Save the money and have a small, normal meeting.",tooltip:"A crowd I had to rent proves nothing.",reveal:"You convene a focused, modest gathering. The spectacle is smaller, but the treasury and the city's patience are spared, and the agenda actually gets done.",effects:{FI:5,EN:3,MI:-6}}},{id:"party-0027",location:"party",arc:"party-t0-a24",stage:0,speaker:"Tribunal Prosecutor",portrait:"official",tags:["1971","execution","timing"],prompt:"You can hang a bad war criminal right before the election to make your fans cheer.",left:{id:"a",label:"Hang the criminal right before the election.",tooltip:"Justice and the calendar can keep step.",reveal:"The hanging lands days before the vote and the base roars. The cynicism is noted at home and abroad — a reckoning turned into a campaign prop.",effects:{MI:6,FA:3,EN:3,GL:-10}},right:{id:"b",label:"Let the law happen on its own normal time.",tooltip:"A gallows is not a campaign poster.",reveal:"You let the process conclude when it concludes. The base would have preferred the theatre, but the verdict keeps its dignity intact.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0028",location:"party",arc:"party-t0-a25",stage:0,speaker:"Culture Minister",portrait:"official",tags:["legacy","dynasty","naming"],prompt:"Your friends want to name the airport, schools, and bridges after your family so no one ever forgets you.",left:{id:"a",label:"Say yes and name everything after your family.",tooltip:"A name on the map is a claim on the future.",reveal:"The signs change across the country. Your lineage is everywhere now — and so is the evidence, for critics, of a personality cult.",effects:{FA:6,MI:3,EN:-10,GL:-10}},right:{id:"b",label:"Say no to renaming everything.",tooltip:"A dynasty secure in itself need not shout.",reveal:"You let the airports keep their names. The family's elders sulk at the modesty, but the state stays larger than your bloodline.",effects:{GL:5,EN:3,FA:-10}}},{id:"party-0029",location:"party",arc:"party-t0-a26",stage:0,speaker:"Polling Agent Coordinator",portrait:"fixer",tags:["booth-capture","election-day","violence"],prompt:"On voting day, your team can secretly kick out the other team's checkers and stuff the boxes with fake votes for you.",left:{id:"a",label:"Tell your team to stuff the boxes with fake votes.",tooltip:"The last hour decides the count.",reveal:"The boxes fill and the seats are yours. Phone videos of ejected agents go viral by nightfall, and the dozen seats become a dozen scandals.",effects:{MI:6,GL:-16,EN:-13}},right:{id:"b",label:"Tell them to stop and keep the voting fair.",tooltip:"A captured booth is a confession on film.",reveal:"You order the agents to stand down and the count to stand. You may lose some of the twelve, but you keep the only thing a margin is worth — belief.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0030",location:"party",arc:"party-t0-a27",stage:0,speaker:"Party Elders' Council",portrait:"official",tags:["generations","renewal","loyalty"],prompt:"The very old leaders won't give up their jobs to the younger, smarter people. If you force them out, they will be mad.",left:{id:"a",label:"Let the old leaders keep their jobs.",tooltip:"Loyalty earned over decades is not lightly retired.",reveal:"The veterans stay and the peace holds. The talented young drift toward NGOs and business, and the party ages with its leaders.",effects:{FA:3,MI:3,EN:-6,GL:-6}},right:{id:"b",label:"Give the jobs to the younger, smarter people.",tooltip:"A party that cannot renew itself buries itself.",reveal:"You move the forty-somethings into real power. The elders are wounded and noisy, but the benches suddenly have a future tense.",effects:{EN:6,GL:5,FA:-10,MI:-3}}},{id:"party-0031",location:"party",arc:"party-t0-a28",stage:0,speaker:"Parliamentary Affairs Minister",portrait:"official",tags:["speaker","parliament","fairness"],prompt:"You get to pick the referee for the big government meetings. You can pick your friend who always lets you win, or a fair person.",left:{id:"a",label:"Pick your friend who always lets you win.",tooltip:"The chair should sit on my side of the aisle.",reveal:"Bills sail through and the opposition is muzzled at every turn. The house becomes a rubber stamp, and parliament's last shred of theatre dies.",effects:{MI:5,GL:-10,EN:-10}},right:{id:"b",label:"Pick a fair person.",tooltip:"A fair umpire makes my wins count.",reveal:"The house gets a Speaker both sides respect. Your rivals get their moments, but the chamber's rulings carry weight again.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0032",location:"party",arc:"party-t0-a29",stage:0,speaker:"Overseas Wing Secretary",portrait:"fixer",tags:["diaspora","funding","foreign"],prompt:"Your friends in other countries want to send you lots of secret money for your campaign. It is illegal to take secret foreign money.",left:{id:"a",label:"Take the secret foreign money.",tooltip:"A son abroad still pays his mother's bills.",reveal:"The funds arrive off the books and the chest swells. Somewhere a paper trail survives, and when it surfaces it will read as foreign money buying your government.",effects:{FI:6,MI:2,GL:-13,EN:-6}},right:{id:"b",label:"Say no to the illegal money.",tooltip:"Money I cannot name is a leash I cannot see.",reveal:"You insist on clean, declared donations only. The chest grows slower, but no foreign-funding exposé waits in your future.",effects:{GL:5,EN:3,FI:-10}}},{id:"party-0033",location:"party",arc:"party-t0-a30",stage:0,speaker:"Minorities Cell Convenor",portrait:"official",tags:["minorities","secularism","vote-bank"],prompt:"Small religious groups always vote for you, but they are being attacked. They want you to protect them loudly, which might upset the big groups.",left:{id:"a",label:"Just say sorry, but don't upset the big groups.",tooltip:"A bloc that has nowhere else to go waits patiently.",reveal:"You issue statements and little else. The minorities feel taken for granted, and the next attack erodes a loyalty you assumed was permanent.",effects:{MI:2,EN:-10,GL:-6}},right:{id:"b",label:"Protect them loudly and punish the attackers.",tooltip:"A protected vote is a kept vote.",reveal:"You deploy security and jail the ringleaders. The hardline preachers rage, but the minority bloc rallies to you with real gratitude.",effects:{EN:6,GL:5,MI:-6,FA:-3}}},{id:"party-0034",location:"party",arc:"party-t0-a31",stage:0,speaker:"Strategy Director",portrait:"shadow",tags:["dummy-candidates","election","manipulation"],prompt:'Your enemies are quitting the election. You can pay fake "enemies" to run against you so it looks like a real game.',left:{id:"a",label:"Pay fake enemies to run against you.",tooltip:"An empty stage needs painted rivals.",reveal:"The ballot fills with your own men pretending to oppose you. Observers see through it instantly, and the charade becomes shorthand for the whole farce.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Just run alone and let people see the truth.",tooltip:"A staged fight fools no one and shames me.",reveal:"You let the contest be what it is — thin, but honest. The optics of a low-turnout win are bad, but not as bad as being caught faking your own opposition.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0035",location:"party",arc:"party-t0-a32",stage:0,speaker:"Cabinet Secretary",portrait:"official",tags:["bureaucracy","purge","patronage"],prompt:"You can fire all the government workers who used to work for the old boss and replace them with your own fans.",left:{id:"a",label:"Fire them and hire only your fans.",tooltip:"A machine must answer to one hand.",reveal:"Loyalists rise and capable neutrals rot in OSD limbo. The government does as told, and the institution's professionalism bleeds out with the purged.",effects:{MI:6,EN:-10,GL:-10}},right:{id:"b",label:"Keep the good workers, even if they worked for the old boss.",tooltip:"A bureaucracy I gut once will fail me later.",reveal:"You promote on competence and let officers serve the office, not the person. Some will drag their feet on your worst ideas — which is rather the point.",effects:{EN:5,GL:5,MI:-10}}},{id:"party-0036",location:"party",arc:"party-t0-a33",stage:0,speaker:"Party Historian",portrait:"official",tags:["history","martyrs","narrative"],prompt:"A helper wants to change the history books to make the enemy team look like killers, just to make your team look better.",left:{id:"a",label:"Change the history books to make them look bad.",tooltip:"Yesterday's blood is today's mandate.",reveal:"The speeches land like blows and the base is electrified. The opposition is painted as murderers' heirs, and any hope of national reconciliation dies on the dais.",effects:{MI:5,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Keep the history books honest and respectful.",tooltip:"A grave is not a campaign stop.",reveal:"You honour the dead without naming the living as villains. The base wanted more fire, but the day keeps its solemnity and you keep the high ground.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0037",location:"party",arc:"party-t0-a34",stage:0,speaker:"Law Minister",portrait:"official",tags:["judiciary","appointments","independence"],prompt:"You get to pick two big judges before a big court case about you. You can pick your friends to make sure you win.",left:{id:"a",label:"Pick your friends as the judges.",tooltip:"A verdict is safest decided before the hearing.",reveal:"Your judges take their seats and the ruling goes your way. The judgment is sound on paper and stillborn in credibility; the court is now visibly yours.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Pick the smartest judges and hope for the best.",tooltip:"A court I own cannot protect me from the one who owns me next.",reveal:"You elevate the senior, respected names. They may rule against you, but a judiciary that can say no is the only one whose yes means anything.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0038",location:"party",arc:"party-t0-a35",stage:0,speaker:"District President",portrait:"people",tags:["grassroots","accountability","local"],prompt:"People hate one of your politicians because he is mean and steals. You can protect him, or fire him and listen to the people.",left:{id:"a",label:"Protect the mean politician.",tooltip:"A sitting MP's machine is not lightly broken.",reveal:"You back your man and the machine grinds on. The workers feel betrayed and stay home, and the seat that looked safe wobbles.",effects:{MI:3,FA:2,EN:-10,GL:-3}},right:{id:"b",label:"Fire him and listen to the people.",tooltip:"A party that won't hear its base goes deaf.",reveal:"You drop the incumbent and let the workers pick. He fumes and threatens to bolt, but the district roars back to life around its own choice.",effects:{EN:6,MI:-6,FA:-3,GL:2}}},{id:"party-0039",location:"party",arc:"party-t0-a36",stage:0,speaker:"Establishment Minister",portrait:"official",tags:["jobs","patronage","youth"],prompt:"You are hiring thousands of new government workers. You can secretly give all the jobs to your fans, or give them to the smartest people.",left:{id:"a",label:"Secretly give the jobs to your fans.",tooltip:"A job given is a vote owned for life.",reveal:"Cadres' sons fill the rolls and a generation is bound to you. The merit-passed-over seethe, and the civil service inherits a cohort hired for loyalty, not skill.",effects:{MI:5,FA:3,EN:-13,GL:-6}},right:{id:"b",label:"Give the jobs to the smartest people.",tooltip:"A government staffed by favours governs like one.",reveal:"You run a clean recruitment. The youth wing howls at the lost spoils, but you gain a competent intake and the credit for a fair process.",effects:{EN:6,GL:3,FA:-6,MI:-6}}},{id:"party-0040",location:"party",arc:"party-t0-a37",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["reconciliation","rivals","unity"],prompt:"An old leader who left your team angry wants to come back. He brings lots of votes but also lots of drama.",left:{id:"a",label:"Welcome him back for the votes.",tooltip:"A returned rival fights for you, not against.",reveal:"He rejoins to fanfare, faction and all, and your numbers swell. He also resumes manoeuvring from the inside, an old knife back in the drawer.",effects:{MI:5,FA:-3,EN:2,GL:2}},right:{id:"b",label:"Tell him to stay away.",tooltip:"A man who left once leaves twice.",reveal:"You refuse the reunion. His faction stays outside and occasionally bites, but your inner circle is spared a practised intriguer.",effects:{FA:3,MI:-6,EN:-3}}},{id:"party-0041",location:"party",arc:"party-t0-a38",stage:0,speaker:"Religious Front Emissary",portrait:"cleric",tags:["islamist","blasphemy","alliance"],prompt:"A strict religious group wants you to hang a man for his beliefs and ban a nice charity. They will help you win if you do it.",left:{id:"a",label:"Do what they want to get their help.",tooltip:"An ally's price rises with his usefulness.",reveal:"You give them the ban and the spectacle. The streets stay yours for now, but each concession shifts the country further from the constitution you swore to.",effects:{MI:5,FA:2,EN:-16,GL:-16}},right:{id:"b",label:"Say no and make them angry.",tooltip:"An ally who owns my conscience is my master.",reveal:"You decline, and they threaten to turn their squares against you. The winter ahead is colder, but you have stopped feeding the thing that would devour you.",effects:{EN:6,GL:6,MI:-13}}},{id:"party-0042",location:"party",arc:"party-t0-a39",stage:0,speaker:"Leader of the House",portrait:"official",tags:["parliament","boycott","legitimacy"],prompt:"The enemy team is not at the meeting. You can quickly pass all your new rules without anyone arguing with you.",left:{id:"a",label:"Pass all the rules quickly while they are gone.",tooltip:"An absent opposition forfeits its say.",reveal:"Laws pour through unopposed in days. The efficiency is real and the legitimacy is gone; you have legislated alone and it shows on every statute.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Wait for them to come back to be fair.",tooltip:"Laws made in an empty room echo hollow.",reveal:"You hold the most divisive bills and leave the door ajar for the opposition's return. Less gets done, but parliament keeps a pulse.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0043",location:"party",arc:"party-t0-a40",stage:0,speaker:"Election Tech Adviser",portrait:"official",tags:["evm","election","trust"],prompt:"You are getting new voting machines. You can make them secret so no one can check the math, which makes it easy to cheat.",left:{id:"a",label:"Use the secret machines so you can cheat.",tooltip:"A count with no receipt cannot be challenged.",reveal:"The machines report whatever they report and nothing can check them. The opposition's distrust hardens into certainty, and every result is now disputed by design.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Make sure the machines print paper receipts to be fair.",tooltip:"A vote no one can recount is no vote at all.",reveal:"Every machine prints a verifiable receipt. The technology stops being a conspiracy and starts being a count people might actually believe.",effects:{GL:6,EN:5,FI:-6,MI:-6}}},{id:"party-0044",location:"party",arc:"party-t0-a41",stage:0,speaker:"Field Security Chief",portrait:"shadow",tags:["intimidation","polling","agents"],prompt:"A guard suggests scaring the other team's checkers the night before the vote, so they don't show up and you can cheat easily.",left:{id:"a",label:"Scare the checkers away.",tooltip:"An unwatched booth is an obedient booth.",reveal:"The agents melt away and the marginals go unobserved. The pattern is unmistakable to anyone looking, and many are looking.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Say no and let them check the votes.",tooltip:"Fear at the booth poisons the whole well.",reveal:"You order the pressure stopped. The opposition watches every box, catches you on nothing, and the contest is cleaner than your fixers wanted.",effects:{GL:5,EN:5,MI:-10}}},{id:"party-0045",location:"party",arc:"party-t0-a42",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["defection","poaching","majority"],prompt:"You can bribe a smart, young enemy leader to join your team by offering him a big job. This makes you look powerful but unfair.",left:{id:"a",label:"Bribe him to join your team.",tooltip:"Their best man is better as mine.",reveal:"He crosses to fanfare and the opposition loses a future. He governs his district as a fief, and the message lands: in your house, talent is bought.",effects:{MI:5,FA:2,EN:-6,GL:-6}},right:{id:"b",label:"Leave him alone to rise on his own.",tooltip:"A man I had to buy will be bought from me.",reveal:"You pass on the poach. He stays a thorn across the aisle, but your benches are not staffed by mercenaries, and your district bosses keep their turf.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0046",location:"party",arc:"party-t0-a43",stage:0,speaker:"Election Commission Liaison",portrait:"official",tags:["ballot","symbol","advantage"],prompt:"You can secretly trick the voting papers so your name is always at the top and easy to find, making you win more.",left:{id:"a",label:"Trick the voting papers.",tooltip:"A small edge, multiplied by millions.",reveal:"Your symbol sits first on every paper and the marginal voter's thumb drifts your way. It is petty and effective, and observers log every tilted ballot.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Make the papers fair and random.",tooltip:"A win bought by ballot order is not a win.",reveal:"You order the symbols randomised and fair. You forgo a quiet edge, but the ballot itself stops being evidence against you.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0047",location:"party",arc:"party-t0-a44",stage:0,speaker:"City Campaign Manager",portrait:"fixer",tags:["mayor","dhaka","election"],prompt:"Your friend is running for mayor but people don't like him. You can cheat to make him win, or replace him with someone people actually like.",left:{id:"a",label:"Cheat to make your friend win.",tooltip:"The capital cannot fall to a rival.",reveal:"Your man takes the city hall on a tide of state largesse and managed counts. He governs the capital you can no longer claim was freely won.",effects:{MI:5,FI:-10,GL:-10,EN:-6}},right:{id:"b",label:"Let the popular person run instead.",tooltip:"A mayor the city chose serves the city — and reflects on me.",reveal:"You back a candidate people actually like. He owes you little and may freelance, but a clean win in the capital buys you legitimacy money cannot.",effects:{EN:6,GL:5,MI:-6,FA:-3}}},{id:"party-0048",location:"party",arc:"party-t0-a45",stage:0,speaker:"Street Operations Coordinator",portrait:"fixer",tags:["hartal","arson","escalation"],prompt:"Your enemies burned a bus. Your team wants to go burn down their buildings to get revenge.",left:{id:"a",label:"Let your team burn down their buildings.",tooltip:"Blood answers blood, or it never stops.",reveal:"Your cadres burn back and the season descends into mutual arson. The economy seizes, the morgues fill, and both sides own the ashes.",effects:{MI:5,EN:-16,FI:-10,GL:-10}},right:{id:"b",label:"Stop your team and let the police handle it.",tooltip:"I will not turn a blockade into a civil war.",reveal:"You refuse to escalate and let the police hunt the bombers. The blockade still bites, but the bloodshed has only one author, and it is not you.",effects:{GL:5,EN:3,MI:-6,FI:-6}}},{id:"party-0049",location:"party",arc:"party-t0-a46",stage:0,speaker:"Party Historian",portrait:"official",tags:["legacy","founder","cult"],prompt:"Your friends want to build a giant, super expensive museum just to talk about how great your family is.",left:{id:"a",label:"Build the giant, expensive museum.",tooltip:"A founder's shrine anchors a movement forever.",reveal:"The marble rises and the pilgrimages begin. The reverence is enforced and total, and the treasury and the country's pluralism both pay for it.",effects:{FA:6,MI:3,FI:-10,GL:-6}},right:{id:"b",label:"Build a small, normal memorial instead.",tooltip:"A legacy that needs a palace was never solid.",reveal:"You approve a dignified, smaller tribute. The family's elders feel slighted, but the funds and the breathing room for other histories survive.",effects:{GL:3,EN:3,FI:2,FA:-10}}},{id:"party-0050",location:"party",arc:"party-t0-a47",stage:0,speaker:"Labour Wing Secretary",portrait:"people",tags:["labour","garments","wages"],prompt:"Factory workers want better pay. If you help them, they will vote for you, but the rich factory owners will be furious.",left:{id:"a",label:"Help the rich factory owners.",tooltip:"The cheques come from the gate, not the floor.",reveal:"You quietly throttle the wage push to keep the owners happy. The chest stays full, and a million workers learn whose party this really is.",effects:{FI:5,FA:2,EN:-13,GL:-6}},right:{id:"b",label:"Help the workers get better pay.",tooltip:"A million floor votes outweigh a hundred gate cheques.",reveal:"Your wing fronts the agitation and wins a real raise. The owners fume and trim their donations, but the workers' districts are yours for a generation.",effects:{EN:6,GL:3,FI:-10,MI:2}}},{id:"party-0051",location:"party",arc:"party-t0-a48",stage:0,speaker:"Strategy Director",portrait:"official",tags:["by-election","barometer","risk"],prompt:"There is a small vote happening. You can cheat to win easily, or play fair and risk losing to see how people really feel.",left:{id:"a",label:"Cheat to win the small vote safely.",tooltip:"A loss now is a flood later.",reveal:"You secure the seat the old way and avoid the bad headline. You also blind yourself to how thin your support has worn, governing on a number you faked.",effects:{MI:3,GL:-6,EN:-6}},right:{id:"b",label:"Play fair and risk losing.",tooltip:"Better to read the ground than to pave over it.",reveal:"You run it honestly. Win or lose, you finally know where you stand — and if you lose, you learn it now, while there is time to act.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0052",location:"party",arc:"party-t0-a49",stage:0,speaker:"Law Minister",portrait:"official",tags:["contempt","press","speech"],prompt:"A news writer called you a thief. You can throw him in jail to scare everyone, or just show proof that he is wrong.",left:{id:"a",label:"Throw the writer in jail.",tooltip:"An example silences a chorus.",reveal:"He is jailed and the newsrooms flinch. The corruption story is buried under his arrest, which becomes the bigger, longer-running scandal.",effects:{MI:5,FA:2,GL:-13,EN:-10}},right:{id:"b",label:"Show proof he is wrong and let him go.",tooltip:"A government that answers fears nothing.",reveal:"You publish the records that refute him and let him keep printing. The base wanted him jailed, but you have won the argument instead of the arrest.",effects:{GL:6,EN:5,MI:-6}}},{id:"party-0053",location:"party",arc:"party-t0-a50",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["floor-crossing","discipline","law"],prompt:"You can make a strict rule that anyone on your team who disagrees with you goes to jail. This stops all arguing.",left:{id:"a",label:"Make the strict rule to stop arguing.",tooltip:"A whip with teeth needs no second crack.",reveal:"Abstention becomes career suicide and every vote is unanimous. Your benches are flawless and lifeless, a parliament that cannot think, only obey.",effects:{MI:5,GL:-10,EN:-10}},right:{id:"b",label:"Let people disagree and vote how they want.",tooltip:"An MP who cannot ever say no is not a representative.",reveal:"You permit dissent on matters of conscience. A few votes get messier, but your benches contain humans again, and the house earns a little respect.",effects:{GL:5,EN:5,MI:-10}}},{id:"party-0054",location:"party",arc:"party-t0-a51",stage:0,speaker:"Coalition Manager",portrait:"fixer",tags:["seats","allies","arithmetic"],prompt:"Your smaller partner teams want to run in the election too. You can bully them into taking the worst spots, or be generous.",left:{id:"a",label:"Bully them and keep the best spots for yourself.",tooltip:"An alliance is a pyramid, not a partnership.",reveal:"Your candidates get the winnable seats and the partners get crumbs. You dominate the alliance and hollow it, leaving allies who campaign at half-effort.",effects:{MI:5,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Be generous and share the good spots.",tooltip:"A partner fed campaigns harder than one starved.",reveal:"You give the small parties real winnable seats. Your own count is slimmer, but the alliance pulls together and turns out as one.",effects:{EN:3,GL:3,MI:-3,FA:-3}}},{id:"party-0055",location:"party",arc:"party-t0-a52",stage:0,speaker:"Student Wing President",portrait:"fixer",tags:["martyr","funeral","mobilisation"],prompt:"One of your young helpers died fighting the enemy. Your team wants to carry his body through the city to make everyone angry and start a huge fight.",left:{id:"a",label:"Have the big, angry parade.",tooltip:"A martyr's coffin is a recruiting drum.",reveal:"The procession swells into a riot and the rivals are branded murderers. The base burns hot, the city burns with it, and another coffin is already on its way.",effects:{MI:5,FA:2,EN:-13,GL:-6}},right:{id:"b",label:"Have a quiet, respectful funeral.",tooltip:"I will not turn a boy's grave into a battlefield.",reveal:"You give the cadre a dignified, guarded farewell. The president wanted a spectacle and a casus belli; you gave him neither, and the city stays calm.",effects:{EN:5,GL:3,MI:-6}}},{id:"party-0056",location:"party",arc:"party-t0-a53",stage:0,speaker:"Foreign Liaison Officer",portrait:"ambassador",tags:["observers","election","legitimacy"],prompt:"People from other countries want to watch your election to make sure it's fair. You can hide the cheating parts from them, or let them see everything.",left:{id:"a",label:"Hide things and make it hard for them to watch.",tooltip:"Witnesses are only invited to a clean house.",reveal:"The observers are penned far from the action and issue damning reports anyway. The restrictions themselves become the headline: a government afraid of being watched.",effects:{MI:3,GL:-13,EN:-6}},right:{id:"b",label:"Let them see everything and have a fair vote.",tooltip:"A vote that can be watched is a vote that is believed.",reveal:"You let the monitors go where they please. It forces discipline on your machinery, and the clean bill of health they give is worth a hundred press releases.",effects:{GL:6,EN:3,MI:-6}}},{id:"party-0057",location:"party",arc:"party-t0-a54",stage:0,speaker:"Anti-Graft Commission Chair",portrait:"official",tags:["acc","lawfare","selective"],prompt:"The police who catch thieves work for you. You can tell them to only arrest your enemies, or tell them to arrest anyone who steals, even your friends.",left:{id:"a",label:"Tell them to only arrest your enemies.",tooltip:"An investigator off the leash bites the master.",reveal:"The watchdog hounds your enemies and ignores your friends. It is devastatingly useful and visibly partisan, and your own grafters learn they are untouchable.",effects:{MI:5,FA:3,GL:-13,EN:-10}},right:{id:"b",label:"Tell them to arrest anyone who steals.",tooltip:"A watchdog that only bites the neighbour guards nothing.",reveal:"You unleash it on all comers, your side included. A few ministers fall and the base panics, but the Commission gains teeth the public actually trusts.",effects:{GL:6,EN:6,MI:-10,FA:-10}}},{id:"party-0058",location:"party",arc:"party-t0-a55",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["caretaker","constitution","power"],prompt:"You can make a rule that your team always stays in charge during elections, which makes it super easy to win every time.",left:{id:"a",label:"Make the rule so you always stay in charge.",tooltip:"Why concede each election what I can settle once?",reveal:"The amendment passes and the advantage is permanent. So is the opposition's casus belli; every future poll now inherits this original sin.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Keep it fair and let a neutral team run elections.",tooltip:"A rule that survives me protects me from my successors.",reveal:"You keep — or restore — a neutral poll-time authority. You surrender a structural edge, but you drain the poison from every election to come.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0059",location:"party",arc:"party-t0-a56",stage:0,speaker:"Party Treasurer",portrait:"shadow",tags:["funding","black-money","audit"],prompt:"You have a giant pile of secret cash for the election. You can lie about where you got it, or only use honest money and have less to spend.",left:{id:"a",label:"Lie about the money and hide it.",tooltip:"Money has no smell once it is washed.",reveal:"The cash is scrubbed and the audit finds nothing — for now. The shells are a time bomb, and the day one bursts it takes a cabinet with it.",effects:{FI:5,MI:2,GL:-10,EN:-6}},right:{id:"b",label:"Only use honest money, even if it's less.",tooltip:"A washed rupee still stains the hand that spent it.",reveal:"You run on declared money and fight the campaign lean. The shortfall hurts at every rally, but no laundering scandal waits in your second term.",effects:{GL:5,EN:3,FI:-10}}},{id:"party-0060",location:"party",arc:"party-t0-a57",stage:0,speaker:"Party Elders' Council",portrait:"official",tags:["dynasty","nepotism","nominations"],prompt:"Your whole family wants to be politicians now because you are the boss. People might think you are just giving jobs to your relatives.",left:{id:"a",label:"Give your family the easy jobs.",tooltip:"Blood holds when everything else bends.",reveal:"The relatives are slotted into winnable seats. The dynasty's grip tightens, and the photo of the new parliamentary party looks like a wedding album.",effects:{FA:6,MI:2,EN:-10,GL:-6}},right:{id:"b",label:"Tell them no and pick the smartest people.",tooltip:"A party of cousins has no roots.",reveal:"You cap the relatives and open seats to organisers. The family is wounded and loud, but the benches gain people the wards chose.",effects:{EN:5,GL:3,FA:-13,MI:-3}}},{id:"party-0061",location:"party",arc:"party-t0-a58",stage:0,speaker:"Hill Affairs Convenor",portrait:"official",tags:["cht","indigenous","accord"],prompt:"People in the hills want you to keep an old promise to protect them. But the army and new settlers want to take their land.",left:{id:"a",label:"Help the army and the new settlers.",tooltip:"The plains vote outnumbers the hills.",reveal:"You shelve the accord again. The garrisons and settlers are pleased, and the hills add another broken promise to a decades-long ledger of them.",effects:{MI:3,FA:2,EN:-13,GL:-6}},right:{id:"b",label:"Keep the promise and protect the hill people.",tooltip:"A promise twenty years deferred is a wound.",reveal:"You move on land rights and a partial drawdown. The army and settlers resist hard, but the hills, for once, see the state keep its word.",effects:{EN:6,GL:5,MI:-10,FA:-3}}},{id:"party-0062",location:"party",arc:"party-t0-a59",stage:0,speaker:"Returning Officer Coordinator",portrait:"official",tags:["results","count","delay"],prompt:"The votes are coming in. You can pause the TV news to secretly change some numbers so you win, or show the honest truth instantly.",left:{id:"a",label:"Pause the news to secretly change numbers.",tooltip:"A few hours buys a comfortable margin.",reveal:"The overnight delay yields a tidier result and an obvious one. The gap between the late seats and the rest tells its own story to anyone counting.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Show the honest truth instantly.",tooltip:"A count that needs the night to fix was never counted.",reveal:"You declare on schedule, narrow margins and all. Governing the thinner majority is harder, but the result lands before anyone can call it cooked.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0063",location:"party",arc:"party-t0-a60",stage:0,speaker:"Personal Physician",portrait:"doctor",tags:["succession","health","dynasty"],prompt:"You are very sick but no one knows. You can pick the next leader now, but people might stop listening to you early.",left:{id:"a",label:"Hide it and pretend you are perfectly fine.",tooltip:"A wounded king shows no blood.",reveal:"You hide the decline and grip the wheel. The succession stays unsettled, and the day the truth breaks the party will tear itself apart over a vacuum.",effects:{MI:3,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Pick the next leader now to be safe.",tooltip:"A transition I design beats one fought over my bed.",reveal:"You begin the handover on your own terms. Your authority ebbs the moment you announce, but the dynasty gains a real chance of surviving you.",effects:{FA:5,GL:3,EN:3,MI:-10}}},{id:"party-0064",location:"party",arc:"party-t0-a61",stage:0,speaker:"Election Commission Liaison",portrait:"official",tags:["recount","dispute","credibility"],prompt:"The enemy wants to recount the votes because they think you cheated in one town. You can say no using a silly rule, or let them recount and risk losing.",left:{id:"a",label:"Say no and keep the win.",tooltip:"A win declared is a win kept.",reveal:"You deny the recount and the seat stands, disputed forever. The technicality fools no one, and the seat becomes a permanent symbol of the stolen vote.",effects:{MI:3,GL:-10,EN:-6}},right:{id:"b",label:"Let them recount the votes fairly.",tooltip:"A seat that survives a recount is truly mine.",reveal:"You allow the recount under cameras. You may lose the seat, but the seats you keep are now unassailable, and the gesture buys rare goodwill.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0065",location:"party",arc:"party-t0-a62",stage:0,speaker:"Information Minister",portrait:"official",tags:["history","national-day","narrative"],prompt:"You can change the school books so they only talk about how amazing your family is and ignore all the other heroes.",left:{id:"a",label:"Change the books to only praise your family.",tooltip:"He who tells the founding owns the nation.",reveal:"The broadcasts crown your lineage as the sole begetter of the republic. Historians wince, rivals' heirs seethe, and the cult deepens by another generation.",effects:{FA:5,MI:2,EN:-10,GL:-6}},right:{id:"b",label:"Tell the honest history about all the heroes.",tooltip:"A nation with one father is an orphan of the rest.",reveal:"You share the credit across the founding generation. The family's mythmakers are disappointed, but the story gains the ring of truth and the nation's buy-in.",effects:{GL:5,EN:5,FA:-10}}},{id:"party-0066",location:"party",arc:"party-t0-a63",stage:0,speaker:"Inspector-General of Police",portrait:"general",tags:["police","recruitment","loyalty"],prompt:"You are hiring new police. You can only hire people who promise to vote for you, or hire the strongest, smartest people.",left:{id:"a",label:"Only hire people who promise to vote for you.",tooltip:"A force that loves me will never aim at me.",reveal:"Loyalists fill the ranks and the force becomes a praetorian guard. It will protect you faithfully — until the day loyalty to a person costs it the public's last trust.",effects:{MI:6,EN:-10,GL:-6}},right:{id:"b",label:"Hire the strongest and smartest people.",tooltip:"A police that serves the law outlasts the one that serves me.",reveal:"You insist on a professional intake. The new constables answer to the badge, not your name — less pliable, but a force the public might one day respect.",effects:{EN:5,GL:3,MI:-6}}},{id:"party-0067",location:"party",arc:"party-t0-a64",stage:0,speaker:"Intelligence Chief",portrait:"shadow",tags:["cabinet","plot","loyalty"],prompt:"Two of your friends are secretly talking to the army about taking your job. You can spy on them secretly, or yell at them right now.",left:{id:"a",label:"Spy on them secretly to stop them.",tooltip:"A plot is best killed in the cradle.",reveal:"You wiretap, gather leverage, and break them with it. The plot dies, but so does trust in your cabinet, where every minister now assumes he too is bugged.",effects:{MI:5,FA:-3,EN:-6,GL:-6}},right:{id:"b",label:"Yell at them right now and demand they be loyal.",tooltip:"Daylight scatters conspirators.",reveal:"You face them down in front of the cabinet. The gamble forces a public reaffirmation of loyalty, and the cabinet sees a leader who fights in the open, not the shadows.",effects:{FA:3,GL:3,EN:2,MI:-6}}},{id:"party-0068",location:"party",arc:"party-t0-a65",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["scandal","family","corruption"],prompt:"Someone in your family got caught stealing. You can hide the secret, or let the police arrest them like anyone else.",left:{id:"a",label:"Hide the secret to protect your family.",tooltip:"Blood is not investigated.",reveal:"The file vanishes and the family is shielded. The cover-up leaks in pieces, and 'one law for them' becomes the opposition's favourite chant.",effects:{FA:5,MI:2,GL:-13,EN:-13}},right:{id:"b",label:"Let the police arrest them.",tooltip:"A dynasty above the law is a dynasty without one.",reveal:"You allow the investigation, family or not. The relative is furious and the household tense, but the public sees, astonished, that the rules might apply to everyone.",effects:{GL:6,EN:6,FA:-13,MI:-3}}},{id:"party-0069",location:"party",arc:"party-t0-a66",stage:0,speaker:"Manifesto Committee Chair",portrait:"official",tags:["manifesto","promises","credibility"],prompt:"You are writing your promises for the election. You can promise crazy, impossible things to get votes, or be honest about what you can actually do.",left:{id:"a",label:"Promise impossible things to win.",tooltip:"A campaign is won on dreams, not spreadsheets.",reveal:"The crowds roar at free electricity and a job for every graduate. You win, then spend the term explaining why the moon is still in the sky.",effects:{MI:3,EN:-6,GL:-6,FI:-3}},right:{id:"b",label:"Be honest and only promise what you can do.",tooltip:"A promise kept is worth ten promises made.",reveal:"You run on what you can actually do. The rallies are less electric, but every pledge you redeem next term compounds into trust.",effects:{EN:5,GL:5,MI:-3}}},{id:"party-0070",location:"party",arc:"party-t0-a67",stage:0,speaker:"Student Wing President",portrait:"fixer",tags:["students","protest","blame"],prompt:"Your student helpers beat up peaceful kids on video. They want you to lie and say the peaceful kids started it.",left:{id:"a",label:"Lie and protect your student helpers.",tooltip:"I do not abandon my own to a mob's verdict.",reveal:"You defend the indefensible and the lie collapses on contact with the video. The campuses unite against you, and the wing learns it can attack with impunity.",effects:{MI:3,FA:2,EN:-16,GL:-10}},right:{id:"b",label:"Punish your helpers and say sorry.",tooltip:"A wing that beats students is a liability, not an asset.",reveal:"You suspend the cadres and apologise to the campus. The wing president seethes at the betrayal, but the wider student body, stunned, lowers its guard.",effects:{EN:6,GL:3,MI:-6,FA:-3}}},{id:"party-0071",location:"party",arc:"party-t0-a68",stage:0,speaker:"Elder Statesman",portrait:"official",tags:["dialogue","opposition","reconciliation"],prompt:"Your enemies offer to stop fighting if you let their friends out of jail and make fairer rules.",left:{id:"a",label:"Say no and keep fighting them.",tooltip:"I do not negotiate with those I have already beaten.",reveal:"You spurn the overture and rule unchallenged on paper. The crisis hardens underground, and the legitimacy gap you could have closed widens instead.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Make a deal and trade rules for peace.",tooltip:"A rival at the table is not a rival in the street.",reveal:"You negotiate, free some activists, and concede real reforms. The hardliners howl betrayal, but the country exhales, and your rule gains a legitimacy force never bought it.",effects:{GL:6,EN:6,MI:-13}}},{id:"party-0072",location:"party",arc:"party-t0-a69",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["congress","rules","control"],prompt:"You can change your team's rules so you never have to vote for a leader again, meaning you are the boss forever.",left:{id:"a",label:"Change the rules to be boss forever.",tooltip:"A party that votes on its head invites a coup.",reveal:"The top posts become appointments and dissent within the party dies. You command total control of a machine that no longer argues — or thinks.",effects:{MI:5,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Keep the voting rules to be fair.",tooltip:"A party that cannot choose its own leaders cannot lead a country.",reveal:"You preserve the internal vote. It means occasional surprises and rivals you did not pick, but the party stays a living thing with roots that hold.",effects:{EN:5,GL:3,MI:-6}}},{id:"party-0073",location:"party",arc:"party-t0-a69",stage:1,speaker:"General Secretary",portrait:"fixer",tags:["congress","rules","control"],prompt:"A very popular guy on your team might win a vote against your favorite friend. You can kick him out for a fake reason so your friend wins.",left:{id:"a",label:"Kick him out for a fake reason.",tooltip:"A challenge unanswered is a challenge avoided.",reveal:"He is ruled ineligible and the slate passes unopposed. The delegates who backed him go home bitter, and the province cools toward you for a generation.",effects:{MI:3,FA:2,EN:-10,GL:-3}},right:{id:"b",label:"Let everyone vote fairly.",tooltip:"A leader the delegates chose serves stronger than one I imposed.",reveal:"You let the contest run. He may win a post you did not plan to give, but the congress crackles with real life and the province feels seen.",effects:{EN:5,GL:3,FA:-3,MI:-6}}},{id:"party-0074",location:"party",arc:"party-t0-a70",stage:0,speaker:"Legal Affairs Secretary",portrait:"official",tags:["defamation","press","intimidation"],prompt:"You can file hundreds of fake lawsuits against reporters and enemies to keep them busy and scared in court forever.",left:{id:"a",label:"File the fake lawsuits to scare them.",tooltip:"A man in court has no time to campaign.",reveal:"The critics drown in hearings across the country, exhausted and broke. The tactic is transparent, and 'judicial harassment' becomes the verdict on your rule abroad.",effects:{MI:3,GL:-13,EN:-10}},right:{id:"b",label:"Stop the fake lawsuits.",tooltip:"A law used as a club is no longer a law.",reveal:"You order the suits dropped. Your critics keep their freedom and their venom, but you are spared a reputation as a man who litigates dissent into silence.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0075",location:"party",arc:"party-t0-a70",stage:1,speaker:"Legal Affairs Secretary",portrait:"official",tags:["defamation","press","intimidation"],prompt:"One of those fake lawsuits got a young reporter thrown in jail for a long time.",left:{id:"a",label:"Leave her in jail.",tooltip:"To intervene is to admit the suit was mine.",reveal:"You stay out and she stays in. Her detention becomes a cause célèbre, every passing week a fresh indictment of your tolerance for it.",effects:{MI:2,GL:-10,EN:-10}},right:{id:"b",label:"Step in and let her go free.",tooltip:"A jailed reporter is a wound I can still close.",reveal:"You quietly secure her release and rein in the local leader. The base mutters about weakness, but the embarrassment ends and a small debt of goodwill is repaid.",effects:{GL:5,EN:5,MI:-3}}},{id:"party-0076",location:"party",arc:"party-t0-a71",stage:0,speaker:"Delimitation Commissioner",portrait:"official",tags:["gerrymander","constituencies","advantage"],prompt:"You can redraw the map for the election to trap all your enemies in one area, making it super easy for you to win the rest.",left:{id:"a",label:"Redraw the map to cheat and win.",tooltip:"A map drawn well wins seats before a vote is cast.",reveal:"The new map quietly tilts a dozen seats your way for a generation. The psephologists notice and cry foul, but the lines are set and the advantage banked.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Draw the map fairly for everyone.",tooltip:"A rigged map is a confession printed in ink.",reveal:"You insist on a neutral, population-based redraw. You forgo a structural edge, but the electoral map stops being one more piece of evidence against you.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0077",location:"party",arc:"party-t0-a72",stage:0,speaker:"Administrative Reforms Secretary",portrait:"fixer",tags:["districts","patronage","spending"],prompt:"Local leaders want you to create brand new towns on the map just so they can get new jobs and money.",left:{id:"a",label:"Create the new towns to give them jobs.",tooltip:"A new district is a thousand new favours to grant.",reveal:"You carve out the new districts and the patronage flows. Local bosses are delighted, and the bloated administration becomes one more permanent cost the budget never planned for.",effects:{FA:5,MI:2,FI:-10,EN:-6}},right:{id:"b",label:"Say no to wasting money on fake towns.",tooltip:"I will not buy loyalty by the district.",reveal:"You decline the upgrades. The disappointed local leaders sulk and some turn cold, but the state is spared a fresh layer of offices built purely to be staffed with friends.",effects:{FI:5,GL:2,FA:-10}}},{id:"party-0078",location:"party",arc:"party-t0-a73",stage:0,speaker:"Relief Distribution Coordinator",portrait:"fixer",tags:["patronage","relief-cards","votes"],prompt:"Politicians are only giving free food to people who vote for them, and letting the others starve.",left:{id:"a",label:"Let them keep using food to buy votes.",tooltip:"A card given is a vote owed.",reveal:"The cards stay a tool of loyalty, rewarding your wards and starving the rest. The machine hums, and the genuinely hungry in the wrong wards learn that relief here wears a party colour.",effects:{FA:5,MI:2,EN:-13,GL:-6}},right:{id:"b",label:"Force them to give food fairly to everyone who is hungry.",tooltip:"Hunger does not check a voter card.",reveal:"You strip the cards from the MPs and route them by need. Your local leaders lose a lever and rage, but the relief reaches the poorest regardless of how they vote.",effects:{EN:6,GL:3,FA:-10}}},{id:"party-0079",location:"party",arc:"party-t0-a74",stage:0,speaker:"City Campaign Manager",portrait:"fixer",tags:["city","election","local"],prompt:"Small city elections are happening. You can rig them quietly to make sure you win, or let people vote freely as a test.",left:{id:"a",label:"Rig the elections quietly.",tooltip:"No verdict against me, however small, can stand.",reveal:"You secure the cities the old way. The wins are hollow and the pattern noted, and you blind yourself to how the towns truly feel about you.",effects:{MI:3,GL:-10,EN:-6}},right:{id:"b",label:"Let people vote freely.",tooltip:"A town honestly won tells me where I stand.",reveal:"You let the corporations vote freely. You lose a few mayoralties, but the honest results give you a true map of your support and a credibility the rigged wins never had.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0080",location:"party",arc:"party-t0-a75",stage:0,speaker:"Statistics Bureau Director",portrait:"official",tags:["census","data","manipulation"],prompt:"You are counting all the people in the country. A helper says you can change the math to favor your towns for more money.",left:{id:"a",label:"Change the math to get more money for your towns.",tooltip:"Numbers serve the state, and I am the state.",reveal:"You tilt the headcounts toward your strongholds. The seats and funds flow your way, and every policy built on the false figures — schools, clinics, rations — is quietly misallocated for a decade.",effects:{MI:5,FI:2,EN:-13,GL:-6}},right:{id:"b",label:"Count the people honestly.",tooltip:"A nation that lies to itself in numbers cannot plan.",reveal:"You demand accurate counts whatever they cost you. Some strongholds shrink on paper and lose seats, but the data the whole state relies on is finally trustworthy.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0081",location:"party",arc:"party-t0-a76",stage:0,speaker:"Liberation Affairs Secretary",portrait:"official",tags:["quota","freedom-fighters","merit"],prompt:"A rule gives the best jobs to kids of old war heroes, making normal young people furious. You can keep the rule or change it to be fair.",left:{id:"a",label:"Keep giving the best jobs to the heroes' kids.",tooltip:"The children of those who bled deserve the state they built.",reveal:"You keep the quota intact and honour the founding generation. Your base of veterans' families is loyal, but the merit-starved youth seethe, and the next spark may be larger.",effects:{FA:3,MI:2,EN:-13,GL:-6}},right:{id:"b",label:"Change the rule to be fair to everyone.",tooltip:"A republic staffed by birthright is no republic.",reveal:"You slash the hereditary quota and open posts to merit. The veterans' lobby feels betrayed, but a generation of frustrated youth sees, astonished, that the state heard them.",effects:{EN:6,GL:5,FA:-10,MI:-3}}},{id:"party-0082",location:"party",arc:"party-t0-a77",stage:0,speaker:"Education Affairs Secretary",portrait:"fixer",tags:["students","union","democracy"],prompt:"School groups haven't voted for their leaders in years, so your bullies run everything. You can let them vote, but your bullies might lose.",left:{id:"a",label:"Keep the voting stopped so your bullies stay in charge.",tooltip:"An unelected wing is a controlled wing.",reveal:"You leave the campuses to your appointed enforcers. The grip holds, but a generation graduates having never voted, learning democracy as something that happens to other people.",effects:{MI:5,EN:-10,GL:-6}},right:{id:"b",label:"Let the schools vote fairly.",tooltip:"Democracy unlearned on campus is unlearned for life.",reveal:"You bring back the campus vote. Your wing may lose its monopoly to independents and rivals, but the campuses come alive and a generation practises the franchise.",effects:{EN:6,GL:5,MI:-10}}},{id:"party-0083",location:"party",arc:"party-t0-a78",stage:0,speaker:"Religious Outreach Coordinator",portrait:"cleric",tags:["pir","endorsement","rural"],prompt:"A famous religious leader will tell millions of people to vote for you, but only if you give his group a lot of money and ignore their secrets.",left:{id:"a",label:"Give him the money to get the votes.",tooltip:"His word turns out the countryside.",reveal:"You strike the bargain and his followers swing your way. The shrine network fattens on state favour beyond any audit, and you have rented a bloc you do not control.",effects:{MI:5,FA:2,FI:-3,EN:-6}},right:{id:"b",label:"Say no to the secret deal.",tooltip:"A vote bought through a pir is a vote I never truly hold.",reveal:"You pass on the deal. The rural bloc stays unmobilised for you and the pir cools, but you owe no shadowy shrine-empire a debt it will one day call in.",effects:{GL:3,EN:2,MI:-6}}},{id:"party-0084",location:"party",arc:"party-t0-a79",stage:0,speaker:"Labour Wing Organiser",portrait:"people",tags:["tea-garden","labour","wages"],prompt:"The poor people picking tea want better pay. If you help them, the rich tea farm owners who usually help you will be mad.",left:{id:"a",label:"Side with the rich tea farm owners.",tooltip:"The gardens vote as the owners say.",reveal:"You leave the bonded wage untouched to keep the owners happy. The estates deliver their votes as instructed, and a quarter-million workers stay trapped at a wage from another century.",effects:{FI:2,FA:3,EN:-13}},right:{id:"b",label:"Help the poor tea pickers get better pay.",tooltip:"A bonded vote is no foundation; a freed one is.",reveal:"You back a real wage rise for the garden workers. The owner-donors retaliate with shut wallets, but the workers, stunned to be seen, become a bloc loyal to you and not the estate.",effects:{EN:6,FA:-6,FI:-6}}},{id:"party-0085",location:"party",arc:"party-t0-a80",stage:0,speaker:"Electoral Reform Adviser",portrait:"official",tags:["pr","system","reform"],prompt:"People want a new voting system that is completely fair. But if it is completely fair, you won't win as easily anymore.",left:{id:"a",label:"Keep the old rules so you keep winning easily.",tooltip:"Why trade a landslide for a coalition?",reveal:"You preserve the system that magnifies your seats. The majorities stay commanding and the small parties shut out, and the gap between your seat count and your vote share stays a standing grievance.",effects:{MI:3,GL:-6,EN:-3}},right:{id:"b",label:"Change to the fair rules.",tooltip:"A parliament that mirrors the vote is the only honest one.",reveal:"You back a shift toward PR. Your dominance shrinks to its real proportion and coalition-building becomes the norm, but parliament finally reflects how the country actually voted.",effects:{GL:5,EN:5,MI:-10}}},{id:"party-0086",location:"party",arc:"party-t0-a81",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["split","faction","discipline"],prompt:"A big leader on your team is mad and wants to start his own team. You can arrest him to stop him, or give him what he wants so he stays.",left:{id:"a",label:"Arrest him before he leaves.",tooltip:"A breakaway strangled in the cradle never breathes.",reveal:"You expel him and bury him in cases before he can organise. The split is averted by force, and every ambitious leader learns the cost of independent thought.",effects:{MI:5,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Give him what he wants so he stays.",tooltip:"A tent that loses a pole sags everywhere.",reveal:"You meet his demands and keep him inside. Unity holds, but you have shown that a credible threat to leave is the surest way to win concessions from you.",effects:{FA:3,MI:-3,EN:2}}},{id:"party-0087",location:"party",arc:"party-t0-a82",stage:0,speaker:"Coalition Manager",portrait:"official",tags:["alliance","left","ideology"],prompt:"A small, smart group wants to join you. They will help you look good, but they want you to be nicer to workers, which will anger your rich friends.",left:{id:"a",label:"Join with them and help the workers.",tooltip:"Their cadres and credibility are worth a tilt.",reveal:"You bring the left in and shift your platform toward labour and land. The donors grumble and some drift, but you gain disciplined organisers and a sheen of conviction.",effects:{EN:5,MI:2,FI:-6,FA:-3}},right:{id:"b",label:"Say no and keep your rich friends happy.",tooltip:"Ideas do not fund campaigns; businessmen do.",reveal:"You pass on the alliance to keep your business backers content. The money stays, but you forgo the street muscle and the credibility, and the left turns its energy against you.",effects:{FI:5,FA:2,EN:-6}}},{id:"party-0088",location:"party",arc:"party-t0-a83",stage:0,speaker:"Tribunal Prosecutor",portrait:"official",tags:["banning","collaborators","1971"],prompt:"You can ban an old religious team for bad things they did in a war long ago. It is fair, but it also magically gets rid of your enemies today.",left:{id:"a",label:"Ban the old team forever.",tooltip:"A party born of atrocity forfeits its place.",reveal:"You dissolve the party and its symbol. The base roars at the reckoning, and the opposition loses an ally — but critics note how neatly justice served your politics, and the banned go underground.",effects:{MI:5,FA:2,EN:2,GL:-6}},right:{id:"b",label:"Let them stay and try to beat them by voting.",tooltip:"A martyr-party banned outlives a beaten one.",reveal:"You leave the party legal and fight it at the ballot. It survives to needle you, but you deny it the banner of victimhood and keep the moral high ground over a real reckoning.",effects:{GL:5,EN:2,MI:-6}}},{id:"party-0089",location:"party",arc:"party-t0-a84",stage:0,speaker:"Rural Development Coordinator",portrait:"fixer",tags:["rural-works","patronage","graft"],prompt:"Politicians are stealing the money meant for building village roads. You can take the money away and give it to honest local councils instead.",left:{id:"a",label:"Let the politicians keep handling the money.",tooltip:"An MP without projects to give is an MP without friends.",reveal:"You leave the rural funds with your MPs. They build where it buys loyalty and skim the rest, and the genuinely needy villages with the wrong MP go without.",effects:{FA:5,MI:2,EN:-10,FI:-3}},right:{id:"b",label:"Give the money to honest local councils.",tooltip:"Roads should follow need, not the member's whim.",reveal:"You hand the funds to elected local bodies with audits. The MPs lose a prized lever and resent it, but the works spread by need and the skim shrinks.",effects:{EN:6,GL:3,FA:-10}}},{id:"party-0090",location:"party",arc:"party-t0-a85",stage:0,speaker:"Religious Affairs Secretary",portrait:"cleric",tags:["mosques","imams","influence"],prompt:"You can pay religious leaders to say nice things about you during their prayers. This tricks people into voting for you.",left:{id:"a",label:"Pay the religious leaders to say nice things.",tooltip:"He who befriends the pulpit befriends the faithful.",reveal:"You fund the imams and stack the committees with loyalists. The Friday sermons soften toward you, and the mosques become one more institution bent to the party's will.",effects:{MI:5,FA:2,EN:-6,GL:-6}},right:{id:"b",label:"Keep religion and politics separate.",tooltip:"A pulpit I own is a pulpit no one believes.",reveal:"You leave the mosque committees free. You forgo the pulpit's quiet endorsement, but the faith keeps a distance from the party that lends its eventual support real weight.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0091",location:"party",arc:"party-t0-a86",stage:0,speaker:"Law Minister",portrait:"official",tags:["sedition","speech","opposition"],prompt:"Protesters made up a funny song making fun of you. You can arrest them and put them in jail for it.",left:{id:"a",label:"Arrest them for making fun of you.",tooltip:"Mockery, unanswered, becomes contempt.",reveal:"You jail the sloganeers and the chant becomes infamous, sung at every rally now in defiance. The heavy hand turns a jingle into a movement and you into its punchline.",effects:{MI:3,FA:2,EN:-13,GL:-10}},right:{id:"b",label:"Laugh at the song and do nothing.",tooltip:"A leader who jails a chant has already lost to it.",reveal:"You wave the mockery away with a joke of your own. The chant loses its charge for want of a martyr, and you look, for once, bigger than your critics.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0092",location:"party",arc:"party-t0-a87",stage:0,speaker:"Justice Reform Adviser",portrait:"official",tags:["truth-commission","reckoning","past"],prompt:"People want to investigate the old bosses for stealing. If you do, people might want to investigate you someday too.",left:{id:"a",label:"Investigate everything deeply.",tooltip:"A nation that cannot face its past repeats it.",reveal:"You establish a real commission with teeth. The past regime's crimes are aired and victims heard, and you accept that the same mirror may one day be turned on you.",effects:{GL:6,EN:5,MI:-6}},right:{id:"b",label:"Only do a small, safe investigation.",tooltip:"A precedent for digging up the dead is a shovel for my own grave.",reveal:"You permit only a toothless, bounded review. The reckoning is stage-managed, the precedent contained, and the victims learn the truth was never really on offer.",effects:{MI:3,FA:2,EN:-6,GL:-6}}},{id:"party-0093",location:"party",arc:"party-t0-a88",stage:0,speaker:"Election Commission Liaison",portrait:"official",tags:["finance","disclosure","transparency"],prompt:"A new rule would force you to tell everyone exactly where you get your campaign money. It ruins your secret cash.",left:{id:"a",label:"Stop the rule and keep your money secret.",tooltip:"A war chest examined is a war chest disarmed.",reveal:"You quietly kill the bill. Your funding stays in the dark, and so does everyone's, and the suspicion that elections here are simply bought hardens into common knowledge.",effects:{FI:2,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Agree to the rule and be honest.",tooltip:"Money in daylight buys less than money in shadow.",reveal:"You support the sunlight law. Your own opaque chest faces scrutiny, but the system gains a check it never had, and you can claim a reform your rivals resisted.",effects:{GL:5,EN:5,FI:-6}}},{id:"party-0094",location:"party",arc:"party-t0-a89",stage:0,speaker:"Strategy Director",portrait:"official",tags:["youth","voting-age","franchise"],prompt:"You can let young kids vote. But right now, young kids are angry at you and will probably vote for the other team.",left:{id:"a",label:"Let the young kids vote.",tooltip:"A franchise widened is a democracy deepened.",reveal:"You enfranchise the youth despite their coolness toward you. It wins democratic credit at home and abroad, and you have handed the vote to a generation that may use it against you.",effects:{GL:5,EN:5,MI:-6}},right:{id:"b",label:"Do not lower the voting age.",tooltip:"I will not arm a cohort that means to vote me out.",reveal:"You decline the reform. The status quo protects you from a hostile bloc, and the young add 'denied the vote' to a lengthening list of grievances against you.",effects:{MI:2,FI:2,GL:-6,EN:-3}}},{id:"party-0095",location:"party",arc:"party-t0-a90",stage:0,speaker:"Parliamentary Affairs Minister",portrait:"official",tags:["opposition","status","norms"],prompt:"You can give the leader of the enemy team a nice office and treat them with respect, or take everything away to make them look weak.",left:{id:"a",label:"Take everything away to make them look weak.",tooltip:"A rival with a chair is a rival with a stage.",reveal:"You hollow out the opposition leadership's perks and powers. Your rival is diminished, and parliament drifts further from the adversarial democracy it pretends to be.",effects:{MI:3,GL:-6,EN:-6}},right:{id:"b",label:"Treat them with respect.",tooltip:"A loyal opposition is the proof a democracy works.",reveal:"You afford your rival the traditional standing and consultation. It legitimises an adversary, but it also legitimises the whole house, and the maturity is noticed abroad.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0096",location:"party",arc:"party-t0-a91",stage:0,speaker:"Reconciliation Adviser",portrait:"official",tags:["reconciliation","history","wounds"],prompt:"A long time ago, your team did a very bad thing. You can say sorry and heal people's feelings, or stay quiet like always.",left:{id:"a",label:"Say sorry for the bad thing.",tooltip:"A wound named can finally close.",reveal:"You offer a genuine acknowledgment of the old wrong. The base is uneasy and hardliners furious, but victims long ignored feel seen, and a festering grievance begins, at last, to heal.",effects:{GL:5,EN:5,FA:-6}},right:{id:"b",label:"Stay quiet and ignore it.",tooltip:"An apology is an admission, and admissions are weapons.",reveal:"You let the anniversary pass unmarked. The party is spared an admission, and the unhealed wound goes on poisoning the well between you and those who remember.",effects:{FA:3,MI:2,EN:-10,GL:-6}}},{id:"party-0097",location:"party",arc:"party-t0-a92",stage:0,speaker:"Election Logistics Officer",portrait:"official",tags:["remote","polling","access"],prompt:`People living far out in the hills mostly vote for your enemies. You can conveniently "forget" to put voting booths near them so they can't vote.`,left:{id:"a",label:"Forget to put voting booths near them.",tooltip:"Why spend a fortune to be voted against?",reveal:"You quietly thin the polling stations in the remote, unfriendly areas. Turnout there collapses for want of access, and the disenfranchisement, once noticed, becomes a quiet scandal.",effects:{MI:2,GL:-6,EN:-10}},right:{id:"b",label:"Spend money to make sure everyone can vote fairly.",tooltip:"A citizen unreachable by the ballot is a citizen abandoned.",reveal:"You pay to reach every char and hill with a polling station. It costs dearly and may not help your numbers, but no Bangladeshi is denied the vote by geography on your watch.",effects:{EN:6,GL:5,FI:-6}}},{id:"party-0098",location:"party",arc:"party-t0-a93",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["bicameral","senate","structure"],prompt:"You can create a special new group of leaders and fill it with your friends. They will make sure no one can ever change your rules.",left:{id:"a",label:"Create the new group and fill it with friends.",tooltip:"A second chamber of friends is a second line of defence.",reveal:"You establish the upper house and pack it with loyalists. It rewards the faithful and checks any unruly future majority, and critics rightly call it a parking lot for cronies.",effects:{FA:5,MI:3,EN:-6,GL:-6}},right:{id:"b",label:"Say no to creating the new group.",tooltip:"A house of cronies is not a check; it is a couch.",reveal:"You decline to build a chamber of appointees. You forgo a tool of patronage and control, but you avoid bolting a permanent crony-park onto the constitution.",effects:{GL:3,EN:3,FA:-10}}},{id:"party-0099",location:"party",arc:"party-t0-a94",stage:0,speaker:"Home Affairs Coordinator",portrait:"people",tags:["violence","compensation","victims"],prompt:"Your fans started a fight on voting day and people died. You can investigate honestly and pay the families, or secretly pay a little to hide it.",left:{id:"a",label:"Investigate honestly and pay the families fairly.",tooltip:"Blood spilled at the ballot is the state's debt.",reveal:"You compensate the victims openly and order real investigations, your own cadres included. The party is uneasy at the scrutiny, but the dead are honoured and the violence's authors face daylight.",effects:{EN:6,GL:5,FA:-6}},right:{id:"b",label:"Secretly pay a little to hide it.",tooltip:"A long inquiry only keeps the bodies in the news.",reveal:"You settle a handful of cases discreetly and let the rest fade. The headlines pass, the cadres learn there is no reckoning, and the families of the unacknowledged dead nurse a lasting grievance.",effects:{FA:3,MI:2,EN:-10,GL:-6}}},{id:"party-0100",location:"party",arc:"party-t0-a95",stage:0,speaker:"Campaign Data Director",portrait:"shadow",tags:["data","micro-targeting","consultants"],prompt:"A tricky company wants to spy on everyone's phones to figure out how to brainwash them into voting for you.",left:{id:"a",label:"Hire the tricky company to brainwash people.",tooltip:"The other side will, if I do not.",reveal:"You bring in the dark-arts firm and the targeting sharpens uncannily. It works — until the harvesting leaks, and your campaign becomes the local chapter of a global data-abuse scandal.",effects:{MI:5,FI:-3,GL:-10,EN:-6}},right:{id:"b",label:"Run a normal, honest campaign.",tooltip:"An election won by manipulation is a mandate built on sand.",reveal:"You decline the manipulation machine and campaign on message and organisation. It is harder and slower, but no harvesting time-bomb sits ticking under your win.",effects:{GL:3,EN:3,MI:-3}}},{id:"party-0101",location:"party",arc:"party-t0-a96",stage:0,speaker:"Returning Officer Coordinator",portrait:"fixer",tags:["nominations","scrutiny","disqualification"],prompt:"You can throw away the voting papers for the enemy team just because they missed a comma or spelled a word wrong.",left:{id:"a",label:"Throw away their papers for tiny mistakes.",tooltip:"A candidate disqualified is a contest avoided.",reveal:"Dozens of opposition hopefuls are struck off on trivia. Your candidates walk into emptier races, and the courts and observers log another way the contest was hollowed before polling.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Let them fix the mistakes and play fair.",tooltip:"A ballot thinned by clerks is a ballot no one trusts.",reveal:"You order the officers to accept all proper nominations. The races are fuller and harder, but the contest cannot be dismissed as rigged at the starting line.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0102",location:"party",arc:"party-t0-a97",stage:0,speaker:"Strategy Director",portrait:"official",tags:["snap-election","timing","advantage"],prompt:"You just did something popular. You can call a surprise election right now to win before people realize the country is running out of money.",left:{id:"a",label:"Call the surprise election right now.",tooltip:"Strike while the numbers smile.",reveal:"You go to the polls on the sugar high and win comfortably. The fresh term is banked, and the soured economy and unpaid giveaway bill land squarely in your own new lap.",effects:{MI:5,FI:-6,EN:-3}},right:{id:"b",label:"Wait until the normal time and face the problems.",tooltip:"A leader who runs from the bill admits he padded it.",reveal:"You hold the scheduled date and govern through the hard patch. You forgo the easy win, but you cannot be accused of cynically timing the vote to dodge the consequences.",effects:{GL:3,EN:2,MI:-6}}},{id:"party-0103",location:"party",arc:"party-t0-a98",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["article-70","dissent","expulsion"],prompt:"One of your teammates voted against a bad rule you made. You can kick him out completely to scare everyone else into obeying.",left:{id:"a",label:"Kick him out completely.",tooltip:"One conscience indulged becomes a chorus.",reveal:"You strip him of his seat for a single honest vote. The benches fall silent and obedient, and the spectacle of a man expelled for conscience stains the parliament's name.",effects:{MI:5,FA:2,EN:-10,GL:-10}},right:{id:"b",label:"Let him disagree this one time.",tooltip:"A parliament of automatons warns me of nothing.",reveal:"You let the conscience vote stand without punishment. The hardliners fret about the precedent, but the benches keep a flicker of humanity and the house a shred of dignity.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0104",location:"party",arc:"party-t0-a99",stage:0,speaker:"Party Elders' Council",portrait:"official",tags:["president","ceremonial","loyalty"],prompt:"You get to pick the President. You can pick a yes-man who does whatever you say, or a smart, fair person who might argue with you.",left:{id:"a",label:"Pick the yes-man.",tooltip:"A rubber stamp does not develop a spine at midnight.",reveal:"You elevate a reliable nonentity to the presidency. Every decree is signed on cue, and the one office that might restrain you in a crisis is neutered in advance.",effects:{MI:3,FA:2,GL:-6,EN:-3}},right:{id:"b",label:"Pick the smart, fair person.",tooltip:"A dignified head of state reflects on the whole house.",reveal:"You choose a credible figure for the presidency. He lends the state gravity, and you accept that in a true crisis he might use the office's powers as his own conscience, not yours, dictates.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0105",location:"party",arc:"party-t0-a100",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["merger","absorption","growth"],prompt:"A small team wants to join yours. They have lots of voters, but they will demand big jobs and cause drama.",left:{id:"a",label:"Let them join your team.",tooltip:"Their region becomes mine overnight.",reveal:"You merge them in and your map fills out in the weak region. Their leaders crowd your benches with new demands and old baggage, and your once-tight organisation grows lumpier.",effects:{MI:5,FA:-3,EN:2}},right:{id:"b",label:"Say no and work hard to get votes yourself.",tooltip:"A merger buys a region and inherits its quarrels.",reveal:"You decline the merger and invest in building your own base there. It is slower and the region stays thin for you, but your party keeps its coherence and owes no newcomers.",effects:{FA:2,MI:-6,FI:-3}}},{id:"party-0106",location:"party",arc:"party-t0-a101",stage:0,speaker:"Manifesto Committee Chair",portrait:"official",tags:["manifesto","leak","damage"],prompt:"A secret plan to cut people's favorite free things leaked online. You can admit it's true, or lie and say the paper is fake and you changed your mind.",left:{id:"a",label:"Admit it is true.",tooltip:"A policy abandoned at the first leak was never a policy.",reveal:"You defend the subsidy cut openly. The honesty earns grudging respect in some quarters, but the beloved subsidy's defenders mobilise and the issue dogs the whole campaign.",effects:{GL:2,FI:3,EN:-13}},right:{id:"b",label:"Lie and say it was fake.",tooltip:"A leak is a chance to hear the room.",reveal:"You bin the unpopular plan and recast the draft. The flip-flop draws mockery, but the beloved subsidy survives and the campaign's biggest landmine is defused.",effects:{EN:5,GL:-3,FI:-6}}},{id:"party-0107",location:"party",arc:"party-t0-a102",stage:0,speaker:"Field Mobilisation Officer",portrait:"fixer",tags:["turnout","transport","poll-day"],prompt:"On voting day, you can send free buses only for the people voting for you, and leave the enemy voters stranded.",left:{id:"a",label:"Send free buses only for your voters.",tooltip:"I move my voters; theirs can walk.",reveal:"Your strongholds turn out in force on free buses while the opposition's wards wait for transport that never comes. The lopsided turnout flatters your win and fools no observer.",effects:{MI:5,GL:-6,EN:-6}},right:{id:"b",label:"Don't send buses, let everyone get there fairly.",tooltip:"A bus that only carries my voters is a thumb on the scale.",reveal:"You either drop the scheme or run it for all. Your raw turnout edge shrinks, but the poll-day logistics give your enemies nothing to point at.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0108",location:"party",arc:"party-t0-a103",stage:0,speaker:"Chief Whip",portrait:"official",tags:["confidence","majority","coalition"],prompt:"You are almost losing. You can secretly bribe a few independent politicians to win, or play fair and risk losing your power.",left:{id:"a",label:"Bribe them to win safely.",tooltip:"A government that wins its first vote narrowly never recovers.",reveal:"You purchase the cushion and win comfortably. The bought independents will be back for more all term, and your government is mortgaged to them from its first day.",effects:{MI:5,FA:2,FI:-3,EN:-6}},right:{id:"b",label:"Play fair and risk losing.",tooltip:"A majority I had to buy is a majority I do not have.",reveal:"You take the confidence vote on your honest count and scrape through. Governing the knife-edge is exhausting, but you owe no shadowy independents and the mandate is real.",effects:{GL:3,EN:3,MI:-3}}},{id:"party-0109",location:"party",arc:"party-t0-a104",stage:0,speaker:"Cabinet Secretary",portrait:"general",tags:["emergency","powers","rule"],prompt:'You can declare a "State of Emergency." This pauses all rules and lets you do whatever you want forever, but everyone will know you are a dictator.',left:{id:"a",label:"Declare a State of Emergency.",tooltip:"Order first; legitimacy can be rebuilt.",reveal:"You suspend rights and rule by decree. The streets fall silent under the clampdown, and the word 'dictator' attaches itself to you in every capital and every history book.",effects:{MI:6,GL:-16,EN:-13}},right:{id:"b",label:"Play by the normal rules, even if it's hard.",tooltip:"A leader who suspends the constitution has already abdicated.",reveal:"You refuse the emergency and ride out the unrest within constitutional bounds. It is harder and more dangerous, but you remain a head of government, not a usurper.",effects:{GL:5,EN:3,MI:-10}}},{id:"party-0110",location:"party",arc:"party-t0-a105",stage:0,speaker:"Professional Wing Coordinator",portrait:"fixer",tags:["bar-association","professionals","capture"],prompt:"Doctors and lawyers have their own groups. You can rig their votes so your friends are in charge of them too.",left:{id:"a",label:"Rig their votes so your friends are in charge.",tooltip:"The professions sway the educated; capture them.",reveal:"Your panels sweep the professional bodies on patronage and pressure. The lawyers, doctors, and engineers' associations become party annexes, and their independent voice — and credibility — dies.",effects:{MI:3,FA:2,EN:-6,GL:-6}},right:{id:"b",label:"Let the doctors and lawyers pick their own leaders.",tooltip:"A captured bar defends no one, least of all me.",reveal:"You let the professional bodies run free. They will sometimes pass resolutions against you, but their independence keeps them respected, and a free bar is a check worth having.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0111",location:"party",arc:"party-t0-a106",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["caretaker","judiciary","poll"],prompt:"You can make sure a friendly judge is the one watching the election so you can't lose.",left:{id:"a",label:"Make sure your friendly judge is watching.",tooltip:"Even a neutral office should hold a friendly face.",reveal:"You quietly time the judicial retirements so your man heads the poll-time authority. The 'neutral' oversight is neutral in name only, and the opposition smells it instantly.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Let the normal, fair judge watch.",tooltip:"A poll umpire I picked is no umpire at all.",reveal:"You leave the succession to run its natural course, friendly or not. You surrender a hidden lever, but the poll-time authority is genuinely impartial and its verdict will be believed.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0112",location:"party",arc:"party-t0-a107",stage:0,speaker:"Media Adviser",portrait:"fixer",tags:["celebrity","endorsement","image"],prompt:"A super famous movie star wants to run on your team. He is clueless about laws, but everyone will vote for him because he's famous.",left:{id:"a",label:"Let the clueless movie star run for your team.",tooltip:"Stardust wins seats that policy cannot.",reveal:"The star joins to adoring crowds and wins his seat on charisma. He is a magnet for the young and a liability in the chamber, every gaffe a headline, every absence noted.",effects:{MI:3,EN:2,GL:-3}},right:{id:"b",label:"Let him just cheer for you, but pick someone smart to run.",tooltip:"A famous face is an asset; a famous fool is a cost.",reveal:"You take the star's public backing but steer him away from a seat. You bank the glamour without saddling the benches with a celebrity who cannot legislate.",effects:{GL:2,MI:2,FA:-3}}},{id:"party-0113",location:"party",arc:"party-t0-a108",stage:0,speaker:"Coalition Manager",portrait:"official",tags:["coalition","programme","compromise"],prompt:"Your partner teams want opposite things. You can lie to both of them to keep them happy, or pick a side and make one team very angry.",left:{id:"a",label:"Lie to both to keep them happy.",tooltip:"A vague platform offends no partner.",reveal:"You fudge the programme into mush that everyone can sign. The alliance holds for the campaign, then tears itself apart in government over the contradictions you never resolved.",effects:{MI:2,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Pick a side and make clear rules.",tooltip:"A coalition that cannot agree a page cannot govern a country.",reveal:"You hammer out a real, consistent platform, losing a partner or two who cannot accept it. The alliance is smaller but governable, and voters know what it actually stands for.",effects:{GL:3,EN:3,FA:-6,MI:-3}}},{id:"party-0114",location:"party",arc:"party-t0-a109",stage:0,speaker:"Reconciliation Adviser",portrait:"official",tags:["banning","restoration","inclusion"],prompt:"A group that was banned a long time ago wants to come back and promises to be good.",left:{id:"a",label:"Keep them banned forever.",tooltip:"A banned enemy is a contained enemy.",reveal:"You refuse restoration. The party stays underground, its exclusion a permanent grievance and recruiting tool, and the politics of the banned festers beyond the ballot's reach.",effects:{MI:3,FA:2,EN:-6,GL:-6}},right:{id:"b",label:"Let them come back safely.",tooltip:"A grievance let into the chamber is a grievance out of the streets.",reveal:"You readmit the party on conditions. The hardliners howl about legitimising enemies, but an underground grievance becomes a contestable political force, answerable to voters.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0115",location:"party",arc:"party-t0-a110",stage:0,speaker:"Field Mobilisation Officer",portrait:"people",tags:["turnout","gotv","organisation"],prompt:"You can try to get everyone in the country to vote, or only wake up the people who like you and let the others sleep.",left:{id:"a",label:"Only wake up your friends to vote.",tooltip:"I wake my voters and let theirs dream.",reveal:"Your wards turn out heavily while the opposition's stay home, unprodded. The lopsided turnout pads your margins, and the selective mobilisation is one more managed feature of the result.",effects:{MI:5,EN:-3,GL:-3}},right:{id:"b",label:"Try to get everyone in the country to vote.",tooltip:"A high honest turnout is a mandate money cannot buy.",reveal:"You lift turnout everywhere, friend and foe alike. You forgo a turnout edge, but a high, genuine participation gives whatever result emerges a legitimacy nothing else can.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0116",location:"party",arc:"party-t0-a111",stage:0,speaker:"Local Government Secretary",portrait:"official",tags:["devolution","decentralisation","power"],prompt:"You can give small towns the money and power to fix their own problems. It helps them, but makes you less powerful.",left:{id:"a",label:"Keep all the power for yourself.",tooltip:"A capital that lets go of the purse lets go of the country.",reveal:"You keep the money and decisions in the centre's fist. Your grip stays tight, and local government remains a hollow shell where accountability and initiative go to die.",effects:{MI:3,EN:-6,GL:-3}},right:{id:"b",label:"Give the towns the money and power to fix things.",tooltip:"A nation governed only from the capital is barely governed.",reveal:"You push genuine money and authority down to elected councils. You loosen your grip and empower some rivals, but governance gets closer to the people and visibly better.",effects:{EN:6,GL:5,MI:-10}}},{id:"party-0117",location:"party",arc:"party-t0-a112",stage:0,speaker:"Culture Minister",portrait:"official",tags:["nationalism","law","speech"],prompt:"You can make a law that anyone who doesn't salute the flag perfectly goes to jail. This is a great excuse to arrest complainers.",left:{id:"a",label:"Make the strict flag law.",tooltip:"The symbols of the nation are above mockery.",reveal:"You criminalise disrespect of the national symbols. Patriots applaud, and the elastic offence becomes a convenient charge to level at any critic who steps out of line.",effects:{MI:3,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Let people show respect however they want.",tooltip:"Forced reverence is no reverence at all.",reveal:"You reject the law. The hardliners grumble that you failed to honour the nation, but you decline a cudgel that would have dressed censorship as patriotism.",effects:{GL:3,EN:3,MI:-3}}},{id:"party-0118",location:"party",arc:"party-t0-a113",stage:0,speaker:"Election Tech Adviser",portrait:"official",tags:["results","transmission","transparency"],prompt:"A new app lets everyone see the votes being counted instantly on their phones. This makes it impossible for you to cheat.",left:{id:"a",label:"Use the app to prove you are fair.",tooltip:"A count the whole country watches is a count it believes.",reveal:"You launch the transparent dashboard. Tampering becomes near-impossible and the result, whatever it is, is trusted — and you have closed off your own machine's options for good.",effects:{GL:6,EN:5,MI:-6}},right:{id:"b",label:"Say no to the app so you can control the numbers.",tooltip:"A dashboard that cannot be managed is a risk I need not take.",reveal:"You stick with the slower official channels. The flexibility to 'reconcile' close seats survives, and so does the public's weary assumption that the count is never quite clean.",effects:{MI:3,GL:-10,EN:-6}}},{id:"party-0119",location:"party",arc:"party-t0-a114",stage:0,speaker:"Education Affairs Secretary",portrait:"cleric",tags:["madrasa","recognition","votes"],prompt:"Religious schools want their easy tests to count the same as hard college tests for getting jobs. If you say yes, they will vote for you.",left:{id:"a",label:"Say yes so they vote for you.",tooltip:"A million graduates and their families are a bloc worth winning.",reveal:"You grant equivalence to the madrasa degrees. The religious bloc swings gratefully behind you, and the secular establishment recoils as the civil service opens to a parallel education it cannot vouch for.",effects:{MI:3,FA:2,EN:-10,GL:-10}},right:{id:"b",label:"Make them take a harder test first to be fair.",tooltip:"Equal recognition demands an equal standard.",reveal:"You offer recognition conditional on bridging courses in core subjects. The bloc is disappointed at the half-measure, but the civil service keeps a baseline and the secularists are mollified.",effects:{GL:3,EN:3,FA:-6,MI:-3}}},{id:"party-0120",location:"party",arc:"party-t0-a115",stage:0,speaker:"Campaign Data Director",portrait:"fixer",tags:["canvassing","data","privacy"],prompt:"Your helpers can secretly knock on doors and make lists of everyone's secrets and religion to figure out how to trick them.",left:{id:"a",label:"Tell them to make the secret lists.",tooltip:"Knowledge of the voter is power over the vote.",reveal:"Your canvassers compile an intimate map of every household. The targeting grows formidable, and a covert dossier on millions' private lives now sits on a party server, one breach from scandal.",effects:{MI:5,EN:-6,GL:-6}},right:{id:"b",label:"Tell them to just ask for votes normally.",tooltip:"A party that files its citizens is a state I do not want to lead.",reveal:"You canvass for support without building the secret dossier. Your targeting is cruder, but you refuse to assemble a surveillance file on the people you ask to trust you.",effects:{GL:3,EN:3,MI:-3}}},{id:"party-0121",location:"party",arc:"party-t0-a116",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["dissolution","parliament","tactic"],prompt:"You can cancel the government early to trick your enemies before they are ready for the election.",left:{id:"a",label:"Cancel early to trick them.",tooltip:"An opponent off-balance is an opponent beaten.",reveal:"You dissolve the house and rush the polls. The disorganised opposition is caught flat-footed, and you wear the charge of gaming the calendar for the win it buys you.",effects:{MI:5,GL:-6,EN:-3}},right:{id:"b",label:"Finish your normal time fairly.",tooltip:"A house cut short for tactics cheapens the next.",reveal:"You let the term run out naturally. The opposition gets time to organise, but you cannot be accused of dissolving democracy's clock whenever it suited you.",effects:{GL:3,EN:2,MI:-6}}},{id:"party-0122",location:"party",arc:"party-t0-a117",stage:0,speaker:"Chief Whip",portrait:"people",tags:["backbench","rebellion","policy"],prompt:"Your own team is refusing to vote for a terrible rule you made. You can bully them into voting yes, or listen to them and fix the rule.",left:{id:"a",label:"Bully them into voting yes.",tooltip:"A backbencher's job is to vote, not to think.",reveal:"You whip the bill through over the rebels' objections. It passes, and so does the public anger they warned of, landing on the very MPs you forced to swallow it.",effects:{MI:3,FA:2,EN:-10}},right:{id:"b",label:"Listen to them and fix the rule.",tooltip:"The benches closest to the people often see clearest.",reveal:"You amend the bill to meet the backbenchers' concerns. The cabinet's pride is dented and the bill weakened, but you have averted a doorstep disaster and kept your MPs loyal.",effects:{EN:5,GL:2,MI:-3}}},{id:"party-0123",location:"party",arc:"party-t0-a118",stage:0,speaker:"Party Treasurer",portrait:"official",tags:["donations","corporate","influence"],prompt:"A new rule will limit how much money rich people can give you. This makes things fairer, but you will be much poorer for the election.",left:{id:"a",label:"Stop the rule so you get the rich people's money.",tooltip:"A campaign starved of corporate cash is a campaign that loses.",reveal:"You kill the cap and the corporate money keeps flowing. The war chest stays fat, and the oligarchs' hooks stay deep in your policy, exactly as the reformers feared.",effects:{FI:5,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Agree to the rule to make things fair.",tooltip:"A party owned by donors governs for donors.",reveal:"You support capping and disclosing corporate money. The war chest thins painfully, but you loosen the oligarchs' grip and can credibly claim to have cleaned a corner of the system.",effects:{GL:5,EN:5,FI:-10,FA:-6}}},{id:"party-0124",location:"party",arc:"party-t0-a119",stage:0,speaker:"Information Commissioner",portrait:"official",tags:["rti","transparency","accountability"],prompt:"A new rule lets any normal person read the government's secret papers. This stops stealing, but means people will see your mistakes.",left:{id:"a",label:"Stop the rule to keep your secrets.",tooltip:"An open file is an open invitation to my enemies.",reveal:"You quietly hollow out the RTI regime with exemptions and delays. The corruption-fighters lose their best tool, and 'a government with something to hide' becomes the obvious reading.",effects:{MI:2,FA:2,EN:-10,GL:-10}},right:{id:"b",label:"Agree to the rule and show the papers.",tooltip:"Sunlight is the cheapest disinfectant a state can buy.",reveal:"You give the RTI law teeth and enforce it. Some embarrassing files surface and ministers squirm, but corruption gets harder and your reform credentials grow real.",effects:{GL:5,EN:5,FA:-6}}},{id:"party-0125",location:"party",arc:"party-t0-a120",stage:0,speaker:"Parliamentary Affairs Minister",portrait:"official",tags:["oversight","committee","audit"],prompt:"The team checking the government's spending is usually run by your enemies to keep things honest. You can put your friends in charge to hide your stealing.",left:{id:"a",label:"Put your friends in charge of checking the spending.",tooltip:"I will not hand my critics a microphone and my ledgers.",reveal:"You take the chair and stack the committee. Government spending sails through unexamined, and the one institution meant to catch waste and graft is turned into a shield for it.",effects:{MI:3,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Let your enemies check the spending to be honest.",tooltip:"Spending watched is spending behaved.",reveal:"You honour the convention and let the opposition scrutinise your ledgers. Some uncomfortable findings emerge, but waste is curbed and the house gains a working check.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0126",location:"party",arc:"party-t0-a121",stage:0,speaker:"Returning Officer Coordinator",portrait:"fixer",tags:["postal","service-voters","fraud"],prompt:"Soldiers voting by mail are easy to trick. You can secretly change all their votes to be for you.",left:{id:"a",label:"Secretly change the soldiers' votes.",tooltip:"The men in uniform vote as the chain suggests.",reveal:"You shepherd the postal votes into a reliable bloc. The numbers help, and the pattern — a service vote that breaks suspiciously one way — is logged by every observer watching.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Count their votes honestly.",tooltip:"A soldier's secret ballot is still a secret ballot.",reveal:"You insist the postal votes be handled openly and freely. You forgo a managed bloc, but you cannot be accused of voting the barracks by proxy.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0127",location:"party",arc:"party-t0-a122",stage:0,speaker:"Coalition Manager",portrait:"fixer",tags:["hung-parliament","kingmaker","deals"],prompt:"No one won the election entirely. You can buy a few small teams with giant bags of money to win, or try to run the country carefully with less power.",left:{id:"a",label:"Buy the small teams with money and jobs.",tooltip:"A government formed is a government; how matters later.",reveal:"You assemble the majority by buying the kingmakers wholesale. The cabinet bloats with bought men and their price tags, and your government begins life owing everyone everything.",effects:{MI:5,FA:2,FI:-6,EN:-6}},right:{id:"b",label:"Try to lead carefully with less power.",tooltip:"Better to govern honestly on a knife-edge than to buy a throne.",reveal:"You build a minority government surviving vote by vote. It is precarious and exhausting, but it is not a bazaar, and each policy must be argued and won rather than purchased.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0128",location:"party",arc:"party-t0-a123",stage:0,speaker:"Women's Wing Chief",portrait:"people",tags:["women","reserved-seats","reform"],prompt:"Women want to actually be voted into the special seats, instead of you just picking them. If you let them, you can't control who gets the seats.",left:{id:"a",label:"Let the women be voted in fairly.",tooltip:"A seat won is a voice; a seat granted is an echo.",reveal:"You back direct election for the women's seats. You lose dozens of controllable appointments, but a cohort of women MPs arrives with real mandates and real independence.",effects:{EN:6,GL:5,FA:-6,MI:-6}},right:{id:"b",label:"Keep picking the women yourself.",tooltip:"Why give away seats I currently simply assign?",reveal:"You preserve the nomination system. The women's wing is disappointed and the tokenism critique stands, but you keep dozens of safe, loyal seats firmly in your gift.",effects:{MI:3,FA:3,EN:-10,GL:-6}}},{id:"party-0129",location:"party",arc:"party-t0-a124",stage:0,speaker:"Election Logistics Officer",portrait:"shadow",tags:["polling-station","relocation","suppression"],prompt:"You can secretly move the voting boxes in the enemy's towns far away right before the vote, so they can't walk there in time.",left:{id:"a",label:"Move the boxes far away to trick them.",tooltip:"A booth moved is a vote not cast.",reveal:"You scatter the opposition's booths to far-off venues at the last hour. Their turnout sags as planned, and the manoeuvre, once mapped by observers, becomes textbook documented suppression.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Keep the boxes close so everyone can vote.",tooltip:"A voter should not need a map to find democracy.",reveal:"You keep every booth where the voters expect it. You forgo a quiet suppression tactic, but no one can chart a pattern of vanished polling stations in your enemies' wards.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0130",location:"party",arc:"party-t0-a125",stage:0,speaker:"Law Minister",portrait:"official",tags:["election-petition","courts","result"],prompt:"Your enemies went to court with proof that you cheated. You can tell the judges to throw all the proof in the trash without looking at it.",left:{id:"a",label:"Tell the judges to throw the proof in the trash.",tooltip:"A result reopened is a result undone.",reveal:"Your courts throw out every petition, evidence or not. The seats are safe and the message clear — the bench is yours — and the contested results stay forever disputed.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Let the judges look at the proof fairly.",tooltip:"A seat that survives the court is a seat I truly hold.",reveal:"You let the courts weigh the real cases. You may lose a few seats to honest rulings, but the ones you keep are unassailable and the judiciary keeps a shred of credibility.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0131",location:"party",arc:"party-t0-a126",stage:0,speaker:"Cyber Cell Commander",portrait:"shadow",tags:["deepfake","disinformation","smear"],prompt:"Your computer team made a fake, realistic video of your enemy saying something terrible. You can show it to everyone to ruin her, but it is a lie.",left:{id:"a",label:"Show everyone the fake video.",tooltip:"A lie that wins the day outlives its debunking.",reveal:"You loose the forgery and it rips through the timelines. It may swing the vote before it is exposed, and when it is, the trail back to your cell makes you the story for years.",effects:{MI:3,GL:-13,EN:-13}},right:{id:"b",label:"Do not use the fake video.",tooltip:"A throne won by a forgery rots from the seat up.",reveal:"You kill the operation. You forgo a devastating dirty trick, but you are spared the day a forensic analyst pins the fabrication on your government for all to see.",effects:{GL:5,EN:5,MI:-3}}},{id:"party-0132",location:"party",arc:"party-t0-a127",stage:0,speaker:"Strategy Director",portrait:"official",tags:["by-poll","succession","seat"],prompt:"An old politician died. You can give his job to his very smart daughter, or to a mindless helper who will just do whatever you say.",left:{id:"a",label:"Give the job to the mindless helper.",tooltip:"A grateful nobody serves better than a proud somebody.",reveal:"You parachute in the controllable outsider. He wins the safe seat and owes you all, and the late MP's daughter — and the constituency that loved her father — turn bitter.",effects:{MI:3,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Give the job to the smart daughter.",tooltip:"Merit and local roots win seats fixers cannot.",reveal:"You give the daughter the nomination on merit. The fixer loses his pawn and grumbles, but the seat is won warmly and the benches gain a leader rather than a placeholder.",effects:{EN:5,GL:3,FA:-3,MI:-3}}},{id:"party-0133",location:"party",arc:"party-t0-a128",stage:0,speaker:"Digital Government Adviser",portrait:"people",tags:["e-governance","services","corruption"],prompt:"You can use computers so people don't have to pay bribes to government workers anymore. The workers will be very mad they lost their extra money.",left:{id:"a",label:"Use the computers to stop the bribes.",tooltip:"A counter with no clerk has no palm to grease.",reveal:"You force the e-services through against the clerks' sabotage. The petty bribery at a thousand counters withers, citizens save time and money, and you bank a visible, popular win.",effects:{EN:6,GL:5,FI:2,FA:-6}},right:{id:"b",label:"Let the workers keep taking bribes.",tooltip:"Do not pick a fight with a million clerks at once.",reveal:"You let the digital push die quietly to keep the bureaucracy content. The counters stay manned and the palms stay greased, and the citizen keeps paying a small bribe for every stamp.",effects:{FA:3,FI:-3,EN:-10}}},{id:"party-0134",location:"party",arc:"party-t0-a129",stage:0,speaker:"Leader of the House",portrait:"official",tags:["parliament","accountability","norms"],prompt:"In meetings, people only ask you fake, easy questions to make you look smart. You can let them ask real, hard questions to prove you are a good leader.",left:{id:"a",label:"Keep only answering the fake, easy questions.",tooltip:"A minister cornered on live television is a wound.",reveal:"You keep the softballs flying. Your ministers are spared embarrassment, and parliament's central ritual of accountability stays a hollow performance everyone sees through.",effects:{MI:2,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Let them ask real, hard questions.",tooltip:"A minister who can answer hard questions is a minister worth having.",reveal:"You restore genuine question hour. Your weaker ministers flounder under real questioning, but the strong shine, the house comes alive, and accountability stops being a charade.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0135",location:"party",arc:"party-t0-a130",stage:0,speaker:"Labour Wing Secretary",portrait:"people",tags:["unions","affiliation","leverage"],prompt:"You can make the big worker groups join your team. They will vote for you, but you will have to actually give them what they want later.",left:{id:"a",label:"Make them join your team.",tooltip:"Organised labour, organised for me.",reveal:"You affiliate the big unions and gain disciplined muscle. They now expect delivery on wages and conditions, and the day you cannot, their organised power turns squarely against you.",effects:{MI:3,EN:3,FI:-6,FA:-3}},right:{id:"b",label:"Keep them away so you don't owe them anything.",tooltip:"A union in the tent demands the tent's wealth.",reveal:"You keep the unions independent. You forgo their organised turnout, but you are not held hostage to wage demands you may not be able to meet.",effects:{FI:3,MI:-3,EN:-3}}},{id:"party-0136",location:"party",arc:"party-t0-a131",stage:0,speaker:"Civic Education Director",portrait:"people",tags:["voter-education","awareness","turnout"],prompt:"You can pay to teach people how to spot election cheating. But if they learn, they might catch you cheating.",left:{id:"a",label:"Teach people how to spot cheating.",tooltip:"An informed electorate is a legitimate election.",reveal:"You fund honest voter education. Turnout and confidence rise, and so does the number of citizens who know exactly what an irregularity looks like — a price you accept for a credible vote.",effects:{GL:5,EN:5,MI:-6}},right:{id:"b",label:"Stop the classes so they don't learn.",tooltip:"Why teach the voter to catch me?",reveal:"You quietly defund the programme. The electorate stays hazier on its rights and easier to manage, and the democracy you preside over grows a little thinner and more cynical.",effects:{MI:2,GL:-6,EN:-6}}},{id:"party-0137",location:"party",arc:"party-t0-a132",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["cadres","violence","amnesty"],prompt:"Many of your helpers beat people up in the past. You can magically erase all their crimes to thank them for helping you.",left:{id:"a",label:"Erase their crimes so they don't go to jail.",tooltip:"I do not abandon the foot-soldiers who carried me.",reveal:"You wipe the cadres' cases clean en masse. Loyalty is rewarded and the machine reassured, and genuine thugs walk free alongside the wronged, impunity stamped a little deeper.",effects:{MI:3,FA:5,EN:-13,GL:-6}},right:{id:"b",label:"Let the judges send the bad ones to jail.",tooltip:"An amnesty for thugs is a licence for the next.",reveal:"You refuse the blanket pardon and let cases proceed individually. The cadres feel betrayed and some desert, but the genuinely innocent are cleared and the guilty face the law.",effects:{GL:5,EN:3,FA:-10}}},{id:"party-0138",location:"party",arc:"party-t0-a133",stage:0,speaker:"Overseas Wing Secretary",portrait:"shadow",tags:["overseas","voting","fraud"],prompt:"Your people in other countries are voting. Since no one is watching, you can easily sneak a bunch of fake votes in for yourself.",left:{id:"a",label:"Sneak in the fake votes.",tooltip:"Distant ballots are the least watched of all.",reveal:"You manufacture margins at the friendly embassies. The diaspora numbers swell suspiciously, and the watchdogs add 'phantom overseas votes' to the dossier on the election.",effects:{MI:3,GL:-10,EN:-6}},right:{id:"b",label:"Keep the faraway voting strictly fair.",tooltip:"A vote cast abroad must be as clean as one cast at home.",reveal:"You insist on full observation of the embassy ballots. You forgo an easy padding, but the diaspora vote becomes a point of pride rather than another asterisk.",effects:{GL:5,EN:2,MI:-6}}},{id:"party-0139",location:"party",arc:"party-t0-a134",stage:0,speaker:"Strategy Director",portrait:"fixer",tags:["independents","spoilers","tactics"],prompt:"You can secretly pay fake politicians to run in the election just to confuse people and steal votes from your real enemy.",left:{id:"a",label:"Pay the fake politicians to confuse people.",tooltip:"A split rival is a beaten rival.",reveal:"You bankroll the spoilers and the opposition vote fractures in the target seats. The tactic delivers, and the day a funded 'independent' talks, it confirms every accusation of a rigged field.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Play fair and win on your own.",tooltip:"A manufactured candidate is a confession in waiting.",reveal:"You refuse the spoiler scheme and fight the weak seats straight. You lose some you might have stolen, but no funded fake candidate can ever surface to sink you.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0140",location:"party",arc:"party-t0-a135",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["ombudsman","accountability","graft"],prompt:"The rules say there should be a special policeman who arrests government leaders who steal. No one has ever hired him. You can hire him now.",left:{id:"a",label:"Do not hire him, to keep your leaders safe.",tooltip:"An office uncreated cannot investigate me.",reveal:"You leave the post unfilled, as your predecessors did. The constitutional check stays a dead letter, and the corruption it was meant to catch goes on unmolested.",effects:{FA:2,MI:2,EN:-10,GL:-6}},right:{id:"b",label:"Hire the special policeman to stop the stealing.",tooltip:"A check unfilled for fifty years shames us all.",reveal:"You finally appoint a genuine ombudsman with teeth. Some of your own are caught in its early cases, but you accomplish what no government dared, and the reform is historic.",effects:{GL:6,EN:5,FA:-6,MI:-3}}},{id:"party-0141",location:"party",arc:"party-t0-a136",stage:0,speaker:"Home Affairs Coordinator",portrait:"official",tags:["magistrates","election-day","neutrality"],prompt:"Special judges are driving around on voting day. You can tell them to bully your enemies, or tell them to just keep everyone safe.",left:{id:"a",label:"Tell them to bully your enemies.",tooltip:"Authority on the ground should answer to me.",reveal:"Your magistrates lean on the opposition and overlook your side's tricks. The polls tilt under colour of law, and the partisan use of the bench becomes one more documented stain.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Tell them to just keep everyone safe.",tooltip:"A magistrate with a thumb on the scale poisons the whole poll.",reveal:"You instruct the magistrates to be strictly impartial. They keep order without favour, and the polls run with a fairness your fixers wanted to subvert.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0142",location:"party",arc:"party-t0-a137",stage:0,speaker:"Electoral Roll Officer",portrait:"shadow",tags:["nid","purge","disenfranchisement"],prompt:"You can use computers to erase poor people and minorities from the voting list so they can't vote against you.",left:{id:"a",label:"Erase them from the list secretly.",tooltip:"A roll trimmed of my enemies is a roll improved.",reveal:"You scrub the list with a partisan hand, and the poor, the migrant, and the minority find themselves voteless. The disenfranchisement is quiet, deniable, and — once mapped — damning.",effects:{MI:5,GL:-13,EN:-13}},right:{id:"b",label:"Keep the list fair and add anyone who is missing.",tooltip:"A purge that targets the poor is a coup with a database.",reveal:"You clean the roll honestly and run a drive to register the missing. The list loses its phantoms without losing its poor, and the franchise widens rather than narrows.",effects:{GL:5,EN:6,MI:-6}}},{id:"party-0143",location:"party",arc:"party-t0-a138",stage:0,speaker:"Youth Wing Coordinator",portrait:"people",tags:["youth","outreach","spending"],prompt:"Young people are very angry at you. You can throw a giant, expensive festival with concerts to trick them into liking you again.",left:{id:"a",label:"Throw the giant, expensive festival.",tooltip:"A bridge to the young is worth its price in taka.",reveal:"You bankroll the festival and reach a generation that had written you off. It is costly and some sneer at the gloss, but the outreach softens the youth's hostility a little.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Save the money and skip the festival.",tooltip:"A concert does not undo a killing.",reveal:"You decline the spending as hollow. The treasury is spared, but the alienated youth see no gesture at all, and the generational rift hardens another notch.",effects:{FI:3,EN:-10,GL:-3}}},{id:"party-0144",location:"party",arc:"party-t0-a139",stage:0,speaker:"Parliamentary Affairs Minister",portrait:"official",tags:["privilege","press","intimidation"],prompt:"Your friend wants to drag a news reporter into a scary government meeting to yell at him for writing a mean story.",left:{id:"a",label:"Let your friend drag the reporter in.",tooltip:"The dignity of the house must be defended.",reveal:"You let the house summon and censure the journalist. The press gallery gets the message and softens, and parliament adds 'cudgel against reporters' to its repertoire.",effects:{MI:3,FA:2,EN:-10,GL:-10}},right:{id:"b",label:"Stop your friend and let the reporter be.",tooltip:"A parliament that bullies the press fears it.",reveal:"You kill the privilege motion. The thin-skinned MP fumes, but the press keeps its independence and you are spared a needless fight with the entire media.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0145",location:"party",arc:"party-t0-a140",stage:0,speaker:"Cabinet Secretary",portrait:"official",tags:["ministers","conduct","accountability"],prompt:"Your leaders are obviously stealing money. You can force them to show their bank accounts and fire the thieves.",left:{id:"a",label:"Force them to show their accounts and fire them.",tooltip:"A cabinet of looters is a scandal with portfolios.",reveal:"You impose asset declarations and enforce resignations. A few loyal grandees fall and the cabinet trembles, but the public sees, astonished, that office is no longer a licence to loot.",effects:{GL:5,EN:6,FA:-10,MI:-3}},right:{id:"b",label:"Ignore it and let them keep stealing.",tooltip:"A loyal grandee's loyalty is bought with a free hand.",reveal:"You decline to bind your ministers. They stay loyal and enriched, and 'one law for them' becomes the defining grievance of your government.",effects:{FA:5,MI:2,EN:-13,GL:-6}}},{id:"party-0146",location:"party",arc:"party-t0-a141",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["president","cross-voting","discipline"],prompt:"You are voting for the President. Some of your friends want to vote for the wrong person as a joke. You can threaten them so they don't.",left:{id:"a",label:"Threaten them so they vote for your person.",tooltip:"A secret ballot is no excuse for disloyalty.",reveal:"You lean hard on the waverers and your candidate wins clean. The dissent is suppressed, but you have learned nothing about the discontent that prompted it, and it festers unspoken.",effects:{MI:3,FA:2,EN:-6}},right:{id:"b",label:"Let them vote in secret without threats.",tooltip:"A warning shot heard is a rebellion averted.",reveal:"You let the MPs vote freely and read the bruised result as the message it is. Your candidate squeaks in, and you act on the discontent before it grows into something you cannot whip.",effects:{GL:2,EN:3,FA:-3,MI:-3}}},{id:"party-0147",location:"party",arc:"party-t0-a142",stage:0,speaker:"General Secretary",portrait:"official",tags:["reshuffle","cabinet","balance"],prompt:"You have to switch your helpers around. You can pick the helpers who are dumb but loyal, or the very smart ones who might try to take your job.",left:{id:"a",label:"Pick the dumb, loyal helpers.",tooltip:"A loyal fool never sharpens a knife for me.",reveal:"You keep the faithful and the mediocre in post. The cabinet is safe and pliant, and the country is governed by people chosen for their harmlessness rather than their skill.",effects:{MI:2,FA:5,EN:-10,GL:-6}},right:{id:"b",label:"Pick the very smart helpers.",tooltip:"A government that cannot govern is loyal to nothing.",reveal:"You promote the capable, ambition and all. Governance sharpens and the public notices, and you accept the risk that one of your talents may grow large enough to threaten you.",effects:{EN:5,GL:5,FA:-10,MI:-3}}},{id:"party-0148",location:"party",arc:"party-t0-a143",stage:0,speaker:"Strategy Director",portrait:"official",tags:["referendum","legitimacy","gamble"],prompt:`People don't believe you won fairly. You can ask the whole country to vote "Yes" or "No" on if they want you to stay. It's a huge gamble.`,left:{id:"a",label:'Ask the country to vote "Yes" or "No".',tooltip:"A fresh mandate silences every whisper.",reveal:"You put your rule to the people. It is a genuine gamble, and the campaign consumes the country; whatever the result, you have staked your legitimacy on a single roll of the dice.",effects:{GL:3,EN:2,MI:-3}},right:{id:"b",label:"Don't take the risk.",tooltip:"A vote I might lose is a weapon I hand my enemies.",reveal:"You decline the plebiscite. You keep the doubts unresolved rather than risk a public verdict, and the legitimacy question goes on quietly eating at your authority.",effects:{MI:3,GL:-3,EN:-3}}},{id:"party-0149",location:"party",arc:"party-t0-a143",stage:1,speaker:"Strategy Director",portrait:"official",tags:["referendum","legitimacy","gamble"],prompt:'You did the "Yes" or "No" vote, but hardly anyone showed up, and the numbers are obviously fake.',left:{id:"a",label:"Brag loudly that everyone loves you.",tooltip:"A win is a win; let the doubters choke on it.",reveal:"You proclaim the implausible result a ringing endorsement. Your base cheers, but no one outside it believes a 98 percent on a 30 percent turnout, and the 'vindication' becomes a punchline.",effects:{MI:3,FA:2,GL:-13,EN:-10}},right:{id:"b",label:"Admit the vote was messy and calm down.",tooltip:"A boast no one believes is worse than silence.",reveal:"You acknowledge the weak turnout and claim only a modest mandate. The base wanted triumphalism, but the candour spares you the ridicule and salvages a sliver of credibility.",effects:{GL:3,EN:3,FA:-6,MI:-3}}},{id:"party-0150",location:"party",arc:"party-t0-a143",stage:2,speaker:"Strategy Director",portrait:"official",tags:["referendum","legitimacy","gamble"],prompt:"Because of the messy vote, your enemies demand a totally fair, watched election. If you say yes, you might lose your job.",left:{id:"a",label:"Ignore them and stay the boss.",tooltip:"I have had my plebiscite; I owe them no more.",reveal:"You refuse the clean election and hide behind the tainted referendum. The opposition's demand hardens into a movement, and your legitimacy gap, papered over, widens beneath the paper.",effects:{MI:3,GL:-13,EN:-10}},right:{id:"b",label:"Agree to the totally fair election.",tooltip:"Only a real vote ends a real doubt.",reveal:"You agree to the genuine, observed election. The hardliners call it surrender, but you gamble that a clean mandate, even a narrow one, is worth more than a hollow one defended forever.",effects:{GL:6,EN:5,MI:-13}}},{id:"party-0151",location:"party",arc:"party-t1-a0",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["election","caretaker","legitimacy"],prompt:"A term later, the same fault line tears open again. Your helper says you must let a fair, neutral team run the election, or the other side will quit and say you cheated.",left:{id:"a",label:"Refuse and run the election yourself.",tooltip:"A contest I run is a contest I survive.",reveal:"You keep control of the machinery and win the seats. Turnout is thin, the opposition cries fraud, and your mandate carries an asterisk abroad.",effects:{MI:8,GL:-16,EN:-10}},right:{id:"b",label:"Let the fair team run the election.",tooltip:"A legitimate loss beats an illegitimate win.",reveal:"You gamble on a clean vote. The world applauds the rare concession; your own machine panics that you have bet the house on the people.",effects:{GL:8,EN:5,MI:-16}}},{id:"party-0152",location:"party",arc:"party-t1-a0",stage:1,speaker:"General Secretary",portrait:"fixer",tags:["election","caretaker","legitimacy"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. The votes are close. You can secretly change the counting to make sure you win, but people might notice.",left:{id:"a",label:"Secretly change the votes to win.",tooltip:"A majority is not left to chance.",reveal:"Your majority is secured and unmistakably engineered. Observers document the irregularities; the result is yours and rotten at the root.",effects:{MI:6,GL:-16,EN:-13,FA:3}},right:{id:"b",label:"Let the real counting decide, even if you lose.",tooltip:"A stolen seat is a debt that comes due.",reveal:"You accept the honest tally and a slimmer majority. Governing is harder; the legitimacy you keep may matter more than the seats you lost.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0153",location:"party",arc:"party-t1-a1",stage:0,speaker:"Election Commission Liaison",portrait:"official",tags:["ec","institutions","appointments"],prompt:"A new season of power, an old problem with sharper teeth. You get to pick the new voting judges. You can pick your friends who will let you win, or honest people who might rule against you.",left:{id:"a",label:"Pick your friends to be the judges.",tooltip:"An umpire I pick does not call me out.",reveal:"The Commission becomes an extension of your office. It serves you flawlessly — and the institution's credibility, once spent, will not return when you need it.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Pick honest, fair people.",tooltip:"A referee everyone trusts protects the winner too.",reveal:"You stack the body with respected names. They will sometimes rule against you, but the elections they bless will be believed.",effects:{GL:6,EN:5,MI:-13}}},{id:"party-0154",location:"party",arc:"party-t1-a2",stage:0,speaker:"Street Operations Coordinator",portrait:"fixer",tags:["hartal","blockade","violence"],prompt:"The crisis returns, and this time the cabinet is watching. Your enemies are blocking the roads. You can send your own fighters to stop them, but it will be very violent.",left:{id:"a",label:"Send your fighters to stop them.",tooltip:"Meet their streets with ours.",reveal:"Your cadres clear the roads in running battles. Commerce resumes amid the wreckage, and the cycle of street violence now belongs to you both.",effects:{MI:6,EN:-16,FI:3,GL:-10}},right:{id:"b",label:"Let the police handle it safely.",tooltip:"Two mobs are worse than one.",reveal:"You refuse to militarise your supporters and let the police protect the routes. The blockade drags on and the economy bleeds, but no partisan blood is on your hands.",effects:{GL:3,EN:3,MI:-10,FI:-10}}},{id:"party-0155",location:"party",arc:"party-t1-a3",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["defection","coalition","horse-trading"],prompt:"Once more the issue lands on your desk, the stakes higher than before. You are losing votes. You can secretly promise bad politicians jobs and safety if they switch to your team.",left:{id:"a",label:"Buy their votes with jobs and safety.",tooltip:"A secured floor is worth a few favours.",reveal:"The MPs cross and your majority is iron. The cabinet bloats with bought men, their cases frozen, and the public reads the price tag.",effects:{MI:6,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Refuse to make secret, bad deals.",tooltip:"I will not staff a government with men I had to bribe.",reveal:"You decline the deal and govern on a knife-edge. Every vote is now a fight, but no minister sits in your cabinet to dodge a courtroom.",effects:{GL:5,EN:3,MI:-13}}},{id:"party-0156",location:"party",arc:"party-t1-a4",stage:0,speaker:"Religious Front Emissary",portrait:"cleric",tags:["islamist","alliance","secularism"],prompt:"Another year survived, and the reckoning circles back. A powerful religious group will help you win, but only if you make strict religious laws and take away women's rights.",left:{id:"a",label:"Take their help and make the strict laws.",tooltip:"Their squares are full and my margins are thin.",reveal:"Their mobilisation is yours now, and so are their conditions. The curriculum narrows, reformers despair, and your secular base feels sold.",effects:{MI:8,FA:3,EN:-16,GL:-13}},right:{id:"b",label:"Say no and protect everyone's rights.",tooltip:"I will not trade women's rights for a turnout.",reveal:"You refuse their terms. They can now march against you instead of with you, but the constitution's spine, and your liberal base, hold.",effects:{EN:6,GL:5,MI:-13}}},{id:"party-0157",location:"party",arc:"party-t1-a5",stage:0,speaker:"Tribunal Prosecutor",portrait:"official",tags:["1971","tribunal","justice"],prompt:"The ground has shifted; the same demand arrives with new menace. You are putting old war criminals on trial. You can rush the trials to punish them fast, or go slowly to be totally fair.",left:{id:"a",label:"Rush the trials to punish them fast.",tooltip:"Justice delayed is the guilty escaping.",reveal:"The convictions land quickly to roaring crowds, and your opposition is gutted. Legal observers question the haste, and the verdicts carry that shadow.",effects:{MI:6,FA:3,GL:-10,EN:3}},right:{id:"b",label:"Go slowly and make sure the trials are fair.",tooltip:"A reckoning built on shortcuts collapses.",reveal:"You demand rigorous trials. The base grows impatient and the weapon is blunter, but the verdicts that come will withstand history's scrutiny.",effects:{GL:6,EN:3,MI:-10}}},{id:"party-0158",location:"party",arc:"party-t1-a6",stage:0,speaker:"Student Wing President",portrait:"fixer",tags:["students","campus","extortion"],prompt:"History rhymes: the conflict reopens deeper than last time. Your student group is bullying kids at school. They want more power, but some say you need to stop their bullying.",left:{id:"a",label:"Give your student group more power.",tooltip:"The campuses are a fortress I cannot lose.",reveal:"The wing tightens its grip and delivers the campuses. Its abuses grow more brazen, a powder keg awaiting one viral video.",effects:{MI:6,EN:-16,GL:-10}},right:{id:"b",label:"Stop them and punish the bullies.",tooltip:"A wing that tortures students will one day burn me.",reveal:"You discipline the bosses and cut the extortion. The campuses loosen from your grip, but you have defused a bomb under your own house.",effects:{EN:6,GL:3,MI:-13}}},{id:"party-0159",location:"party",arc:"party-t1-a7",stage:0,speaker:"Party Elders' Council",portrait:"official",tags:["succession","dynasty","loyalty"],prompt:"Mid-reign, the old wound is torn afresh. The older leaders want you to name your child as the next boss right now. Others say you should pick the smartest person, not just your family.",left:{id:"a",label:"Name your child as the next boss.",tooltip:"A clear heir prevents a war of knives.",reveal:"The dynasty is secured and the council placated. Capable non-family leaders drift away, and the party's depth thins to a single bloodline.",effects:{MI:5,FA:6,GL:-6,EN:-6}},right:{id:"b",label:"Pick the smartest person instead.",tooltip:"A party is not an inheritance.",reveal:"You refuse to crown an heir and invite a real contest. The family is wounded and the council nervous, but the party keeps its best minds.",effects:{GL:5,EN:3,FA:-13,MI:-6}}},{id:"party-0160",location:"party",arc:"party-t1-a8",stage:0,speaker:"Attorney General",portrait:"official",tags:["opposition","courts","lawfare"],prompt:"The pressure you deferred has come due, larger now. A judge will put your biggest enemy in jail for an old crime if you want. This means she can't run against you in the election.",left:{id:"a",label:"Have the judge put her in jail.",tooltip:"Remove the rival, remove the race.",reveal:"She is sentenced and disqualified. Her party erupts and the chanceries issue statements, but the ballot now has no name on it but yours.",effects:{MI:8,GL:-16,EN:-10}},right:{id:"b",label:"Let the judge decide fairly on his own.",tooltip:"A throne with no challenger is a target.",reveal:"You refuse to script the verdict. She may yet stand against you, but no one can say you jailed your way to power.",effects:{GL:6,EN:5,MI:-13}}},{id:"party-0161",location:"party",arc:"party-t1-a8",stage:1,speaker:"Attorney General",portrait:"official",tags:["opposition","courts","lawfare"],prompt:"A later term, and the quarrel has hardened into a test. Your enemy is very sick in jail. If she dies there, everyone will hate you. Her family begs to take her to a hospital.",left:{id:"a",label:"Keep her locked in the jail.",tooltip:"A martyr in a cell is safer than a saint set free.",reveal:"You hold firm and the cell stays locked. Her health worsens in the headlines, and every cough becomes an indictment of you.",effects:{MI:5,GL:-13,EN:-13}},right:{id:"b",label:"Let her go to the hospital.",tooltip:"I will not let a corpse defeat me.",reveal:"You let her convalesce under guard at home. The base grumbles that the snake is loose, but you have denied her the one victory captivity offered.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0162",location:"party",arc:"party-t1-a9",stage:0,speaker:"Telecom Regulator",portrait:"official",tags:["internet","election","censorship"],prompt:"The country has changed, but this fault line has not — only worsened. You can turn off the internet on voting day so no one can see if you cheat.",left:{id:"a",label:"Turn off the internet on voting day.",tooltip:"What the cameras cannot upload did not happen.",reveal:"The country goes dark and the count proceeds unwatched. The result is clean-looking and universally disbelieved; the outage itself becomes the story.",effects:{MI:6,GL:-16,FI:-10,EN:-10}},right:{id:"b",label:"Keep the internet on for everyone.",tooltip:"A vote no one can film is a vote no one believes.",reveal:"You let the signal flow. Every irregularity is livestreamed, but so is every honest queue, and the result keeps its credibility.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0163",location:"party",arc:"party-t1-a10",stage:0,speaker:"District Organiser",portrait:"fixer",tags:["vote-buying","patronage","money"],prompt:"It returns, as these things do, with the patience gone. A helper wants to hand out secret envelopes of cash and free things to poor people the night before the vote to make them pick you.",left:{id:"a",label:"Give out the secret cash and free things.",tooltip:"An empty stomach has a short memory.",reveal:"The trucks roll out and the margins firm up. The treasury thins, the habit deepens, and your win smells of the bazaar.",effects:{MI:6,FI:-13,EN:-6,GL:-6}},right:{id:"b",label:"Say no and win fairly without bribes.",tooltip:"Buy a vote once and you rent it forever.",reveal:"You forbid the envelopes and campaign on roads and clinics built. The organisers fret over thin margins, but the votes you win, you keep.",effects:{EN:6,GL:5,FI:3,MI:-10}}},{id:"party-0164",location:"party",arc:"party-t1-a11",stage:0,speaker:"Electoral Roll Officer",portrait:"official",tags:["voter-roll","fraud","ghosts"],prompt:"Years on, the matter is no longer private; the press is already circling. The voting list has thousands of fake names and dead people on it. You can use these fake names to cheat and get more votes.",left:{id:"a",label:"Keep the fake names to get more votes.",tooltip:"A loyal voter need not be a living one.",reveal:"The phantom names stay, ready to be voted. Auditors will find them eventually, and when they do the whole tally is tainted.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Delete the fake names for a fair vote.",tooltip:"Ghosts vote, but they also haunt.",reveal:"You scrub the list to the living. Your stronghold margins shrink honestly, and the register can finally survive a recount.",effects:{GL:6,EN:5,MI:-13}}},{id:"party-0165",location:"party",arc:"party-t1-a12",stage:0,speaker:"Nominations Board Chair",portrait:"fixer",tags:["tickets","candidates","money"],prompt:"The same knot, retied tighter, lands before you once more. Many people want to be on your team. You can let the richest people buy their spots, or pick the people who work the hardest.",left:{id:"a",label:"Let the richest people buy the spots.",tooltip:"A campaign runs on cash, not character.",reveal:"The war chest fills in a week with businessmen-MPs who bought their seats. They will legislate for their own ledgers, and the grassroots see who was passed over.",effects:{FI:8,MI:3,EN:-13,GL:-10}},right:{id:"b",label:"Pick the hardest workers.",tooltip:"A bought candidate serves the buyer, not the booth.",reveal:"You hand seats to organisers who earned them. The campaign chest stays lean, but your benches fill with people the wards actually know.",effects:{EN:6,GL:3,MI:3,FI:-13}}},{id:"party-0166",location:"party",arc:"party-t1-a13",stage:0,speaker:"Media Adviser",portrait:"fixer",tags:["media","propaganda","press"],prompt:"Another monsoon, another return of an argument you cannot end. A rich friend offers to buy all the TV stations so they only say nice things about you and ignore your mistakes.",left:{id:"a",label:"Let him buy the TV stations.",tooltip:"He who owns the screen owns the story.",reveal:"The airwaves turn to praise overnight. Dissent migrates to the shadows of the internet, and 'press freedom' becomes a foreign talking point against you.",effects:{MI:6,FA:3,GL:-13,EN:-10}},right:{id:"b",label:"Say no and let the TV stations be honest.",tooltip:"A choir of yes-men cannot warn me of fire.",reveal:"You wave the tycoon off. The critical broadcasts sting nightly, but they are also the only honest mirror your government has.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0167",location:"party",arc:"party-t1-a14",stage:0,speaker:"Cyber Cell Commander",portrait:"shadow",tags:["trolls","disinformation","online"],prompt:"Deep into the reign, the issue demands a final-sounding answer. Your computer team wants to make thousands of fake internet accounts to spread lies about your enemies and trick people.",left:{id:"a",label:"Pay the computer team to spread lies.",tooltip:"The first lie of the morning sets the day.",reveal:"Ten thousand sock-puppets march on command. The discourse rots, journalists are doxxed, and when the operation leaks it confirms every accusation of manipulation.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Shut the computer team down.",tooltip:"An army of lies eventually turns its guns inward.",reveal:"You disband the operation. Your opponents own more of the timeline now, but your name is off the next disinformation exposé.",effects:{GL:5,EN:5,MI:-10}}},{id:"party-0168",location:"party",arc:"party-t1-a15",stage:0,speaker:"Coalition Manager",portrait:"official",tags:["coalition","allies","leverage"],prompt:"The reckoning you postponed has matured into a crisis. Your partner team threatens to leave unless you give them big jobs. If they leave, you might lose your power.",left:{id:"a",label:"Give them the big jobs so they stay.",tooltip:"A government standing is worth a crowded cabinet.",reveal:"You hand over the posts and the floor holds. Your partner struts as near-equal, and your own MPs resent the ministries they were promised.",effects:{MI:5,FA:-6,EN:-6,GL:3}},right:{id:"b",label:"Tell them no and let them leave.",tooltip:"I will not be governed by my own junior.",reveal:"You refuse, and they storm out. The arithmetic tightens to a knife's edge, but every remaining minister knows you do not bend to blackmail.",effects:{MI:-13,FA:5,EN:3}}},{id:"party-0169",location:"party",arc:"party-t1-a16",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["parliament","no-confidence","discipline"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. Some of your own teammates might vote against you because they are angry. You can scare them into obeying, or actually fix what they are angry about.",left:{id:"a",label:"Scare them into obeying you.",tooltip:"Discipline is taught in the dark.",reveal:"The waverers fall back into line, cowed. The motion dies, but a dozen MPs now serve you out of fear, and fear is a thin glue.",effects:{MI:6,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Listen to them and fix the problem.",tooltip:"A backbencher heard is a backbencher kept.",reveal:"You meet the rebels, concede a real reform, and win the floor in daylight. It cost you policy ground, but the loyalty you bought is genuine.",effects:{EN:5,GL:5,MI:-6}}},{id:"party-0170",location:"party",arc:"party-t1-a17",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["constitution","term-limits","power"],prompt:"The old fault line widens; this time there is no quiet option. You can change the rules so you are allowed to be the boss forever. But this shows everyone you never plan to leave.",left:{id:"a",label:"Change the rules to be boss forever.",tooltip:"Reform takes longer than a term allows.",reveal:"The amendment passes and the horizon clears. At home it reads as ambition unmasked; abroad, as one more strongman erasing his own exit.",effects:{MI:6,FA:3,GL:-16,EN:-13}},right:{id:"b",label:"Keep the rules normal.",tooltip:"A door I cannot lock behind me keeps me honest.",reveal:"You let the constraint stand. The dynasty's grip looks less total, but you have spared yourself the label of president-for-life.",effects:{GL:6,EN:5,MI:-6}}},{id:"party-0171",location:"party",arc:"party-t1-a18",stage:0,speaker:"Home Secretary",portrait:"official",tags:["banning","rivals","repression"],prompt:"Time has not healed it — the conflict comes back armed. You have a sneaky excuse to completely ban the enemy team so they can't run against you at all.",left:{id:"a",label:"Ban the enemy team.",tooltip:"A weed pulled does not seed.",reveal:"The party is dissolved and its cadres scattered or jailed. Your dominance is near-total, and so is the proof that you fear a fair fight.",effects:{MI:8,GL:-16,EN:-13}},right:{id:"b",label:"Let them run and try to beat them fairly.",tooltip:"A banned party becomes a legend; a beaten one becomes a footnote.",reveal:"You leave the rival legal and defeat it in the open. It survives to fight again, but your win carries no asterisk.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0172",location:"party",arc:"party-t1-a19",stage:0,speaker:"Party Treasurer",portrait:"fixer",tags:["funding","patrons","graft"],prompt:"Once again, and with the whole house holding its breath. A rich man who gave you a lot of money now wants special favors, like a free bank. You need his money for the next election.",left:{id:"a",label:"Give him the special favors.",tooltip:"The hand that feeds expects to be kissed.",reveal:"He gets his licence and his concession. The campaign chest is safe for another cycle, and a single oligarch now owns a wing of your economy.",effects:{FI:6,MI:3,EN:-13,GL:-10}},right:{id:"b",label:"Say no and find honest money instead.",tooltip:"A party owned by one man has only one voter.",reveal:"You turn him down and scramble for funding elsewhere. The next campaign will be leaner and harder, but no single patron holds your leash.",effects:{GL:5,EN:5,FI:-13}}},{id:"party-0173",location:"party",arc:"party-t1-a20",stage:0,speaker:"Ward Boss",portrait:"shadow",tags:["mastan","extortion","control"],prompt:"The matter resurfaces in a harder year, patience exhausted. Your best helper wins lots of votes, but he does it by being a scary bully and stealing from people.",left:{id:"a",label:"Keep the bully because he gets you votes.",tooltip:"A made ward is a won ward.",reveal:"He keeps delivering, and keeps grabbing. His enemies pile up, and one of his victims will eventually find a camera.",effects:{MI:6,EN:-13,GL:-6}},right:{id:"b",label:"Fire the bully to keep things clean.",tooltip:"A boss who owns the booth will one day own me.",reveal:"You strip him of cover and let the cases proceed. The ward's turnout machine sputters, but a liability has been removed before it blew.",effects:{EN:6,GL:3,MI:-13}}},{id:"party-0174",location:"party",arc:"party-t1-a21",stage:0,speaker:"Women's Wing Chief",portrait:"official",tags:["women","representation","reserved-seats"],prompt:"A later season of rule, the stakes now openly existential. You get to pick women for special government seats. You can pick hard-working leaders, or just pick the wives of your rich friends.",left:{id:"a",label:"Pick the wives of your rich friends.",tooltip:"The seats are a thank-you, not a ladder.",reveal:"Donors' wives take the benches and vote as told. The women's wing seethes, and the reform you boast of abroad rings hollow at home.",effects:{FA:5,FI:3,EN:-10,GL:-6}},right:{id:"b",label:"Pick the hard-working women leaders.",tooltip:"A reserved seat should hold a leader, not a placeholder.",reveal:"You elevate women who built the wards. The donors grumble at the snub, but your benches gain voices that actually represent someone.",effects:{EN:6,GL:5,FA:-6,MI:-3}}},{id:"party-0175",location:"party",arc:"party-t1-a22",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["defection","loyalty","betrayal"],prompt:"It comes around again, and the margin for error is gone. A good guy on your team might leave to join the enemies. You can ruin his life with a fake secret, or talk to him nicely to keep him.",left:{id:"a",label:"Ruin his life with a fake secret.",tooltip:"A loud man is silenced before he sings.",reveal:"The file leaks and his reputation buckles before he can cross. He is neutralised, and every honest MP learns what conscience costs in your party.",effects:{MI:6,FA:3,EN:-13,GL:-10}},right:{id:"b",label:"Talk to him nicely and fix his worries.",tooltip:"An honest critic kept is worth ten bought loyalists.",reveal:"You hear him out and act on one grievance. He stays, vocal but yours, and the benches see that integrity has a place after all.",effects:{EN:6,GL:5,MI:-6}}},{id:"party-0176",location:"party",arc:"party-t1-a23",stage:0,speaker:"Rally Coordinator",portrait:"fixer",tags:["rally","spectacle","mobilisation"],prompt:"The same demand, but the reign is older and the knives sharper. You can spend a giant amount of money to bus a million people to the city just to cheer for you and look powerful.",left:{id:"a",label:"Spend the money for the giant cheering crowd.",tooltip:"Power unseen is power doubted.",reveal:"The maidan overflows and the footage dominates the week. The cost is staggering and the city paralysed, but no one questions your reach.",effects:{MI:6,FA:3,FI:-13,EN:-6}},right:{id:"b",label:"Save the money and have a small, normal meeting.",tooltip:"A crowd I had to rent proves nothing.",reveal:"You convene a focused, modest gathering. The spectacle is smaller, but the treasury and the city's patience are spared, and the agenda actually gets done.",effects:{FI:5,EN:3,MI:-6}}},{id:"party-0177",location:"party",arc:"party-t1-a24",stage:0,speaker:"Tribunal Prosecutor",portrait:"official",tags:["1971","execution","timing"],prompt:"Years deep, the unresolved returns to be resolved for good. You can hang a bad war criminal right before the election to make your fans cheer.",left:{id:"a",label:"Hang the criminal right before the election.",tooltip:"Justice and the calendar can keep step.",reveal:"The hanging lands days before the vote and the base roars. The cynicism is noted at home and abroad — a reckoning turned into a campaign prop.",effects:{MI:6,FA:3,EN:3,GL:-10}},right:{id:"b",label:"Let the law happen on its own normal time.",tooltip:"A gallows is not a campaign poster.",reveal:"You let the process conclude when it concludes. The base would have preferred the theatre, but the verdict keeps its dignity intact.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0178",location:"party",arc:"party-t1-a25",stage:0,speaker:"Culture Minister",portrait:"official",tags:["legacy","dynasty","naming"],prompt:"The conflict reignites, and the world is watching this time. Your friends want to name the airport, schools, and bridges after your family so no one ever forgets you.",left:{id:"a",label:"Say yes and name everything after your family.",tooltip:"A name on the map is a claim on the future.",reveal:"The signs change across the country. Your lineage is everywhere now — and so is the evidence, for critics, of a personality cult.",effects:{FA:6,MI:3,EN:-10,GL:-10}},right:{id:"b",label:"Say no to renaming everything.",tooltip:"A dynasty secure in itself need not shout.",reveal:"You let the airports keep their names. The family's elders sulk at the modesty, but the state stays larger than your bloodline.",effects:{GL:5,EN:3,FA:-10}}},{id:"party-0179",location:"party",arc:"party-t1-a26",stage:0,speaker:"Polling Agent Coordinator",portrait:"fixer",tags:["booth-capture","election-day","violence"],prompt:"A familiar crisis, escalated by everything you let slide. On voting day, your team can secretly kick out the other team's checkers and stuff the boxes with fake votes for you.",left:{id:"a",label:"Tell your team to stuff the boxes with fake votes.",tooltip:"The last hour decides the count.",reveal:"The boxes fill and the seats are yours. Phone videos of ejected agents go viral by nightfall, and the dozen seats become a dozen scandals.",effects:{MI:6,GL:-16,EN:-13}},right:{id:"b",label:"Tell them to stop and keep the voting fair.",tooltip:"A captured booth is a confession on film.",reveal:"You order the agents to stand down and the count to stand. You may lose some of the twelve, but you keep the only thing a margin is worth — belief.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0180",location:"party",arc:"party-t1-a27",stage:0,speaker:"Party Elders' Council",portrait:"official",tags:["generations","renewal","loyalty"],prompt:"The fault line cracks wider; the decision can no longer wait. The very old leaders won't give up their jobs to the younger, smarter people. If you force them out, they will be mad.",left:{id:"a",label:"Let the old leaders keep their jobs.",tooltip:"Loyalty earned over decades is not lightly retired.",reveal:"The veterans stay and the peace holds. The talented young drift toward NGOs and business, and the party ages with its leaders.",effects:{FA:3,MI:3,EN:-6,GL:-6}},right:{id:"b",label:"Give the jobs to the younger, smarter people.",tooltip:"A party that cannot renew itself buries itself.",reveal:"You move the forty-somethings into real power. The elders are wounded and noisy, but the benches suddenly have a future tense.",effects:{EN:6,GL:5,FA:-10,MI:-3}}},{id:"party-0181",location:"party",arc:"party-t1-a28",stage:0,speaker:"Parliamentary Affairs Minister",portrait:"official",tags:["speaker","parliament","fairness"],prompt:"Late in the reign, the old question demands a heavier answer. You get to pick the referee for the big government meetings. You can pick your friend who always lets you win, or a fair person.",left:{id:"a",label:"Pick your friend who always lets you win.",tooltip:"The chair should sit on my side of the aisle.",reveal:"Bills sail through and the opposition is muzzled at every turn. The house becomes a rubber stamp, and parliament's last shred of theatre dies.",effects:{MI:5,GL:-10,EN:-10}},right:{id:"b",label:"Pick a fair person.",tooltip:"A fair umpire makes my wins count.",reveal:"The house gets a Speaker both sides respect. Your rivals get their moments, but the chamber's rulings carry weight again.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0182",location:"party",arc:"party-t1-a29",stage:0,speaker:"Overseas Wing Secretary",portrait:"fixer",tags:["diaspora","funding","foreign"],prompt:"It returns once more — and this round may be the one remembered. Your friends in other countries want to send you lots of secret money for your campaign. It is illegal to take secret foreign money.",left:{id:"a",label:"Take the secret foreign money.",tooltip:"A son abroad still pays his mother's bills.",reveal:"The funds arrive off the books and the chest swells. Somewhere a paper trail survives, and when it surfaces it will read as foreign money buying your government.",effects:{FI:6,MI:2,GL:-13,EN:-6}},right:{id:"b",label:"Say no to the illegal money.",tooltip:"Money I cannot name is a leash I cannot see.",reveal:"You insist on clean, declared donations only. The chest grows slower, but no foreign-funding exposé waits in your future.",effects:{GL:5,EN:3,FI:-10}}},{id:"party-0183",location:"party",arc:"party-t1-a30",stage:0,speaker:"Minorities Cell Convenor",portrait:"official",tags:["minorities","secularism","vote-bank"],prompt:"The reckoning circles back, grown teeth in the waiting. Small religious groups always vote for you, but they are being attacked. They want you to protect them loudly, which might upset the big groups.",left:{id:"a",label:"Just say sorry, but don't upset the big groups.",tooltip:"A bloc that has nowhere else to go waits patiently.",reveal:"You issue statements and little else. The minorities feel taken for granted, and the next attack erodes a loyalty you assumed was permanent.",effects:{MI:2,EN:-10,GL:-6}},right:{id:"b",label:"Protect them loudly and punish the attackers.",tooltip:"A protected vote is a kept vote.",reveal:"You deploy security and jail the ringleaders. The hardline preachers rage, but the minority bloc rallies to you with real gratitude.",effects:{EN:6,GL:5,MI:-6,FA:-3}}},{id:"party-0184",location:"party",arc:"party-t1-a31",stage:0,speaker:"Strategy Director",portrait:"shadow",tags:["dummy-candidates","election","manipulation"],prompt:'Another term, the same antagonist, the stakes raised again. Your enemies are quitting the election. You can pay fake "enemies" to run against you so it looks like a real game.',left:{id:"a",label:"Pay fake enemies to run against you.",tooltip:"An empty stage needs painted rivals.",reveal:"The ballot fills with your own men pretending to oppose you. Observers see through it instantly, and the charade becomes shorthand for the whole farce.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Just run alone and let people see the truth.",tooltip:"A staged fight fools no one and shames me.",reveal:"You let the contest be what it is — thin, but honest. The optics of a low-turnout win are bad, but not as bad as being caught faking your own opposition.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0185",location:"party",arc:"party-t1-a32",stage:0,speaker:"Cabinet Secretary",portrait:"official",tags:["bureaucracy","purge","patronage"],prompt:"The matter, long deferred, lands with the force of a verdict. You can fire all the government workers who used to work for the old boss and replace them with your own fans.",left:{id:"a",label:"Fire them and hire only your fans.",tooltip:"A machine must answer to one hand.",reveal:"Loyalists rise and capable neutrals rot in OSD limbo. The government does as told, and the institution's professionalism bleeds out with the purged.",effects:{MI:6,EN:-10,GL:-10}},right:{id:"b",label:"Keep the good workers, even if they worked for the old boss.",tooltip:"A bureaucracy I gut once will fail me later.",reveal:"You promote on competence and let officers serve the office, not the person. Some will drag their feet on your worst ideas — which is rather the point.",effects:{EN:5,GL:5,MI:-10}}},{id:"party-0186",location:"party",arc:"party-t1-a33",stage:0,speaker:"Party Historian",portrait:"official",tags:["history","martyrs","narrative"],prompt:"Years on and unhealed, the conflict returns to claim its answer. A helper wants to change the history books to make the enemy team look like killers, just to make your team look better.",left:{id:"a",label:"Change the history books to make them look bad.",tooltip:"Yesterday's blood is today's mandate.",reveal:"The speeches land like blows and the base is electrified. The opposition is painted as murderers' heirs, and any hope of national reconciliation dies on the dais.",effects:{MI:5,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Keep the history books honest and respectful.",tooltip:"A grave is not a campaign stop.",reveal:"You honour the dead without naming the living as villains. The base wanted more fire, but the day keeps its solemnity and you keep the high ground.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0187",location:"party",arc:"party-t1-a34",stage:0,speaker:"Law Minister",portrait:"official",tags:["judiciary","appointments","independence"],prompt:"The same fault line, the harder hour, the narrower path. You get to pick two big judges before a big court case about you. You can pick your friends to make sure you win.",left:{id:"a",label:"Pick your friends as the judges.",tooltip:"A verdict is safest decided before the hearing.",reveal:"Your judges take their seats and the ruling goes your way. The judgment is sound on paper and stillborn in credibility; the court is now visibly yours.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Pick the smartest judges and hope for the best.",tooltip:"A court I own cannot protect me from the one who owns me next.",reveal:"You elevate the senior, respected names. They may rule against you, but a judiciary that can say no is the only one whose yes means anything.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0188",location:"party",arc:"party-t1-a35",stage:0,speaker:"District President",portrait:"people",tags:["grassroots","accountability","local"],prompt:"It comes back sharpened by every season you survived. People hate one of your politicians because he is mean and steals. You can protect him, or fire him and listen to the people.",left:{id:"a",label:"Protect the mean politician.",tooltip:"A sitting MP's machine is not lightly broken.",reveal:"You back your man and the machine grinds on. The workers feel betrayed and stay home, and the seat that looked safe wobbles.",effects:{MI:3,FA:2,EN:-10,GL:-3}},right:{id:"b",label:"Fire him and listen to the people.",tooltip:"A party that won't hear its base goes deaf.",reveal:"You drop the incumbent and let the workers pick. He fumes and threatens to bolt, but the district roars back to life around its own choice.",effects:{EN:6,MI:-6,FA:-3,GL:2}}},{id:"party-0189",location:"party",arc:"party-t1-a36",stage:0,speaker:"Establishment Minister",portrait:"official",tags:["jobs","patronage","youth"],prompt:"A later year of power, the old crisis now a true test of it. You are hiring thousands of new government workers. You can secretly give all the jobs to your fans, or give them to the smartest people.",left:{id:"a",label:"Secretly give the jobs to your fans.",tooltip:"A job given is a vote owned for life.",reveal:"Cadres' sons fill the rolls and a generation is bound to you. The merit-passed-over seethe, and the civil service inherits a cohort hired for loyalty, not skill.",effects:{MI:5,FA:3,EN:-13,GL:-6}},right:{id:"b",label:"Give the jobs to the smartest people.",tooltip:"A government staffed by favours governs like one.",reveal:"You run a clean recruitment. The youth wing howls at the lost spoils, but you gain a competent intake and the credit for a fair process.",effects:{EN:6,GL:3,FA:-6,MI:-6}}},{id:"party-0190",location:"party",arc:"party-t1-a37",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["reconciliation","rivals","unity"],prompt:"The unresolved returns, and this time it will not be deferred. An old leader who left your team angry wants to come back. He brings lots of votes but also lots of drama.",left:{id:"a",label:"Welcome him back for the votes.",tooltip:"A returned rival fights for you, not against.",reveal:"He rejoins to fanfare, faction and all, and your numbers swell. He also resumes manoeuvring from the inside, an old knife back in the drawer.",effects:{MI:5,FA:-3,EN:2,GL:2}},right:{id:"b",label:"Tell him to stay away.",tooltip:"A man who left once leaves twice.",reveal:"You refuse the reunion. His faction stays outside and occasionally bites, but your inner circle is spared a practised intriguer.",effects:{FA:3,MI:-6,EN:-3}}},{id:"party-0191",location:"party",arc:"party-t1-a38",stage:0,speaker:"Religious Front Emissary",portrait:"cleric",tags:["islamist","blasphemy","alliance"],prompt:"A term later, the same fault line tears open again. A strict religious group wants you to hang a man for his beliefs and ban a nice charity. They will help you win if you do it.",left:{id:"a",label:"Do what they want to get their help.",tooltip:"An ally's price rises with his usefulness.",reveal:"You give them the ban and the spectacle. The streets stay yours for now, but each concession shifts the country further from the constitution you swore to.",effects:{MI:5,FA:2,EN:-16,GL:-16}},right:{id:"b",label:"Say no and make them angry.",tooltip:"An ally who owns my conscience is my master.",reveal:"You decline, and they threaten to turn their squares against you. The winter ahead is colder, but you have stopped feeding the thing that would devour you.",effects:{EN:6,GL:6,MI:-13}}},{id:"party-0192",location:"party",arc:"party-t1-a39",stage:0,speaker:"Leader of the House",portrait:"official",tags:["parliament","boycott","legitimacy"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. The enemy team is not at the meeting. You can quickly pass all your new rules without anyone arguing with you.",left:{id:"a",label:"Pass all the rules quickly while they are gone.",tooltip:"An absent opposition forfeits its say.",reveal:"Laws pour through unopposed in days. The efficiency is real and the legitimacy is gone; you have legislated alone and it shows on every statute.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Wait for them to come back to be fair.",tooltip:"Laws made in an empty room echo hollow.",reveal:"You hold the most divisive bills and leave the door ajar for the opposition's return. Less gets done, but parliament keeps a pulse.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0193",location:"party",arc:"party-t1-a40",stage:0,speaker:"Election Tech Adviser",portrait:"official",tags:["evm","election","trust"],prompt:"A new season of power, an old problem with sharper teeth. You are getting new voting machines. You can make them secret so no one can check the math, which makes it easy to cheat.",left:{id:"a",label:"Use the secret machines so you can cheat.",tooltip:"A count with no receipt cannot be challenged.",reveal:"The machines report whatever they report and nothing can check them. The opposition's distrust hardens into certainty, and every result is now disputed by design.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Make sure the machines print paper receipts to be fair.",tooltip:"A vote no one can recount is no vote at all.",reveal:"Every machine prints a verifiable receipt. The technology stops being a conspiracy and starts being a count people might actually believe.",effects:{GL:6,EN:5,FI:-6,MI:-6}}},{id:"party-0194",location:"party",arc:"party-t1-a41",stage:0,speaker:"Field Security Chief",portrait:"shadow",tags:["intimidation","polling","agents"],prompt:"The crisis returns, and this time the cabinet is watching. A guard suggests scaring the other team's checkers the night before the vote, so they don't show up and you can cheat easily.",left:{id:"a",label:"Scare the checkers away.",tooltip:"An unwatched booth is an obedient booth.",reveal:"The agents melt away and the marginals go unobserved. The pattern is unmistakable to anyone looking, and many are looking.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Say no and let them check the votes.",tooltip:"Fear at the booth poisons the whole well.",reveal:"You order the pressure stopped. The opposition watches every box, catches you on nothing, and the contest is cleaner than your fixers wanted.",effects:{GL:5,EN:5,MI:-10}}},{id:"party-0195",location:"party",arc:"party-t1-a42",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["defection","poaching","majority"],prompt:"Once more the issue lands on your desk, the stakes higher than before. You can bribe a smart, young enemy leader to join your team by offering him a big job. This makes you look powerful but unfair.",left:{id:"a",label:"Bribe him to join your team.",tooltip:"Their best man is better as mine.",reveal:"He crosses to fanfare and the opposition loses a future. He governs his district as a fief, and the message lands: in your house, talent is bought.",effects:{MI:5,FA:2,EN:-6,GL:-6}},right:{id:"b",label:"Leave him alone to rise on his own.",tooltip:"A man I had to buy will be bought from me.",reveal:"You pass on the poach. He stays a thorn across the aisle, but your benches are not staffed by mercenaries, and your district bosses keep their turf.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0196",location:"party",arc:"party-t1-a43",stage:0,speaker:"Election Commission Liaison",portrait:"official",tags:["ballot","symbol","advantage"],prompt:"Another year survived, and the reckoning circles back. You can secretly trick the voting papers so your name is always at the top and easy to find, making you win more.",left:{id:"a",label:"Trick the voting papers.",tooltip:"A small edge, multiplied by millions.",reveal:"Your symbol sits first on every paper and the marginal voter's thumb drifts your way. It is petty and effective, and observers log every tilted ballot.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Make the papers fair and random.",tooltip:"A win bought by ballot order is not a win.",reveal:"You order the symbols randomised and fair. You forgo a quiet edge, but the ballot itself stops being evidence against you.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0197",location:"party",arc:"party-t1-a44",stage:0,speaker:"City Campaign Manager",portrait:"fixer",tags:["mayor","dhaka","election"],prompt:"The ground has shifted; the same demand arrives with new menace. Your friend is running for mayor but people don't like him. You can cheat to make him win, or replace him with someone people actually like.",left:{id:"a",label:"Cheat to make your friend win.",tooltip:"The capital cannot fall to a rival.",reveal:"Your man takes the city hall on a tide of state largesse and managed counts. He governs the capital you can no longer claim was freely won.",effects:{MI:5,FI:-10,GL:-10,EN:-6}},right:{id:"b",label:"Let the popular person run instead.",tooltip:"A mayor the city chose serves the city — and reflects on me.",reveal:"You back a candidate people actually like. He owes you little and may freelance, but a clean win in the capital buys you legitimacy money cannot.",effects:{EN:6,GL:5,MI:-6,FA:-3}}},{id:"party-0198",location:"party",arc:"party-t1-a45",stage:0,speaker:"Street Operations Coordinator",portrait:"fixer",tags:["hartal","arson","escalation"],prompt:"History rhymes: the conflict reopens deeper than last time. Your enemies burned a bus. Your team wants to go burn down their buildings to get revenge.",left:{id:"a",label:"Let your team burn down their buildings.",tooltip:"Blood answers blood, or it never stops.",reveal:"Your cadres burn back and the season descends into mutual arson. The economy seizes, the morgues fill, and both sides own the ashes.",effects:{MI:5,EN:-16,FI:-10,GL:-10}},right:{id:"b",label:"Stop your team and let the police handle it.",tooltip:"I will not turn a blockade into a civil war.",reveal:"You refuse to escalate and let the police hunt the bombers. The blockade still bites, but the bloodshed has only one author, and it is not you.",effects:{GL:5,EN:3,MI:-6,FI:-6}}},{id:"party-0199",location:"party",arc:"party-t1-a46",stage:0,speaker:"Party Historian",portrait:"official",tags:["legacy","founder","cult"],prompt:"Mid-reign, the old wound is torn afresh. Your friends want to build a giant, super expensive museum just to talk about how great your family is.",left:{id:"a",label:"Build the giant, expensive museum.",tooltip:"A founder's shrine anchors a movement forever.",reveal:"The marble rises and the pilgrimages begin. The reverence is enforced and total, and the treasury and the country's pluralism both pay for it.",effects:{FA:6,MI:3,FI:-10,GL:-6}},right:{id:"b",label:"Build a small, normal memorial instead.",tooltip:"A legacy that needs a palace was never solid.",reveal:"You approve a dignified, smaller tribute. The family's elders feel slighted, but the funds and the breathing room for other histories survive.",effects:{GL:3,EN:3,FI:2,FA:-10}}},{id:"party-0200",location:"party",arc:"party-t1-a47",stage:0,speaker:"Labour Wing Secretary",portrait:"people",tags:["labour","garments","wages"],prompt:"The pressure you deferred has come due, larger now. Factory workers want better pay. If you help them, they will vote for you, but the rich factory owners will be furious.",left:{id:"a",label:"Help the rich factory owners.",tooltip:"The cheques come from the gate, not the floor.",reveal:"You quietly throttle the wage push to keep the owners happy. The chest stays full, and a million workers learn whose party this really is.",effects:{FI:5,FA:2,EN:-13,GL:-6}},right:{id:"b",label:"Help the workers get better pay.",tooltip:"A million floor votes outweigh a hundred gate cheques.",reveal:"Your wing fronts the agitation and wins a real raise. The owners fume and trim their donations, but the workers' districts are yours for a generation.",effects:{EN:6,GL:3,FI:-10,MI:2}}},{id:"party-0201",location:"party",arc:"party-t1-a48",stage:0,speaker:"Strategy Director",portrait:"official",tags:["by-election","barometer","risk"],prompt:"A later term, and the quarrel has hardened into a test. There is a small vote happening. You can cheat to win easily, or play fair and risk losing to see how people really feel.",left:{id:"a",label:"Cheat to win the small vote safely.",tooltip:"A loss now is a flood later.",reveal:"You secure the seat the old way and avoid the bad headline. You also blind yourself to how thin your support has worn, governing on a number you faked.",effects:{MI:3,GL:-6,EN:-6}},right:{id:"b",label:"Play fair and risk losing.",tooltip:"Better to read the ground than to pave over it.",reveal:"You run it honestly. Win or lose, you finally know where you stand — and if you lose, you learn it now, while there is time to act.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0202",location:"party",arc:"party-t1-a49",stage:0,speaker:"Law Minister",portrait:"official",tags:["contempt","press","speech"],prompt:"The country has changed, but this fault line has not — only worsened. A news writer called you a thief. You can throw him in jail to scare everyone, or just show proof that he is wrong.",left:{id:"a",label:"Throw the writer in jail.",tooltip:"An example silences a chorus.",reveal:"He is jailed and the newsrooms flinch. The corruption story is buried under his arrest, which becomes the bigger, longer-running scandal.",effects:{MI:5,FA:2,GL:-13,EN:-10}},right:{id:"b",label:"Show proof he is wrong and let him go.",tooltip:"A government that answers fears nothing.",reveal:"You publish the records that refute him and let him keep printing. The base wanted him jailed, but you have won the argument instead of the arrest.",effects:{GL:6,EN:5,MI:-6}}},{id:"party-0203",location:"party",arc:"party-t1-a50",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["floor-crossing","discipline","law"],prompt:"It returns, as these things do, with the patience gone. You can make a strict rule that anyone on your team who disagrees with you goes to jail. This stops all arguing.",left:{id:"a",label:"Make the strict rule to stop arguing.",tooltip:"A whip with teeth needs no second crack.",reveal:"Abstention becomes career suicide and every vote is unanimous. Your benches are flawless and lifeless, a parliament that cannot think, only obey.",effects:{MI:5,GL:-10,EN:-10}},right:{id:"b",label:"Let people disagree and vote how they want.",tooltip:"An MP who cannot ever say no is not a representative.",reveal:"You permit dissent on matters of conscience. A few votes get messier, but your benches contain humans again, and the house earns a little respect.",effects:{GL:5,EN:5,MI:-10}}},{id:"party-0204",location:"party",arc:"party-t1-a51",stage:0,speaker:"Coalition Manager",portrait:"fixer",tags:["seats","allies","arithmetic"],prompt:"Years on, the matter is no longer private; the press is already circling. Your smaller partner teams want to run in the election too. You can bully them into taking the worst spots, or be generous.",left:{id:"a",label:"Bully them and keep the best spots for yourself.",tooltip:"An alliance is a pyramid, not a partnership.",reveal:"Your candidates get the winnable seats and the partners get crumbs. You dominate the alliance and hollow it, leaving allies who campaign at half-effort.",effects:{MI:5,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Be generous and share the good spots.",tooltip:"A partner fed campaigns harder than one starved.",reveal:"You give the small parties real winnable seats. Your own count is slimmer, but the alliance pulls together and turns out as one.",effects:{EN:3,GL:3,MI:-3,FA:-3}}},{id:"party-0205",location:"party",arc:"party-t1-a52",stage:0,speaker:"Student Wing President",portrait:"fixer",tags:["martyr","funeral","mobilisation"],prompt:"The same knot, retied tighter, lands before you once more. One of your young helpers died fighting the enemy. Your team wants to carry his body through the city to make everyone angry and start a huge fight.",left:{id:"a",label:"Have the big, angry parade.",tooltip:"A martyr's coffin is a recruiting drum.",reveal:"The procession swells into a riot and the rivals are branded murderers. The base burns hot, the city burns with it, and another coffin is already on its way.",effects:{MI:5,FA:2,EN:-13,GL:-6}},right:{id:"b",label:"Have a quiet, respectful funeral.",tooltip:"I will not turn a boy's grave into a battlefield.",reveal:"You give the cadre a dignified, guarded farewell. The president wanted a spectacle and a casus belli; you gave him neither, and the city stays calm.",effects:{EN:5,GL:3,MI:-6}}},{id:"party-0206",location:"party",arc:"party-t1-a53",stage:0,speaker:"Foreign Liaison Officer",portrait:"ambassador",tags:["observers","election","legitimacy"],prompt:"Another monsoon, another return of an argument you cannot end. People from other countries want to watch your election to make sure it's fair. You can hide the cheating parts from them, or let them see everything.",left:{id:"a",label:"Hide things and make it hard for them to watch.",tooltip:"Witnesses are only invited to a clean house.",reveal:"The observers are penned far from the action and issue damning reports anyway. The restrictions themselves become the headline: a government afraid of being watched.",effects:{MI:3,GL:-13,EN:-6}},right:{id:"b",label:"Let them see everything and have a fair vote.",tooltip:"A vote that can be watched is a vote that is believed.",reveal:"You let the monitors go where they please. It forces discipline on your machinery, and the clean bill of health they give is worth a hundred press releases.",effects:{GL:6,EN:3,MI:-6}}},{id:"party-0207",location:"party",arc:"party-t1-a54",stage:0,speaker:"Anti-Graft Commission Chair",portrait:"official",tags:["acc","lawfare","selective"],prompt:"Deep into the reign, the issue demands a final-sounding answer. The police who catch thieves work for you. You can tell them to only arrest your enemies, or tell them to arrest anyone who steals, even your friends.",left:{id:"a",label:"Tell them to only arrest your enemies.",tooltip:"An investigator off the leash bites the master.",reveal:"The watchdog hounds your enemies and ignores your friends. It is devastatingly useful and visibly partisan, and your own grafters learn they are untouchable.",effects:{MI:5,FA:3,GL:-13,EN:-10}},right:{id:"b",label:"Tell them to arrest anyone who steals.",tooltip:"A watchdog that only bites the neighbour guards nothing.",reveal:"You unleash it on all comers, your side included. A few ministers fall and the base panics, but the Commission gains teeth the public actually trusts.",effects:{GL:6,EN:6,MI:-10,FA:-10}}},{id:"party-0208",location:"party",arc:"party-t1-a55",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["caretaker","constitution","power"],prompt:"The reckoning you postponed has matured into a crisis. You can make a rule that your team always stays in charge during elections, which makes it super easy to win every time.",left:{id:"a",label:"Make the rule so you always stay in charge.",tooltip:"Why concede each election what I can settle once?",reveal:"The amendment passes and the advantage is permanent. So is the opposition's casus belli; every future poll now inherits this original sin.",effects:{MI:6,GL:-13,EN:-10}},right:{id:"b",label:"Keep it fair and let a neutral team run elections.",tooltip:"A rule that survives me protects me from my successors.",reveal:"You keep — or restore — a neutral poll-time authority. You surrender a structural edge, but you drain the poison from every election to come.",effects:{GL:6,EN:5,MI:-10}}},{id:"party-0209",location:"party",arc:"party-t1-a56",stage:0,speaker:"Party Treasurer",portrait:"shadow",tags:["funding","black-money","audit"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. You have a giant pile of secret cash for the election. You can lie about where you got it, or only use honest money and have less to spend.",left:{id:"a",label:"Lie about the money and hide it.",tooltip:"Money has no smell once it is washed.",reveal:"The cash is scrubbed and the audit finds nothing — for now. The shells are a time bomb, and the day one bursts it takes a cabinet with it.",effects:{FI:5,MI:2,GL:-10,EN:-6}},right:{id:"b",label:"Only use honest money, even if it's less.",tooltip:"A washed rupee still stains the hand that spent it.",reveal:"You run on declared money and fight the campaign lean. The shortfall hurts at every rally, but no laundering scandal waits in your second term.",effects:{GL:5,EN:3,FI:-10}}},{id:"party-0210",location:"party",arc:"party-t1-a57",stage:0,speaker:"Party Elders' Council",portrait:"official",tags:["dynasty","nepotism","nominations"],prompt:"The old fault line widens; this time there is no quiet option. Your whole family wants to be politicians now because you are the boss. People might think you are just giving jobs to your relatives.",left:{id:"a",label:"Give your family the easy jobs.",tooltip:"Blood holds when everything else bends.",reveal:"The relatives are slotted into winnable seats. The dynasty's grip tightens, and the photo of the new parliamentary party looks like a wedding album.",effects:{FA:6,MI:2,EN:-10,GL:-6}},right:{id:"b",label:"Tell them no and pick the smartest people.",tooltip:"A party of cousins has no roots.",reveal:"You cap the relatives and open seats to organisers. The family is wounded and loud, but the benches gain people the wards chose.",effects:{EN:5,GL:3,FA:-13,MI:-3}}},{id:"party-0211",location:"party",arc:"party-t1-a58",stage:0,speaker:"Hill Affairs Convenor",portrait:"official",tags:["cht","indigenous","accord"],prompt:"Time has not healed it — the conflict comes back armed. People in the hills want you to keep an old promise to protect them. But the army and new settlers want to take their land.",left:{id:"a",label:"Help the army and the new settlers.",tooltip:"The plains vote outnumbers the hills.",reveal:"You shelve the accord again. The garrisons and settlers are pleased, and the hills add another broken promise to a decades-long ledger of them.",effects:{MI:3,FA:2,EN:-13,GL:-6}},right:{id:"b",label:"Keep the promise and protect the hill people.",tooltip:"A promise twenty years deferred is a wound.",reveal:"You move on land rights and a partial drawdown. The army and settlers resist hard, but the hills, for once, see the state keep its word.",effects:{EN:6,GL:5,MI:-10,FA:-3}}},{id:"party-0212",location:"party",arc:"party-t1-a59",stage:0,speaker:"Returning Officer Coordinator",portrait:"official",tags:["results","count","delay"],prompt:"Once again, and with the whole house holding its breath. The votes are coming in. You can pause the TV news to secretly change some numbers so you win, or show the honest truth instantly.",left:{id:"a",label:"Pause the news to secretly change numbers.",tooltip:"A few hours buys a comfortable margin.",reveal:"The overnight delay yields a tidier result and an obvious one. The gap between the late seats and the rest tells its own story to anyone counting.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Show the honest truth instantly.",tooltip:"A count that needs the night to fix was never counted.",reveal:"You declare on schedule, narrow margins and all. Governing the thinner majority is harder, but the result lands before anyone can call it cooked.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0213",location:"party",arc:"party-t1-a60",stage:0,speaker:"Personal Physician",portrait:"doctor",tags:["succession","health","dynasty"],prompt:"The matter resurfaces in a harder year, patience exhausted. You are very sick but no one knows. You can pick the next leader now, but people might stop listening to you early.",left:{id:"a",label:"Hide it and pretend you are perfectly fine.",tooltip:"A wounded king shows no blood.",reveal:"You hide the decline and grip the wheel. The succession stays unsettled, and the day the truth breaks the party will tear itself apart over a vacuum.",effects:{MI:3,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Pick the next leader now to be safe.",tooltip:"A transition I design beats one fought over my bed.",reveal:"You begin the handover on your own terms. Your authority ebbs the moment you announce, but the dynasty gains a real chance of surviving you.",effects:{FA:5,GL:3,EN:3,MI:-10}}},{id:"party-0214",location:"party",arc:"party-t1-a61",stage:0,speaker:"Election Commission Liaison",portrait:"official",tags:["recount","dispute","credibility"],prompt:"A later season of rule, the stakes now openly existential. The enemy wants to recount the votes because they think you cheated in one town. You can say no using a silly rule, or let them recount and risk losing.",left:{id:"a",label:"Say no and keep the win.",tooltip:"A win declared is a win kept.",reveal:"You deny the recount and the seat stands, disputed forever. The technicality fools no one, and the seat becomes a permanent symbol of the stolen vote.",effects:{MI:3,GL:-10,EN:-6}},right:{id:"b",label:"Let them recount the votes fairly.",tooltip:"A seat that survives a recount is truly mine.",reveal:"You allow the recount under cameras. You may lose the seat, but the seats you keep are now unassailable, and the gesture buys rare goodwill.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0215",location:"party",arc:"party-t1-a62",stage:0,speaker:"Information Minister",portrait:"official",tags:["history","national-day","narrative"],prompt:"It comes around again, and the margin for error is gone. You can change the school books so they only talk about how amazing your family is and ignore all the other heroes.",left:{id:"a",label:"Change the books to only praise your family.",tooltip:"He who tells the founding owns the nation.",reveal:"The broadcasts crown your lineage as the sole begetter of the republic. Historians wince, rivals' heirs seethe, and the cult deepens by another generation.",effects:{FA:5,MI:2,EN:-10,GL:-6}},right:{id:"b",label:"Tell the honest history about all the heroes.",tooltip:"A nation with one father is an orphan of the rest.",reveal:"You share the credit across the founding generation. The family's mythmakers are disappointed, but the story gains the ring of truth and the nation's buy-in.",effects:{GL:5,EN:5,FA:-10}}},{id:"party-0216",location:"party",arc:"party-t1-a63",stage:0,speaker:"Inspector-General of Police",portrait:"general",tags:["police","recruitment","loyalty"],prompt:"The same demand, but the reign is older and the knives sharper. You are hiring new police. You can only hire people who promise to vote for you, or hire the strongest, smartest people.",left:{id:"a",label:"Only hire people who promise to vote for you.",tooltip:"A force that loves me will never aim at me.",reveal:"Loyalists fill the ranks and the force becomes a praetorian guard. It will protect you faithfully — until the day loyalty to a person costs it the public's last trust.",effects:{MI:6,EN:-10,GL:-6}},right:{id:"b",label:"Hire the strongest and smartest people.",tooltip:"A police that serves the law outlasts the one that serves me.",reveal:"You insist on a professional intake. The new constables answer to the badge, not your name — less pliable, but a force the public might one day respect.",effects:{EN:5,GL:3,MI:-6}}},{id:"party-0217",location:"party",arc:"party-t1-a64",stage:0,speaker:"Intelligence Chief",portrait:"shadow",tags:["cabinet","plot","loyalty"],prompt:"Years deep, the unresolved returns to be resolved for good. Two of your friends are secretly talking to the army about taking your job. You can spy on them secretly, or yell at them right now.",left:{id:"a",label:"Spy on them secretly to stop them.",tooltip:"A plot is best killed in the cradle.",reveal:"You wiretap, gather leverage, and break them with it. The plot dies, but so does trust in your cabinet, where every minister now assumes he too is bugged.",effects:{MI:5,FA:-3,EN:-6,GL:-6}},right:{id:"b",label:"Yell at them right now and demand they be loyal.",tooltip:"Daylight scatters conspirators.",reveal:"You face them down in front of the cabinet. The gamble forces a public reaffirmation of loyalty, and the cabinet sees a leader who fights in the open, not the shadows.",effects:{FA:3,GL:3,EN:2,MI:-6}}},{id:"party-0218",location:"party",arc:"party-t1-a65",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["scandal","family","corruption"],prompt:"The conflict reignites, and the world is watching this time. Someone in your family got caught stealing. You can hide the secret, or let the police arrest them like anyone else.",left:{id:"a",label:"Hide the secret to protect your family.",tooltip:"Blood is not investigated.",reveal:"The file vanishes and the family is shielded. The cover-up leaks in pieces, and 'one law for them' becomes the opposition's favourite chant.",effects:{FA:5,MI:2,GL:-13,EN:-13}},right:{id:"b",label:"Let the police arrest them.",tooltip:"A dynasty above the law is a dynasty without one.",reveal:"You allow the investigation, family or not. The relative is furious and the household tense, but the public sees, astonished, that the rules might apply to everyone.",effects:{GL:6,EN:6,FA:-13,MI:-3}}},{id:"party-0219",location:"party",arc:"party-t1-a66",stage:0,speaker:"Manifesto Committee Chair",portrait:"official",tags:["manifesto","promises","credibility"],prompt:"A familiar crisis, escalated by everything you let slide. You are writing your promises for the election. You can promise crazy, impossible things to get votes, or be honest about what you can actually do.",left:{id:"a",label:"Promise impossible things to win.",tooltip:"A campaign is won on dreams, not spreadsheets.",reveal:"The crowds roar at free electricity and a job for every graduate. You win, then spend the term explaining why the moon is still in the sky.",effects:{MI:3,EN:-6,GL:-6,FI:-3}},right:{id:"b",label:"Be honest and only promise what you can do.",tooltip:"A promise kept is worth ten promises made.",reveal:"You run on what you can actually do. The rallies are less electric, but every pledge you redeem next term compounds into trust.",effects:{EN:5,GL:5,MI:-3}}},{id:"party-0220",location:"party",arc:"party-t1-a67",stage:0,speaker:"Student Wing President",portrait:"fixer",tags:["students","protest","blame"],prompt:"The fault line cracks wider; the decision can no longer wait. Your student helpers beat up peaceful kids on video. They want you to lie and say the peaceful kids started it.",left:{id:"a",label:"Lie and protect your student helpers.",tooltip:"I do not abandon my own to a mob's verdict.",reveal:"You defend the indefensible and the lie collapses on contact with the video. The campuses unite against you, and the wing learns it can attack with impunity.",effects:{MI:3,FA:2,EN:-16,GL:-10}},right:{id:"b",label:"Punish your helpers and say sorry.",tooltip:"A wing that beats students is a liability, not an asset.",reveal:"You suspend the cadres and apologise to the campus. The wing president seethes at the betrayal, but the wider student body, stunned, lowers its guard.",effects:{EN:6,GL:3,MI:-6,FA:-3}}},{id:"party-0221",location:"party",arc:"party-t1-a68",stage:0,speaker:"Elder Statesman",portrait:"official",tags:["dialogue","opposition","reconciliation"],prompt:"Late in the reign, the old question demands a heavier answer. Your enemies offer to stop fighting if you let their friends out of jail and make fairer rules.",left:{id:"a",label:"Say no and keep fighting them.",tooltip:"I do not negotiate with those I have already beaten.",reveal:"You spurn the overture and rule unchallenged on paper. The crisis hardens underground, and the legitimacy gap you could have closed widens instead.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Make a deal and trade rules for peace.",tooltip:"A rival at the table is not a rival in the street.",reveal:"You negotiate, free some activists, and concede real reforms. The hardliners howl betrayal, but the country exhales, and your rule gains a legitimacy force never bought it.",effects:{GL:6,EN:6,MI:-13}}},{id:"party-0222",location:"party",arc:"party-t1-a69",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["congress","rules","control"],prompt:"It returns once more — and this round may be the one remembered. You can change your team's rules so you never have to vote for a leader again, meaning you are the boss forever.",left:{id:"a",label:"Change the rules to be boss forever.",tooltip:"A party that votes on its head invites a coup.",reveal:"The top posts become appointments and dissent within the party dies. You command total control of a machine that no longer argues — or thinks.",effects:{MI:5,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Keep the voting rules to be fair.",tooltip:"A party that cannot choose its own leaders cannot lead a country.",reveal:"You preserve the internal vote. It means occasional surprises and rivals you did not pick, but the party stays a living thing with roots that hold.",effects:{EN:5,GL:3,MI:-6}}},{id:"party-0223",location:"party",arc:"party-t1-a69",stage:1,speaker:"General Secretary",portrait:"fixer",tags:["congress","rules","control"],prompt:"The reckoning circles back, grown teeth in the waiting. A very popular guy on your team might win a vote against your favorite friend. You can kick him out for a fake reason so your friend wins.",left:{id:"a",label:"Kick him out for a fake reason.",tooltip:"A challenge unanswered is a challenge avoided.",reveal:"He is ruled ineligible and the slate passes unopposed. The delegates who backed him go home bitter, and the province cools toward you for a generation.",effects:{MI:3,FA:2,EN:-10,GL:-3}},right:{id:"b",label:"Let everyone vote fairly.",tooltip:"A leader the delegates chose serves stronger than one I imposed.",reveal:"You let the contest run. He may win a post you did not plan to give, but the congress crackles with real life and the province feels seen.",effects:{EN:5,GL:3,FA:-3,MI:-6}}},{id:"party-0224",location:"party",arc:"party-t1-a70",stage:0,speaker:"Legal Affairs Secretary",portrait:"official",tags:["defamation","press","intimidation"],prompt:"Another term, the same antagonist, the stakes raised again. You can file hundreds of fake lawsuits against reporters and enemies to keep them busy and scared in court forever.",left:{id:"a",label:"File the fake lawsuits to scare them.",tooltip:"A man in court has no time to campaign.",reveal:"The critics drown in hearings across the country, exhausted and broke. The tactic is transparent, and 'judicial harassment' becomes the verdict on your rule abroad.",effects:{MI:3,GL:-13,EN:-10}},right:{id:"b",label:"Stop the fake lawsuits.",tooltip:"A law used as a club is no longer a law.",reveal:"You order the suits dropped. Your critics keep their freedom and their venom, but you are spared a reputation as a man who litigates dissent into silence.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0225",location:"party",arc:"party-t1-a70",stage:1,speaker:"Legal Affairs Secretary",portrait:"official",tags:["defamation","press","intimidation"],prompt:"The matter, long deferred, lands with the force of a verdict. One of those fake lawsuits got a young reporter thrown in jail for a long time.",left:{id:"a",label:"Leave her in jail.",tooltip:"To intervene is to admit the suit was mine.",reveal:"You stay out and she stays in. Her detention becomes a cause célèbre, every passing week a fresh indictment of your tolerance for it.",effects:{MI:2,GL:-10,EN:-10}},right:{id:"b",label:"Step in and let her go free.",tooltip:"A jailed reporter is a wound I can still close.",reveal:"You quietly secure her release and rein in the local leader. The base mutters about weakness, but the embarrassment ends and a small debt of goodwill is repaid.",effects:{GL:5,EN:5,MI:-3}}},{id:"party-0226",location:"party",arc:"party-t1-a71",stage:0,speaker:"Delimitation Commissioner",portrait:"official",tags:["gerrymander","constituencies","advantage"],prompt:"Years on and unhealed, the conflict returns to claim its answer. You can redraw the map for the election to trap all your enemies in one area, making it super easy for you to win the rest.",left:{id:"a",label:"Redraw the map to cheat and win.",tooltip:"A map drawn well wins seats before a vote is cast.",reveal:"The new map quietly tilts a dozen seats your way for a generation. The psephologists notice and cry foul, but the lines are set and the advantage banked.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Draw the map fairly for everyone.",tooltip:"A rigged map is a confession printed in ink.",reveal:"You insist on a neutral, population-based redraw. You forgo a structural edge, but the electoral map stops being one more piece of evidence against you.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0227",location:"party",arc:"party-t1-a72",stage:0,speaker:"Administrative Reforms Secretary",portrait:"fixer",tags:["districts","patronage","spending"],prompt:"The same fault line, the harder hour, the narrower path. Local leaders want you to create brand new towns on the map just so they can get new jobs and money.",left:{id:"a",label:"Create the new towns to give them jobs.",tooltip:"A new district is a thousand new favours to grant.",reveal:"You carve out the new districts and the patronage flows. Local bosses are delighted, and the bloated administration becomes one more permanent cost the budget never planned for.",effects:{FA:5,MI:2,FI:-10,EN:-6}},right:{id:"b",label:"Say no to wasting money on fake towns.",tooltip:"I will not buy loyalty by the district.",reveal:"You decline the upgrades. The disappointed local leaders sulk and some turn cold, but the state is spared a fresh layer of offices built purely to be staffed with friends.",effects:{FI:5,GL:2,FA:-10}}},{id:"party-0228",location:"party",arc:"party-t1-a73",stage:0,speaker:"Relief Distribution Coordinator",portrait:"fixer",tags:["patronage","relief-cards","votes"],prompt:"It comes back sharpened by every season you survived. Politicians are only giving free food to people who vote for them, and letting the others starve.",left:{id:"a",label:"Let them keep using food to buy votes.",tooltip:"A card given is a vote owed.",reveal:"The cards stay a tool of loyalty, rewarding your wards and starving the rest. The machine hums, and the genuinely hungry in the wrong wards learn that relief here wears a party colour.",effects:{FA:5,MI:2,EN:-13,GL:-6}},right:{id:"b",label:"Force them to give food fairly to everyone who is hungry.",tooltip:"Hunger does not check a voter card.",reveal:"You strip the cards from the MPs and route them by need. Your local leaders lose a lever and rage, but the relief reaches the poorest regardless of how they vote.",effects:{EN:6,GL:3,FA:-10}}},{id:"party-0229",location:"party",arc:"party-t1-a74",stage:0,speaker:"City Campaign Manager",portrait:"fixer",tags:["city","election","local"],prompt:"A later year of power, the old crisis now a true test of it. Small city elections are happening. You can rig them quietly to make sure you win, or let people vote freely as a test.",left:{id:"a",label:"Rig the elections quietly.",tooltip:"No verdict against me, however small, can stand.",reveal:"You secure the cities the old way. The wins are hollow and the pattern noted, and you blind yourself to how the towns truly feel about you.",effects:{MI:3,GL:-10,EN:-6}},right:{id:"b",label:"Let people vote freely.",tooltip:"A town honestly won tells me where I stand.",reveal:"You let the corporations vote freely. You lose a few mayoralties, but the honest results give you a true map of your support and a credibility the rigged wins never had.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0230",location:"party",arc:"party-t1-a75",stage:0,speaker:"Statistics Bureau Director",portrait:"official",tags:["census","data","manipulation"],prompt:"The unresolved returns, and this time it will not be deferred. You are counting all the people in the country. A helper says you can change the math to favor your towns for more money.",left:{id:"a",label:"Change the math to get more money for your towns.",tooltip:"Numbers serve the state, and I am the state.",reveal:"You tilt the headcounts toward your strongholds. The seats and funds flow your way, and every policy built on the false figures — schools, clinics, rations — is quietly misallocated for a decade.",effects:{MI:5,FI:2,EN:-13,GL:-6}},right:{id:"b",label:"Count the people honestly.",tooltip:"A nation that lies to itself in numbers cannot plan.",reveal:"You demand accurate counts whatever they cost you. Some strongholds shrink on paper and lose seats, but the data the whole state relies on is finally trustworthy.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0231",location:"party",arc:"party-t1-a76",stage:0,speaker:"Liberation Affairs Secretary",portrait:"official",tags:["quota","freedom-fighters","merit"],prompt:"A term later, the same fault line tears open again. A rule gives the best jobs to kids of old war heroes, making normal young people furious. You can keep the rule or change it to be fair.",left:{id:"a",label:"Keep giving the best jobs to the heroes' kids.",tooltip:"The children of those who bled deserve the state they built.",reveal:"You keep the quota intact and honour the founding generation. Your base of veterans' families is loyal, but the merit-starved youth seethe, and the next spark may be larger.",effects:{FA:3,MI:2,EN:-13,GL:-6}},right:{id:"b",label:"Change the rule to be fair to everyone.",tooltip:"A republic staffed by birthright is no republic.",reveal:"You slash the hereditary quota and open posts to merit. The veterans' lobby feels betrayed, but a generation of frustrated youth sees, astonished, that the state heard them.",effects:{EN:6,GL:5,FA:-10,MI:-3}}},{id:"party-0232",location:"party",arc:"party-t1-a77",stage:0,speaker:"Education Affairs Secretary",portrait:"fixer",tags:["students","union","democracy"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. School groups haven't voted for their leaders in years, so your bullies run everything. You can let them vote, but your bullies might lose.",left:{id:"a",label:"Keep the voting stopped so your bullies stay in charge.",tooltip:"An unelected wing is a controlled wing.",reveal:"You leave the campuses to your appointed enforcers. The grip holds, but a generation graduates having never voted, learning democracy as something that happens to other people.",effects:{MI:5,EN:-10,GL:-6}},right:{id:"b",label:"Let the schools vote fairly.",tooltip:"Democracy unlearned on campus is unlearned for life.",reveal:"You bring back the campus vote. Your wing may lose its monopoly to independents and rivals, but the campuses come alive and a generation practises the franchise.",effects:{EN:6,GL:5,MI:-10}}},{id:"party-0233",location:"party",arc:"party-t1-a78",stage:0,speaker:"Religious Outreach Coordinator",portrait:"cleric",tags:["pir","endorsement","rural"],prompt:"A new season of power, an old problem with sharper teeth. A famous religious leader will tell millions of people to vote for you, but only if you give his group a lot of money and ignore their secrets.",left:{id:"a",label:"Give him the money to get the votes.",tooltip:"His word turns out the countryside.",reveal:"You strike the bargain and his followers swing your way. The shrine network fattens on state favour beyond any audit, and you have rented a bloc you do not control.",effects:{MI:5,FA:2,FI:-3,EN:-6}},right:{id:"b",label:"Say no to the secret deal.",tooltip:"A vote bought through a pir is a vote I never truly hold.",reveal:"You pass on the deal. The rural bloc stays unmobilised for you and the pir cools, but you owe no shadowy shrine-empire a debt it will one day call in.",effects:{GL:3,EN:2,MI:-6}}},{id:"party-0234",location:"party",arc:"party-t1-a79",stage:0,speaker:"Labour Wing Organiser",portrait:"people",tags:["tea-garden","labour","wages"],prompt:"The crisis returns, and this time the cabinet is watching. The poor people picking tea want better pay. If you help them, the rich tea farm owners who usually help you will be mad.",left:{id:"a",label:"Side with the rich tea farm owners.",tooltip:"The gardens vote as the owners say.",reveal:"You leave the bonded wage untouched to keep the owners happy. The estates deliver their votes as instructed, and a quarter-million workers stay trapped at a wage from another century.",effects:{FI:2,FA:3,EN:-13}},right:{id:"b",label:"Help the poor tea pickers get better pay.",tooltip:"A bonded vote is no foundation; a freed one is.",reveal:"You back a real wage rise for the garden workers. The owner-donors retaliate with shut wallets, but the workers, stunned to be seen, become a bloc loyal to you and not the estate.",effects:{EN:6,FA:-6,FI:-6}}},{id:"party-0235",location:"party",arc:"party-t1-a80",stage:0,speaker:"Electoral Reform Adviser",portrait:"official",tags:["pr","system","reform"],prompt:"Once more the issue lands on your desk, the stakes higher than before. People want a new voting system that is completely fair. But if it is completely fair, you won't win as easily anymore.",left:{id:"a",label:"Keep the old rules so you keep winning easily.",tooltip:"Why trade a landslide for a coalition?",reveal:"You preserve the system that magnifies your seats. The majorities stay commanding and the small parties shut out, and the gap between your seat count and your vote share stays a standing grievance.",effects:{MI:3,GL:-6,EN:-3}},right:{id:"b",label:"Change to the fair rules.",tooltip:"A parliament that mirrors the vote is the only honest one.",reveal:"You back a shift toward PR. Your dominance shrinks to its real proportion and coalition-building becomes the norm, but parliament finally reflects how the country actually voted.",effects:{GL:5,EN:5,MI:-10}}},{id:"party-0236",location:"party",arc:"party-t1-a81",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["split","faction","discipline"],prompt:"Another year survived, and the reckoning circles back. A big leader on your team is mad and wants to start his own team. You can arrest him to stop him, or give him what he wants so he stays.",left:{id:"a",label:"Arrest him before he leaves.",tooltip:"A breakaway strangled in the cradle never breathes.",reveal:"You expel him and bury him in cases before he can organise. The split is averted by force, and every ambitious leader learns the cost of independent thought.",effects:{MI:5,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Give him what he wants so he stays.",tooltip:"A tent that loses a pole sags everywhere.",reveal:"You meet his demands and keep him inside. Unity holds, but you have shown that a credible threat to leave is the surest way to win concessions from you.",effects:{FA:3,MI:-3,EN:2}}},{id:"party-0237",location:"party",arc:"party-t1-a82",stage:0,speaker:"Coalition Manager",portrait:"official",tags:["alliance","left","ideology"],prompt:"The ground has shifted; the same demand arrives with new menace. A small, smart group wants to join you. They will help you look good, but they want you to be nicer to workers, which will anger your rich friends.",left:{id:"a",label:"Join with them and help the workers.",tooltip:"Their cadres and credibility are worth a tilt.",reveal:"You bring the left in and shift your platform toward labour and land. The donors grumble and some drift, but you gain disciplined organisers and a sheen of conviction.",effects:{EN:5,MI:2,FI:-6,FA:-3}},right:{id:"b",label:"Say no and keep your rich friends happy.",tooltip:"Ideas do not fund campaigns; businessmen do.",reveal:"You pass on the alliance to keep your business backers content. The money stays, but you forgo the street muscle and the credibility, and the left turns its energy against you.",effects:{FI:5,FA:2,EN:-6}}},{id:"party-0238",location:"party",arc:"party-t1-a83",stage:0,speaker:"Tribunal Prosecutor",portrait:"official",tags:["banning","collaborators","1971"],prompt:"History rhymes: the conflict reopens deeper than last time. You can ban an old religious team for bad things they did in a war long ago. It is fair, but it also magically gets rid of your enemies today.",left:{id:"a",label:"Ban the old team forever.",tooltip:"A party born of atrocity forfeits its place.",reveal:"You dissolve the party and its symbol. The base roars at the reckoning, and the opposition loses an ally — but critics note how neatly justice served your politics, and the banned go underground.",effects:{MI:5,FA:2,EN:2,GL:-6}},right:{id:"b",label:"Let them stay and try to beat them by voting.",tooltip:"A martyr-party banned outlives a beaten one.",reveal:"You leave the party legal and fight it at the ballot. It survives to needle you, but you deny it the banner of victimhood and keep the moral high ground over a real reckoning.",effects:{GL:5,EN:2,MI:-6}}},{id:"party-0239",location:"party",arc:"party-t1-a84",stage:0,speaker:"Rural Development Coordinator",portrait:"fixer",tags:["rural-works","patronage","graft"],prompt:"Mid-reign, the old wound is torn afresh. Politicians are stealing the money meant for building village roads. You can take the money away and give it to honest local councils instead.",left:{id:"a",label:"Let the politicians keep handling the money.",tooltip:"An MP without projects to give is an MP without friends.",reveal:"You leave the rural funds with your MPs. They build where it buys loyalty and skim the rest, and the genuinely needy villages with the wrong MP go without.",effects:{FA:5,MI:2,EN:-10,FI:-3}},right:{id:"b",label:"Give the money to honest local councils.",tooltip:"Roads should follow need, not the member's whim.",reveal:"You hand the funds to elected local bodies with audits. The MPs lose a prized lever and resent it, but the works spread by need and the skim shrinks.",effects:{EN:6,GL:3,FA:-10}}},{id:"party-0240",location:"party",arc:"party-t1-a85",stage:0,speaker:"Religious Affairs Secretary",portrait:"cleric",tags:["mosques","imams","influence"],prompt:"The pressure you deferred has come due, larger now. You can pay religious leaders to say nice things about you during their prayers. This tricks people into voting for you.",left:{id:"a",label:"Pay the religious leaders to say nice things.",tooltip:"He who befriends the pulpit befriends the faithful.",reveal:"You fund the imams and stack the committees with loyalists. The Friday sermons soften toward you, and the mosques become one more institution bent to the party's will.",effects:{MI:5,FA:2,EN:-6,GL:-6}},right:{id:"b",label:"Keep religion and politics separate.",tooltip:"A pulpit I own is a pulpit no one believes.",reveal:"You leave the mosque committees free. You forgo the pulpit's quiet endorsement, but the faith keeps a distance from the party that lends its eventual support real weight.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0241",location:"party",arc:"party-t1-a86",stage:0,speaker:"Law Minister",portrait:"official",tags:["sedition","speech","opposition"],prompt:"A later term, and the quarrel has hardened into a test. Protesters made up a funny song making fun of you. You can arrest them and put them in jail for it.",left:{id:"a",label:"Arrest them for making fun of you.",tooltip:"Mockery, unanswered, becomes contempt.",reveal:"You jail the sloganeers and the chant becomes infamous, sung at every rally now in defiance. The heavy hand turns a jingle into a movement and you into its punchline.",effects:{MI:3,FA:2,EN:-13,GL:-10}},right:{id:"b",label:"Laugh at the song and do nothing.",tooltip:"A leader who jails a chant has already lost to it.",reveal:"You wave the mockery away with a joke of your own. The chant loses its charge for want of a martyr, and you look, for once, bigger than your critics.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0242",location:"party",arc:"party-t1-a87",stage:0,speaker:"Justice Reform Adviser",portrait:"official",tags:["truth-commission","reckoning","past"],prompt:"The country has changed, but this fault line has not — only worsened. People want to investigate the old bosses for stealing. If you do, people might want to investigate you someday too.",left:{id:"a",label:"Investigate everything deeply.",tooltip:"A nation that cannot face its past repeats it.",reveal:"You establish a real commission with teeth. The past regime's crimes are aired and victims heard, and you accept that the same mirror may one day be turned on you.",effects:{GL:6,EN:5,MI:-6}},right:{id:"b",label:"Only do a small, safe investigation.",tooltip:"A precedent for digging up the dead is a shovel for my own grave.",reveal:"You permit only a toothless, bounded review. The reckoning is stage-managed, the precedent contained, and the victims learn the truth was never really on offer.",effects:{MI:3,FA:2,EN:-6,GL:-6}}},{id:"party-0243",location:"party",arc:"party-t1-a88",stage:0,speaker:"Election Commission Liaison",portrait:"official",tags:["finance","disclosure","transparency"],prompt:"It returns, as these things do, with the patience gone. A new rule would force you to tell everyone exactly where you get your campaign money. It ruins your secret cash.",left:{id:"a",label:"Stop the rule and keep your money secret.",tooltip:"A war chest examined is a war chest disarmed.",reveal:"You quietly kill the bill. Your funding stays in the dark, and so does everyone's, and the suspicion that elections here are simply bought hardens into common knowledge.",effects:{FI:2,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Agree to the rule and be honest.",tooltip:"Money in daylight buys less than money in shadow.",reveal:"You support the sunlight law. Your own opaque chest faces scrutiny, but the system gains a check it never had, and you can claim a reform your rivals resisted.",effects:{GL:5,EN:5,FI:-6}}},{id:"party-0244",location:"party",arc:"party-t1-a89",stage:0,speaker:"Strategy Director",portrait:"official",tags:["youth","voting-age","franchise"],prompt:"Years on, the matter is no longer private; the press is already circling. You can let young kids vote. But right now, young kids are angry at you and will probably vote for the other team.",left:{id:"a",label:"Let the young kids vote.",tooltip:"A franchise widened is a democracy deepened.",reveal:"You enfranchise the youth despite their coolness toward you. It wins democratic credit at home and abroad, and you have handed the vote to a generation that may use it against you.",effects:{GL:5,EN:5,MI:-6}},right:{id:"b",label:"Do not lower the voting age.",tooltip:"I will not arm a cohort that means to vote me out.",reveal:"You decline the reform. The status quo protects you from a hostile bloc, and the young add 'denied the vote' to a lengthening list of grievances against you.",effects:{MI:2,FI:2,GL:-6,EN:-3}}},{id:"party-0245",location:"party",arc:"party-t1-a90",stage:0,speaker:"Parliamentary Affairs Minister",portrait:"official",tags:["opposition","status","norms"],prompt:"The same knot, retied tighter, lands before you once more. You can give the leader of the enemy team a nice office and treat them with respect, or take everything away to make them look weak.",left:{id:"a",label:"Take everything away to make them look weak.",tooltip:"A rival with a chair is a rival with a stage.",reveal:"You hollow out the opposition leadership's perks and powers. Your rival is diminished, and parliament drifts further from the adversarial democracy it pretends to be.",effects:{MI:3,GL:-6,EN:-6}},right:{id:"b",label:"Treat them with respect.",tooltip:"A loyal opposition is the proof a democracy works.",reveal:"You afford your rival the traditional standing and consultation. It legitimises an adversary, but it also legitimises the whole house, and the maturity is noticed abroad.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0246",location:"party",arc:"party-t1-a91",stage:0,speaker:"Reconciliation Adviser",portrait:"official",tags:["reconciliation","history","wounds"],prompt:"Another monsoon, another return of an argument you cannot end. A long time ago, your team did a very bad thing. You can say sorry and heal people's feelings, or stay quiet like always.",left:{id:"a",label:"Say sorry for the bad thing.",tooltip:"A wound named can finally close.",reveal:"You offer a genuine acknowledgment of the old wrong. The base is uneasy and hardliners furious, but victims long ignored feel seen, and a festering grievance begins, at last, to heal.",effects:{GL:5,EN:5,FA:-6}},right:{id:"b",label:"Stay quiet and ignore it.",tooltip:"An apology is an admission, and admissions are weapons.",reveal:"You let the anniversary pass unmarked. The party is spared an admission, and the unhealed wound goes on poisoning the well between you and those who remember.",effects:{FA:3,MI:2,EN:-10,GL:-6}}},{id:"party-0247",location:"party",arc:"party-t1-a92",stage:0,speaker:"Election Logistics Officer",portrait:"official",tags:["remote","polling","access"],prompt:`Deep into the reign, the issue demands a final-sounding answer. People living far out in the hills mostly vote for your enemies. You can conveniently "forget" to put voting booths near them so they can't vote.`,left:{id:"a",label:"Forget to put voting booths near them.",tooltip:"Why spend a fortune to be voted against?",reveal:"You quietly thin the polling stations in the remote, unfriendly areas. Turnout there collapses for want of access, and the disenfranchisement, once noticed, becomes a quiet scandal.",effects:{MI:2,GL:-6,EN:-10}},right:{id:"b",label:"Spend money to make sure everyone can vote fairly.",tooltip:"A citizen unreachable by the ballot is a citizen abandoned.",reveal:"You pay to reach every char and hill with a polling station. It costs dearly and may not help your numbers, but no Bangladeshi is denied the vote by geography on your watch.",effects:{EN:6,GL:5,FI:-6}}},{id:"party-0248",location:"party",arc:"party-t1-a93",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["bicameral","senate","structure"],prompt:"The reckoning you postponed has matured into a crisis. You can create a special new group of leaders and fill it with your friends. They will make sure no one can ever change your rules.",left:{id:"a",label:"Create the new group and fill it with friends.",tooltip:"A second chamber of friends is a second line of defence.",reveal:"You establish the upper house and pack it with loyalists. It rewards the faithful and checks any unruly future majority, and critics rightly call it a parking lot for cronies.",effects:{FA:5,MI:3,EN:-6,GL:-6}},right:{id:"b",label:"Say no to creating the new group.",tooltip:"A house of cronies is not a check; it is a couch.",reveal:"You decline to build a chamber of appointees. You forgo a tool of patronage and control, but you avoid bolting a permanent crony-park onto the constitution.",effects:{GL:3,EN:3,FA:-10}}},{id:"party-0249",location:"party",arc:"party-t1-a94",stage:0,speaker:"Home Affairs Coordinator",portrait:"people",tags:["violence","compensation","victims"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. Your fans started a fight on voting day and people died. You can investigate honestly and pay the families, or secretly pay a little to hide it.",left:{id:"a",label:"Investigate honestly and pay the families fairly.",tooltip:"Blood spilled at the ballot is the state's debt.",reveal:"You compensate the victims openly and order real investigations, your own cadres included. The party is uneasy at the scrutiny, but the dead are honoured and the violence's authors face daylight.",effects:{EN:6,GL:5,FA:-6}},right:{id:"b",label:"Secretly pay a little to hide it.",tooltip:"A long inquiry only keeps the bodies in the news.",reveal:"You settle a handful of cases discreetly and let the rest fade. The headlines pass, the cadres learn there is no reckoning, and the families of the unacknowledged dead nurse a lasting grievance.",effects:{FA:3,MI:2,EN:-10,GL:-6}}},{id:"party-0250",location:"party",arc:"party-t1-a95",stage:0,speaker:"Campaign Data Director",portrait:"shadow",tags:["data","micro-targeting","consultants"],prompt:"The old fault line widens; this time there is no quiet option. A tricky company wants to spy on everyone's phones to figure out how to brainwash them into voting for you.",left:{id:"a",label:"Hire the tricky company to brainwash people.",tooltip:"The other side will, if I do not.",reveal:"You bring in the dark-arts firm and the targeting sharpens uncannily. It works — until the harvesting leaks, and your campaign becomes the local chapter of a global data-abuse scandal.",effects:{MI:5,FI:-3,GL:-10,EN:-6}},right:{id:"b",label:"Run a normal, honest campaign.",tooltip:"An election won by manipulation is a mandate built on sand.",reveal:"You decline the manipulation machine and campaign on message and organisation. It is harder and slower, but no harvesting time-bomb sits ticking under your win.",effects:{GL:3,EN:3,MI:-3}}},{id:"party-0251",location:"party",arc:"party-t1-a96",stage:0,speaker:"Returning Officer Coordinator",portrait:"fixer",tags:["nominations","scrutiny","disqualification"],prompt:"Time has not healed it — the conflict comes back armed. You can throw away the voting papers for the enemy team just because they missed a comma or spelled a word wrong.",left:{id:"a",label:"Throw away their papers for tiny mistakes.",tooltip:"A candidate disqualified is a contest avoided.",reveal:"Dozens of opposition hopefuls are struck off on trivia. Your candidates walk into emptier races, and the courts and observers log another way the contest was hollowed before polling.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Let them fix the mistakes and play fair.",tooltip:"A ballot thinned by clerks is a ballot no one trusts.",reveal:"You order the officers to accept all proper nominations. The races are fuller and harder, but the contest cannot be dismissed as rigged at the starting line.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0252",location:"party",arc:"party-t1-a97",stage:0,speaker:"Strategy Director",portrait:"official",tags:["snap-election","timing","advantage"],prompt:"Once again, and with the whole house holding its breath. You just did something popular. You can call a surprise election right now to win before people realize the country is running out of money.",left:{id:"a",label:"Call the surprise election right now.",tooltip:"Strike while the numbers smile.",reveal:"You go to the polls on the sugar high and win comfortably. The fresh term is banked, and the soured economy and unpaid giveaway bill land squarely in your own new lap.",effects:{MI:5,FI:-6,EN:-3}},right:{id:"b",label:"Wait until the normal time and face the problems.",tooltip:"A leader who runs from the bill admits he padded it.",reveal:"You hold the scheduled date and govern through the hard patch. You forgo the easy win, but you cannot be accused of cynically timing the vote to dodge the consequences.",effects:{GL:3,EN:2,MI:-6}}},{id:"party-0253",location:"party",arc:"party-t1-a98",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["article-70","dissent","expulsion"],prompt:"The matter resurfaces in a harder year, patience exhausted. One of your teammates voted against a bad rule you made. You can kick him out completely to scare everyone else into obeying.",left:{id:"a",label:"Kick him out completely.",tooltip:"One conscience indulged becomes a chorus.",reveal:"You strip him of his seat for a single honest vote. The benches fall silent and obedient, and the spectacle of a man expelled for conscience stains the parliament's name.",effects:{MI:5,FA:2,EN:-10,GL:-10}},right:{id:"b",label:"Let him disagree this one time.",tooltip:"A parliament of automatons warns me of nothing.",reveal:"You let the conscience vote stand without punishment. The hardliners fret about the precedent, but the benches keep a flicker of humanity and the house a shred of dignity.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0254",location:"party",arc:"party-t1-a99",stage:0,speaker:"Party Elders' Council",portrait:"official",tags:["president","ceremonial","loyalty"],prompt:"A later season of rule, the stakes now openly existential. You get to pick the President. You can pick a yes-man who does whatever you say, or a smart, fair person who might argue with you.",left:{id:"a",label:"Pick the yes-man.",tooltip:"A rubber stamp does not develop a spine at midnight.",reveal:"You elevate a reliable nonentity to the presidency. Every decree is signed on cue, and the one office that might restrain you in a crisis is neutered in advance.",effects:{MI:3,FA:2,GL:-6,EN:-3}},right:{id:"b",label:"Pick the smart, fair person.",tooltip:"A dignified head of state reflects on the whole house.",reveal:"You choose a credible figure for the presidency. He lends the state gravity, and you accept that in a true crisis he might use the office's powers as his own conscience, not yours, dictates.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0255",location:"party",arc:"party-t1-a100",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["merger","absorption","growth"],prompt:"It comes around again, and the margin for error is gone. A small team wants to join yours. They have lots of voters, but they will demand big jobs and cause drama.",left:{id:"a",label:"Let them join your team.",tooltip:"Their region becomes mine overnight.",reveal:"You merge them in and your map fills out in the weak region. Their leaders crowd your benches with new demands and old baggage, and your once-tight organisation grows lumpier.",effects:{MI:5,FA:-3,EN:2}},right:{id:"b",label:"Say no and work hard to get votes yourself.",tooltip:"A merger buys a region and inherits its quarrels.",reveal:"You decline the merger and invest in building your own base there. It is slower and the region stays thin for you, but your party keeps its coherence and owes no newcomers.",effects:{FA:2,MI:-6,FI:-3}}},{id:"party-0256",location:"party",arc:"party-t1-a101",stage:0,speaker:"Manifesto Committee Chair",portrait:"official",tags:["manifesto","leak","damage"],prompt:"The same demand, but the reign is older and the knives sharper. A secret plan to cut people's favorite free things leaked online. You can admit it's true, or lie and say the paper is fake and you changed your mind.",left:{id:"a",label:"Admit it is true.",tooltip:"A policy abandoned at the first leak was never a policy.",reveal:"You defend the subsidy cut openly. The honesty earns grudging respect in some quarters, but the beloved subsidy's defenders mobilise and the issue dogs the whole campaign.",effects:{GL:2,FI:3,EN:-13}},right:{id:"b",label:"Lie and say it was fake.",tooltip:"A leak is a chance to hear the room.",reveal:"You bin the unpopular plan and recast the draft. The flip-flop draws mockery, but the beloved subsidy survives and the campaign's biggest landmine is defused.",effects:{EN:5,GL:-3,FI:-6}}},{id:"party-0257",location:"party",arc:"party-t1-a102",stage:0,speaker:"Field Mobilisation Officer",portrait:"fixer",tags:["turnout","transport","poll-day"],prompt:"Years deep, the unresolved returns to be resolved for good. On voting day, you can send free buses only for the people voting for you, and leave the enemy voters stranded.",left:{id:"a",label:"Send free buses only for your voters.",tooltip:"I move my voters; theirs can walk.",reveal:"Your strongholds turn out in force on free buses while the opposition's wards wait for transport that never comes. The lopsided turnout flatters your win and fools no observer.",effects:{MI:5,GL:-6,EN:-6}},right:{id:"b",label:"Don't send buses, let everyone get there fairly.",tooltip:"A bus that only carries my voters is a thumb on the scale.",reveal:"You either drop the scheme or run it for all. Your raw turnout edge shrinks, but the poll-day logistics give your enemies nothing to point at.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0258",location:"party",arc:"party-t1-a103",stage:0,speaker:"Chief Whip",portrait:"official",tags:["confidence","majority","coalition"],prompt:"The conflict reignites, and the world is watching this time. You are almost losing. You can secretly bribe a few independent politicians to win, or play fair and risk losing your power.",left:{id:"a",label:"Bribe them to win safely.",tooltip:"A government that wins its first vote narrowly never recovers.",reveal:"You purchase the cushion and win comfortably. The bought independents will be back for more all term, and your government is mortgaged to them from its first day.",effects:{MI:5,FA:2,FI:-3,EN:-6}},right:{id:"b",label:"Play fair and risk losing.",tooltip:"A majority I had to buy is a majority I do not have.",reveal:"You take the confidence vote on your honest count and scrape through. Governing the knife-edge is exhausting, but you owe no shadowy independents and the mandate is real.",effects:{GL:3,EN:3,MI:-3}}},{id:"party-0259",location:"party",arc:"party-t1-a104",stage:0,speaker:"Cabinet Secretary",portrait:"general",tags:["emergency","powers","rule"],prompt:'A familiar crisis, escalated by everything you let slide. You can declare a "State of Emergency." This pauses all rules and lets you do whatever you want forever, but everyone will know you are a dictator.',left:{id:"a",label:"Declare a State of Emergency.",tooltip:"Order first; legitimacy can be rebuilt.",reveal:"You suspend rights and rule by decree. The streets fall silent under the clampdown, and the word 'dictator' attaches itself to you in every capital and every history book.",effects:{MI:6,GL:-16,EN:-13}},right:{id:"b",label:"Play by the normal rules, even if it's hard.",tooltip:"A leader who suspends the constitution has already abdicated.",reveal:"You refuse the emergency and ride out the unrest within constitutional bounds. It is harder and more dangerous, but you remain a head of government, not a usurper.",effects:{GL:5,EN:3,MI:-10}}},{id:"party-0260",location:"party",arc:"party-t1-a105",stage:0,speaker:"Professional Wing Coordinator",portrait:"fixer",tags:["bar-association","professionals","capture"],prompt:"The fault line cracks wider; the decision can no longer wait. Doctors and lawyers have their own groups. You can rig their votes so your friends are in charge of them too.",left:{id:"a",label:"Rig their votes so your friends are in charge.",tooltip:"The professions sway the educated; capture them.",reveal:"Your panels sweep the professional bodies on patronage and pressure. The lawyers, doctors, and engineers' associations become party annexes, and their independent voice — and credibility — dies.",effects:{MI:3,FA:2,EN:-6,GL:-6}},right:{id:"b",label:"Let the doctors and lawyers pick their own leaders.",tooltip:"A captured bar defends no one, least of all me.",reveal:"You let the professional bodies run free. They will sometimes pass resolutions against you, but their independence keeps them respected, and a free bar is a check worth having.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0261",location:"party",arc:"party-t1-a106",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["caretaker","judiciary","poll"],prompt:"Late in the reign, the old question demands a heavier answer. You can make sure a friendly judge is the one watching the election so you can't lose.",left:{id:"a",label:"Make sure your friendly judge is watching.",tooltip:"Even a neutral office should hold a friendly face.",reveal:"You quietly time the judicial retirements so your man heads the poll-time authority. The 'neutral' oversight is neutral in name only, and the opposition smells it instantly.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Let the normal, fair judge watch.",tooltip:"A poll umpire I picked is no umpire at all.",reveal:"You leave the succession to run its natural course, friendly or not. You surrender a hidden lever, but the poll-time authority is genuinely impartial and its verdict will be believed.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0262",location:"party",arc:"party-t1-a107",stage:0,speaker:"Media Adviser",portrait:"fixer",tags:["celebrity","endorsement","image"],prompt:"It returns once more — and this round may be the one remembered. A super famous movie star wants to run on your team. He is clueless about laws, but everyone will vote for him because he's famous.",left:{id:"a",label:"Let the clueless movie star run for your team.",tooltip:"Stardust wins seats that policy cannot.",reveal:"The star joins to adoring crowds and wins his seat on charisma. He is a magnet for the young and a liability in the chamber, every gaffe a headline, every absence noted.",effects:{MI:3,EN:2,GL:-3}},right:{id:"b",label:"Let him just cheer for you, but pick someone smart to run.",tooltip:"A famous face is an asset; a famous fool is a cost.",reveal:"You take the star's public backing but steer him away from a seat. You bank the glamour without saddling the benches with a celebrity who cannot legislate.",effects:{GL:2,MI:2,FA:-3}}},{id:"party-0263",location:"party",arc:"party-t1-a108",stage:0,speaker:"Coalition Manager",portrait:"official",tags:["coalition","programme","compromise"],prompt:"The reckoning circles back, grown teeth in the waiting. Your partner teams want opposite things. You can lie to both of them to keep them happy, or pick a side and make one team very angry.",left:{id:"a",label:"Lie to both to keep them happy.",tooltip:"A vague platform offends no partner.",reveal:"You fudge the programme into mush that everyone can sign. The alliance holds for the campaign, then tears itself apart in government over the contradictions you never resolved.",effects:{MI:2,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Pick a side and make clear rules.",tooltip:"A coalition that cannot agree a page cannot govern a country.",reveal:"You hammer out a real, consistent platform, losing a partner or two who cannot accept it. The alliance is smaller but governable, and voters know what it actually stands for.",effects:{GL:3,EN:3,FA:-6,MI:-3}}},{id:"party-0264",location:"party",arc:"party-t1-a109",stage:0,speaker:"Reconciliation Adviser",portrait:"official",tags:["banning","restoration","inclusion"],prompt:"Another term, the same antagonist, the stakes raised again. A group that was banned a long time ago wants to come back and promises to be good.",left:{id:"a",label:"Keep them banned forever.",tooltip:"A banned enemy is a contained enemy.",reveal:"You refuse restoration. The party stays underground, its exclusion a permanent grievance and recruiting tool, and the politics of the banned festers beyond the ballot's reach.",effects:{MI:3,FA:2,EN:-6,GL:-6}},right:{id:"b",label:"Let them come back safely.",tooltip:"A grievance let into the chamber is a grievance out of the streets.",reveal:"You readmit the party on conditions. The hardliners howl about legitimising enemies, but an underground grievance becomes a contestable political force, answerable to voters.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0265",location:"party",arc:"party-t1-a110",stage:0,speaker:"Field Mobilisation Officer",portrait:"people",tags:["turnout","gotv","organisation"],prompt:"The matter, long deferred, lands with the force of a verdict. You can try to get everyone in the country to vote, or only wake up the people who like you and let the others sleep.",left:{id:"a",label:"Only wake up your friends to vote.",tooltip:"I wake my voters and let theirs dream.",reveal:"Your wards turn out heavily while the opposition's stay home, unprodded. The lopsided turnout pads your margins, and the selective mobilisation is one more managed feature of the result.",effects:{MI:5,EN:-3,GL:-3}},right:{id:"b",label:"Try to get everyone in the country to vote.",tooltip:"A high honest turnout is a mandate money cannot buy.",reveal:"You lift turnout everywhere, friend and foe alike. You forgo a turnout edge, but a high, genuine participation gives whatever result emerges a legitimacy nothing else can.",effects:{GL:5,EN:5,MI:-6}}},{id:"party-0266",location:"party",arc:"party-t1-a111",stage:0,speaker:"Local Government Secretary",portrait:"official",tags:["devolution","decentralisation","power"],prompt:"Years on and unhealed, the conflict returns to claim its answer. You can give small towns the money and power to fix their own problems. It helps them, but makes you less powerful.",left:{id:"a",label:"Keep all the power for yourself.",tooltip:"A capital that lets go of the purse lets go of the country.",reveal:"You keep the money and decisions in the centre's fist. Your grip stays tight, and local government remains a hollow shell where accountability and initiative go to die.",effects:{MI:3,EN:-6,GL:-3}},right:{id:"b",label:"Give the towns the money and power to fix things.",tooltip:"A nation governed only from the capital is barely governed.",reveal:"You push genuine money and authority down to elected councils. You loosen your grip and empower some rivals, but governance gets closer to the people and visibly better.",effects:{EN:6,GL:5,MI:-10}}},{id:"party-0267",location:"party",arc:"party-t1-a112",stage:0,speaker:"Culture Minister",portrait:"official",tags:["nationalism","law","speech"],prompt:"The same fault line, the harder hour, the narrower path. You can make a law that anyone who doesn't salute the flag perfectly goes to jail. This is a great excuse to arrest complainers.",left:{id:"a",label:"Make the strict flag law.",tooltip:"The symbols of the nation are above mockery.",reveal:"You criminalise disrespect of the national symbols. Patriots applaud, and the elastic offence becomes a convenient charge to level at any critic who steps out of line.",effects:{MI:3,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Let people show respect however they want.",tooltip:"Forced reverence is no reverence at all.",reveal:"You reject the law. The hardliners grumble that you failed to honour the nation, but you decline a cudgel that would have dressed censorship as patriotism.",effects:{GL:3,EN:3,MI:-3}}},{id:"party-0268",location:"party",arc:"party-t1-a113",stage:0,speaker:"Election Tech Adviser",portrait:"official",tags:["results","transmission","transparency"],prompt:"It comes back sharpened by every season you survived. A new app lets everyone see the votes being counted instantly on their phones. This makes it impossible for you to cheat.",left:{id:"a",label:"Use the app to prove you are fair.",tooltip:"A count the whole country watches is a count it believes.",reveal:"You launch the transparent dashboard. Tampering becomes near-impossible and the result, whatever it is, is trusted — and you have closed off your own machine's options for good.",effects:{GL:6,EN:5,MI:-6}},right:{id:"b",label:"Say no to the app so you can control the numbers.",tooltip:"A dashboard that cannot be managed is a risk I need not take.",reveal:"You stick with the slower official channels. The flexibility to 'reconcile' close seats survives, and so does the public's weary assumption that the count is never quite clean.",effects:{MI:3,GL:-10,EN:-6}}},{id:"party-0269",location:"party",arc:"party-t1-a114",stage:0,speaker:"Education Affairs Secretary",portrait:"cleric",tags:["madrasa","recognition","votes"],prompt:"A later year of power, the old crisis now a true test of it. Religious schools want their easy tests to count the same as hard college tests for getting jobs. If you say yes, they will vote for you.",left:{id:"a",label:"Say yes so they vote for you.",tooltip:"A million graduates and their families are a bloc worth winning.",reveal:"You grant equivalence to the madrasa degrees. The religious bloc swings gratefully behind you, and the secular establishment recoils as the civil service opens to a parallel education it cannot vouch for.",effects:{MI:3,FA:2,EN:-10,GL:-10}},right:{id:"b",label:"Make them take a harder test first to be fair.",tooltip:"Equal recognition demands an equal standard.",reveal:"You offer recognition conditional on bridging courses in core subjects. The bloc is disappointed at the half-measure, but the civil service keeps a baseline and the secularists are mollified.",effects:{GL:3,EN:3,FA:-6,MI:-3}}},{id:"party-0270",location:"party",arc:"party-t1-a115",stage:0,speaker:"Campaign Data Director",portrait:"fixer",tags:["canvassing","data","privacy"],prompt:"The unresolved returns, and this time it will not be deferred. Your helpers can secretly knock on doors and make lists of everyone's secrets and religion to figure out how to trick them.",left:{id:"a",label:"Tell them to make the secret lists.",tooltip:"Knowledge of the voter is power over the vote.",reveal:"Your canvassers compile an intimate map of every household. The targeting grows formidable, and a covert dossier on millions' private lives now sits on a party server, one breach from scandal.",effects:{MI:5,EN:-6,GL:-6}},right:{id:"b",label:"Tell them to just ask for votes normally.",tooltip:"A party that files its citizens is a state I do not want to lead.",reveal:"You canvass for support without building the secret dossier. Your targeting is cruder, but you refuse to assemble a surveillance file on the people you ask to trust you.",effects:{GL:3,EN:3,MI:-3}}},{id:"party-0271",location:"party",arc:"party-t1-a116",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["dissolution","parliament","tactic"],prompt:"A term later, the same fault line tears open again. You can cancel the government early to trick your enemies before they are ready for the election.",left:{id:"a",label:"Cancel early to trick them.",tooltip:"An opponent off-balance is an opponent beaten.",reveal:"You dissolve the house and rush the polls. The disorganised opposition is caught flat-footed, and you wear the charge of gaming the calendar for the win it buys you.",effects:{MI:5,GL:-6,EN:-3}},right:{id:"b",label:"Finish your normal time fairly.",tooltip:"A house cut short for tactics cheapens the next.",reveal:"You let the term run out naturally. The opposition gets time to organise, but you cannot be accused of dissolving democracy's clock whenever it suited you.",effects:{GL:3,EN:2,MI:-6}}},{id:"party-0272",location:"party",arc:"party-t1-a117",stage:0,speaker:"Chief Whip",portrait:"people",tags:["backbench","rebellion","policy"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. Your own team is refusing to vote for a terrible rule you made. You can bully them into voting yes, or listen to them and fix the rule.",left:{id:"a",label:"Bully them into voting yes.",tooltip:"A backbencher's job is to vote, not to think.",reveal:"You whip the bill through over the rebels' objections. It passes, and so does the public anger they warned of, landing on the very MPs you forced to swallow it.",effects:{MI:3,FA:2,EN:-10}},right:{id:"b",label:"Listen to them and fix the rule.",tooltip:"The benches closest to the people often see clearest.",reveal:"You amend the bill to meet the backbenchers' concerns. The cabinet's pride is dented and the bill weakened, but you have averted a doorstep disaster and kept your MPs loyal.",effects:{EN:5,GL:2,MI:-3}}},{id:"party-0273",location:"party",arc:"party-t1-a118",stage:0,speaker:"Party Treasurer",portrait:"official",tags:["donations","corporate","influence"],prompt:"A new season of power, an old problem with sharper teeth. A new rule will limit how much money rich people can give you. This makes things fairer, but you will be much poorer for the election.",left:{id:"a",label:"Stop the rule so you get the rich people's money.",tooltip:"A campaign starved of corporate cash is a campaign that loses.",reveal:"You kill the cap and the corporate money keeps flowing. The war chest stays fat, and the oligarchs' hooks stay deep in your policy, exactly as the reformers feared.",effects:{FI:5,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Agree to the rule to make things fair.",tooltip:"A party owned by donors governs for donors.",reveal:"You support capping and disclosing corporate money. The war chest thins painfully, but you loosen the oligarchs' grip and can credibly claim to have cleaned a corner of the system.",effects:{GL:5,EN:5,FI:-10,FA:-6}}},{id:"party-0274",location:"party",arc:"party-t1-a119",stage:0,speaker:"Information Commissioner",portrait:"official",tags:["rti","transparency","accountability"],prompt:"The crisis returns, and this time the cabinet is watching. A new rule lets any normal person read the government's secret papers. This stops stealing, but means people will see your mistakes.",left:{id:"a",label:"Stop the rule to keep your secrets.",tooltip:"An open file is an open invitation to my enemies.",reveal:"You quietly hollow out the RTI regime with exemptions and delays. The corruption-fighters lose their best tool, and 'a government with something to hide' becomes the obvious reading.",effects:{MI:2,FA:2,EN:-10,GL:-10}},right:{id:"b",label:"Agree to the rule and show the papers.",tooltip:"Sunlight is the cheapest disinfectant a state can buy.",reveal:"You give the RTI law teeth and enforce it. Some embarrassing files surface and ministers squirm, but corruption gets harder and your reform credentials grow real.",effects:{GL:5,EN:5,FA:-6}}},{id:"party-0275",location:"party",arc:"party-t1-a120",stage:0,speaker:"Parliamentary Affairs Minister",portrait:"official",tags:["oversight","committee","audit"],prompt:"Once more the issue lands on your desk, the stakes higher than before. The team checking the government's spending is usually run by your enemies to keep things honest. You can put your friends in charge to hide your stealing.",left:{id:"a",label:"Put your friends in charge of checking the spending.",tooltip:"I will not hand my critics a microphone and my ledgers.",reveal:"You take the chair and stack the committee. Government spending sails through unexamined, and the one institution meant to catch waste and graft is turned into a shield for it.",effects:{MI:3,FA:2,EN:-10,GL:-6}},right:{id:"b",label:"Let your enemies check the spending to be honest.",tooltip:"Spending watched is spending behaved.",reveal:"You honour the convention and let the opposition scrutinise your ledgers. Some uncomfortable findings emerge, but waste is curbed and the house gains a working check.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0276",location:"party",arc:"party-t1-a121",stage:0,speaker:"Returning Officer Coordinator",portrait:"fixer",tags:["postal","service-voters","fraud"],prompt:"Another year survived, and the reckoning circles back. Soldiers voting by mail are easy to trick. You can secretly change all their votes to be for you.",left:{id:"a",label:"Secretly change the soldiers' votes.",tooltip:"The men in uniform vote as the chain suggests.",reveal:"You shepherd the postal votes into a reliable bloc. The numbers help, and the pattern — a service vote that breaks suspiciously one way — is logged by every observer watching.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Count their votes honestly.",tooltip:"A soldier's secret ballot is still a secret ballot.",reveal:"You insist the postal votes be handled openly and freely. You forgo a managed bloc, but you cannot be accused of voting the barracks by proxy.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0277",location:"party",arc:"party-t1-a122",stage:0,speaker:"Coalition Manager",portrait:"fixer",tags:["hung-parliament","kingmaker","deals"],prompt:"The ground has shifted; the same demand arrives with new menace. No one won the election entirely. You can buy a few small teams with giant bags of money to win, or try to run the country carefully with less power.",left:{id:"a",label:"Buy the small teams with money and jobs.",tooltip:"A government formed is a government; how matters later.",reveal:"You assemble the majority by buying the kingmakers wholesale. The cabinet bloats with bought men and their price tags, and your government begins life owing everyone everything.",effects:{MI:5,FA:2,FI:-6,EN:-6}},right:{id:"b",label:"Try to lead carefully with less power.",tooltip:"Better to govern honestly on a knife-edge than to buy a throne.",reveal:"You build a minority government surviving vote by vote. It is precarious and exhausting, but it is not a bazaar, and each policy must be argued and won rather than purchased.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0278",location:"party",arc:"party-t1-a123",stage:0,speaker:"Women's Wing Chief",portrait:"people",tags:["women","reserved-seats","reform"],prompt:"History rhymes: the conflict reopens deeper than last time. Women want to actually be voted into the special seats, instead of you just picking them. If you let them, you can't control who gets the seats.",left:{id:"a",label:"Let the women be voted in fairly.",tooltip:"A seat won is a voice; a seat granted is an echo.",reveal:"You back direct election for the women's seats. You lose dozens of controllable appointments, but a cohort of women MPs arrives with real mandates and real independence.",effects:{EN:6,GL:5,FA:-6,MI:-6}},right:{id:"b",label:"Keep picking the women yourself.",tooltip:"Why give away seats I currently simply assign?",reveal:"You preserve the nomination system. The women's wing is disappointed and the tokenism critique stands, but you keep dozens of safe, loyal seats firmly in your gift.",effects:{MI:3,FA:3,EN:-10,GL:-6}}},{id:"party-0279",location:"party",arc:"party-t1-a124",stage:0,speaker:"Election Logistics Officer",portrait:"shadow",tags:["polling-station","relocation","suppression"],prompt:"Mid-reign, the old wound is torn afresh. You can secretly move the voting boxes in the enemy's towns far away right before the vote, so they can't walk there in time.",left:{id:"a",label:"Move the boxes far away to trick them.",tooltip:"A booth moved is a vote not cast.",reveal:"You scatter the opposition's booths to far-off venues at the last hour. Their turnout sags as planned, and the manoeuvre, once mapped by observers, becomes textbook documented suppression.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Keep the boxes close so everyone can vote.",tooltip:"A voter should not need a map to find democracy.",reveal:"You keep every booth where the voters expect it. You forgo a quiet suppression tactic, but no one can chart a pattern of vanished polling stations in your enemies' wards.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0280",location:"party",arc:"party-t1-a125",stage:0,speaker:"Law Minister",portrait:"official",tags:["election-petition","courts","result"],prompt:"The pressure you deferred has come due, larger now. Your enemies went to court with proof that you cheated. You can tell the judges to throw all the proof in the trash without looking at it.",left:{id:"a",label:"Tell the judges to throw the proof in the trash.",tooltip:"A result reopened is a result undone.",reveal:"Your courts throw out every petition, evidence or not. The seats are safe and the message clear — the bench is yours — and the contested results stay forever disputed.",effects:{MI:5,GL:-13,EN:-10}},right:{id:"b",label:"Let the judges look at the proof fairly.",tooltip:"A seat that survives the court is a seat I truly hold.",reveal:"You let the courts weigh the real cases. You may lose a few seats to honest rulings, but the ones you keep are unassailable and the judiciary keeps a shred of credibility.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0281",location:"party",arc:"party-t1-a126",stage:0,speaker:"Cyber Cell Commander",portrait:"shadow",tags:["deepfake","disinformation","smear"],prompt:"A later term, and the quarrel has hardened into a test. Your computer team made a fake, realistic video of your enemy saying something terrible. You can show it to everyone to ruin her, but it is a lie.",left:{id:"a",label:"Show everyone the fake video.",tooltip:"A lie that wins the day outlives its debunking.",reveal:"You loose the forgery and it rips through the timelines. It may swing the vote before it is exposed, and when it is, the trail back to your cell makes you the story for years.",effects:{MI:3,GL:-13,EN:-13}},right:{id:"b",label:"Do not use the fake video.",tooltip:"A throne won by a forgery rots from the seat up.",reveal:"You kill the operation. You forgo a devastating dirty trick, but you are spared the day a forensic analyst pins the fabrication on your government for all to see.",effects:{GL:5,EN:5,MI:-3}}},{id:"party-0282",location:"party",arc:"party-t1-a127",stage:0,speaker:"Strategy Director",portrait:"official",tags:["by-poll","succession","seat"],prompt:"The country has changed, but this fault line has not — only worsened. An old politician died. You can give his job to his very smart daughter, or to a mindless helper who will just do whatever you say.",left:{id:"a",label:"Give the job to the mindless helper.",tooltip:"A grateful nobody serves better than a proud somebody.",reveal:"You parachute in the controllable outsider. He wins the safe seat and owes you all, and the late MP's daughter — and the constituency that loved her father — turn bitter.",effects:{MI:3,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Give the job to the smart daughter.",tooltip:"Merit and local roots win seats fixers cannot.",reveal:"You give the daughter the nomination on merit. The fixer loses his pawn and grumbles, but the seat is won warmly and the benches gain a leader rather than a placeholder.",effects:{EN:5,GL:3,FA:-3,MI:-3}}},{id:"party-0283",location:"party",arc:"party-t1-a128",stage:0,speaker:"Digital Government Adviser",portrait:"people",tags:["e-governance","services","corruption"],prompt:"It returns, as these things do, with the patience gone. You can use computers so people don't have to pay bribes to government workers anymore. The workers will be very mad they lost their extra money.",left:{id:"a",label:"Use the computers to stop the bribes.",tooltip:"A counter with no clerk has no palm to grease.",reveal:"You force the e-services through against the clerks' sabotage. The petty bribery at a thousand counters withers, citizens save time and money, and you bank a visible, popular win.",effects:{EN:6,GL:5,FI:2,FA:-6}},right:{id:"b",label:"Let the workers keep taking bribes.",tooltip:"Do not pick a fight with a million clerks at once.",reveal:"You let the digital push die quietly to keep the bureaucracy content. The counters stay manned and the palms stay greased, and the citizen keeps paying a small bribe for every stamp.",effects:{FA:3,FI:-3,EN:-10}}},{id:"party-0284",location:"party",arc:"party-t1-a129",stage:0,speaker:"Leader of the House",portrait:"official",tags:["parliament","accountability","norms"],prompt:"Years on, the matter is no longer private; the press is already circling. In meetings, people only ask you fake, easy questions to make you look smart. You can let them ask real, hard questions to prove you are a good leader.",left:{id:"a",label:"Keep only answering the fake, easy questions.",tooltip:"A minister cornered on live television is a wound.",reveal:"You keep the softballs flying. Your ministers are spared embarrassment, and parliament's central ritual of accountability stays a hollow performance everyone sees through.",effects:{MI:2,FA:2,EN:-6,GL:-3}},right:{id:"b",label:"Let them ask real, hard questions.",tooltip:"A minister who can answer hard questions is a minister worth having.",reveal:"You restore genuine question hour. Your weaker ministers flounder under real questioning, but the strong shine, the house comes alive, and accountability stops being a charade.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0285",location:"party",arc:"party-t1-a130",stage:0,speaker:"Labour Wing Secretary",portrait:"people",tags:["unions","affiliation","leverage"],prompt:"The same knot, retied tighter, lands before you once more. You can make the big worker groups join your team. They will vote for you, but you will have to actually give them what they want later.",left:{id:"a",label:"Make them join your team.",tooltip:"Organised labour, organised for me.",reveal:"You affiliate the big unions and gain disciplined muscle. They now expect delivery on wages and conditions, and the day you cannot, their organised power turns squarely against you.",effects:{MI:3,EN:3,FI:-6,FA:-3}},right:{id:"b",label:"Keep them away so you don't owe them anything.",tooltip:"A union in the tent demands the tent's wealth.",reveal:"You keep the unions independent. You forgo their organised turnout, but you are not held hostage to wage demands you may not be able to meet.",effects:{FI:3,MI:-3,EN:-3}}},{id:"party-0286",location:"party",arc:"party-t1-a131",stage:0,speaker:"Civic Education Director",portrait:"people",tags:["voter-education","awareness","turnout"],prompt:"Another monsoon, another return of an argument you cannot end. You can pay to teach people how to spot election cheating. But if they learn, they might catch you cheating.",left:{id:"a",label:"Teach people how to spot cheating.",tooltip:"An informed electorate is a legitimate election.",reveal:"You fund honest voter education. Turnout and confidence rise, and so does the number of citizens who know exactly what an irregularity looks like — a price you accept for a credible vote.",effects:{GL:5,EN:5,MI:-6}},right:{id:"b",label:"Stop the classes so they don't learn.",tooltip:"Why teach the voter to catch me?",reveal:"You quietly defund the programme. The electorate stays hazier on its rights and easier to manage, and the democracy you preside over grows a little thinner and more cynical.",effects:{MI:2,GL:-6,EN:-6}}},{id:"party-0287",location:"party",arc:"party-t1-a132",stage:0,speaker:"General Secretary",portrait:"fixer",tags:["cadres","violence","amnesty"],prompt:"Deep into the reign, the issue demands a final-sounding answer. Many of your helpers beat people up in the past. You can magically erase all their crimes to thank them for helping you.",left:{id:"a",label:"Erase their crimes so they don't go to jail.",tooltip:"I do not abandon the foot-soldiers who carried me.",reveal:"You wipe the cadres' cases clean en masse. Loyalty is rewarded and the machine reassured, and genuine thugs walk free alongside the wronged, impunity stamped a little deeper.",effects:{MI:3,FA:5,EN:-13,GL:-6}},right:{id:"b",label:"Let the judges send the bad ones to jail.",tooltip:"An amnesty for thugs is a licence for the next.",reveal:"You refuse the blanket pardon and let cases proceed individually. The cadres feel betrayed and some desert, but the genuinely innocent are cleared and the guilty face the law.",effects:{GL:5,EN:3,FA:-10}}},{id:"party-0288",location:"party",arc:"party-t1-a133",stage:0,speaker:"Overseas Wing Secretary",portrait:"shadow",tags:["overseas","voting","fraud"],prompt:"The reckoning you postponed has matured into a crisis. Your people in other countries are voting. Since no one is watching, you can easily sneak a bunch of fake votes in for yourself.",left:{id:"a",label:"Sneak in the fake votes.",tooltip:"Distant ballots are the least watched of all.",reveal:"You manufacture margins at the friendly embassies. The diaspora numbers swell suspiciously, and the watchdogs add 'phantom overseas votes' to the dossier on the election.",effects:{MI:3,GL:-10,EN:-6}},right:{id:"b",label:"Keep the faraway voting strictly fair.",tooltip:"A vote cast abroad must be as clean as one cast at home.",reveal:"You insist on full observation of the embassy ballots. You forgo an easy padding, but the diaspora vote becomes a point of pride rather than another asterisk.",effects:{GL:5,EN:2,MI:-6}}},{id:"party-0289",location:"party",arc:"party-t1-a134",stage:0,speaker:"Strategy Director",portrait:"fixer",tags:["independents","spoilers","tactics"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. You can secretly pay fake politicians to run in the election just to confuse people and steal votes from your real enemy.",left:{id:"a",label:"Pay the fake politicians to confuse people.",tooltip:"A split rival is a beaten rival.",reveal:"You bankroll the spoilers and the opposition vote fractures in the target seats. The tactic delivers, and the day a funded 'independent' talks, it confirms every accusation of a rigged field.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Play fair and win on your own.",tooltip:"A manufactured candidate is a confession in waiting.",reveal:"You refuse the spoiler scheme and fight the weak seats straight. You lose some you might have stolen, but no funded fake candidate can ever surface to sink you.",effects:{GL:3,EN:3,MI:-6}}},{id:"party-0290",location:"party",arc:"party-t1-a135",stage:0,speaker:"Constitutional Adviser",portrait:"official",tags:["ombudsman","accountability","graft"],prompt:"The old fault line widens; this time there is no quiet option. The rules say there should be a special policeman who arrests government leaders who steal. No one has ever hired him. You can hire him now.",left:{id:"a",label:"Do not hire him, to keep your leaders safe.",tooltip:"An office uncreated cannot investigate me.",reveal:"You leave the post unfilled, as your predecessors did. The constitutional check stays a dead letter, and the corruption it was meant to catch goes on unmolested.",effects:{FA:2,MI:2,EN:-10,GL:-6}},right:{id:"b",label:"Hire the special policeman to stop the stealing.",tooltip:"A check unfilled for fifty years shames us all.",reveal:"You finally appoint a genuine ombudsman with teeth. Some of your own are caught in its early cases, but you accomplish what no government dared, and the reform is historic.",effects:{GL:6,EN:5,FA:-6,MI:-3}}},{id:"party-0291",location:"party",arc:"party-t1-a136",stage:0,speaker:"Home Affairs Coordinator",portrait:"official",tags:["magistrates","election-day","neutrality"],prompt:"Time has not healed it — the conflict comes back armed. Special judges are driving around on voting day. You can tell them to bully your enemies, or tell them to just keep everyone safe.",left:{id:"a",label:"Tell them to bully your enemies.",tooltip:"Authority on the ground should answer to me.",reveal:"Your magistrates lean on the opposition and overlook your side's tricks. The polls tilt under colour of law, and the partisan use of the bench becomes one more documented stain.",effects:{MI:5,GL:-10,EN:-6}},right:{id:"b",label:"Tell them to just keep everyone safe.",tooltip:"A magistrate with a thumb on the scale poisons the whole poll.",reveal:"You instruct the magistrates to be strictly impartial. They keep order without favour, and the polls run with a fairness your fixers wanted to subvert.",effects:{GL:5,EN:3,MI:-6}}},{id:"party-0292",location:"party",arc:"party-t1-a137",stage:0,speaker:"Electoral Roll Officer",portrait:"shadow",tags:["nid","purge","disenfranchisement"],prompt:"Once again, and with the whole house holding its breath. You can use computers to erase poor people and minorities from the voting list so they can't vote against you.",left:{id:"a",label:"Erase them from the list secretly.",tooltip:"A roll trimmed of my enemies is a roll improved.",reveal:"You scrub the list with a partisan hand, and the poor, the migrant, and the minority find themselves voteless. The disenfranchisement is quiet, deniable, and — once mapped — damning.",effects:{MI:5,GL:-13,EN:-13}},right:{id:"b",label:"Keep the list fair and add anyone who is missing.",tooltip:"A purge that targets the poor is a coup with a database.",reveal:"You clean the roll honestly and run a drive to register the missing. The list loses its phantoms without losing its poor, and the franchise widens rather than narrows.",effects:{GL:5,EN:6,MI:-6}}},{id:"party-0293",location:"party",arc:"party-t1-a138",stage:0,speaker:"Youth Wing Coordinator",portrait:"people",tags:["youth","outreach","spending"],prompt:"The matter resurfaces in a harder year, patience exhausted. Young people are very angry at you. You can throw a giant, expensive festival with concerts to trick them into liking you again.",left:{id:"a",label:"Throw the giant, expensive festival.",tooltip:"A bridge to the young is worth its price in taka.",reveal:"You bankroll the festival and reach a generation that had written you off. It is costly and some sneer at the gloss, but the outreach softens the youth's hostility a little.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Save the money and skip the festival.",tooltip:"A concert does not undo a killing.",reveal:"You decline the spending as hollow. The treasury is spared, but the alienated youth see no gesture at all, and the generational rift hardens another notch.",effects:{FI:3,EN:-10,GL:-3}}},{id:"party-0294",location:"party",arc:"party-t1-a139",stage:0,speaker:"Parliamentary Affairs Minister",portrait:"official",tags:["privilege","press","intimidation"],prompt:"A later season of rule, the stakes now openly existential. Your friend wants to drag a news reporter into a scary government meeting to yell at him for writing a mean story.",left:{id:"a",label:"Let your friend drag the reporter in.",tooltip:"The dignity of the house must be defended.",reveal:"You let the house summon and censure the journalist. The press gallery gets the message and softens, and parliament adds 'cudgel against reporters' to its repertoire.",effects:{MI:3,FA:2,EN:-10,GL:-10}},right:{id:"b",label:"Stop your friend and let the reporter be.",tooltip:"A parliament that bullies the press fears it.",reveal:"You kill the privilege motion. The thin-skinned MP fumes, but the press keeps its independence and you are spared a needless fight with the entire media.",effects:{GL:5,EN:3,MI:-3}}},{id:"party-0295",location:"party",arc:"party-t1-a140",stage:0,speaker:"Cabinet Secretary",portrait:"official",tags:["ministers","conduct","accountability"],prompt:"It comes around again, and the margin for error is gone. Your leaders are obviously stealing money. You can force them to show their bank accounts and fire the thieves.",left:{id:"a",label:"Force them to show their accounts and fire them.",tooltip:"A cabinet of looters is a scandal with portfolios.",reveal:"You impose asset declarations and enforce resignations. A few loyal grandees fall and the cabinet trembles, but the public sees, astonished, that office is no longer a licence to loot.",effects:{GL:5,EN:6,FA:-10,MI:-3}},right:{id:"b",label:"Ignore it and let them keep stealing.",tooltip:"A loyal grandee's loyalty is bought with a free hand.",reveal:"You decline to bind your ministers. They stay loyal and enriched, and 'one law for them' becomes the defining grievance of your government.",effects:{FA:5,MI:2,EN:-13,GL:-6}}},{id:"party-0296",location:"party",arc:"party-t1-a141",stage:0,speaker:"Chief Whip",portrait:"fixer",tags:["president","cross-voting","discipline"],prompt:"The same demand, but the reign is older and the knives sharper. You are voting for the President. Some of your friends want to vote for the wrong person as a joke. You can threaten them so they don't.",left:{id:"a",label:"Threaten them so they vote for your person.",tooltip:"A secret ballot is no excuse for disloyalty.",reveal:"You lean hard on the waverers and your candidate wins clean. The dissent is suppressed, but you have learned nothing about the discontent that prompted it, and it festers unspoken.",effects:{MI:3,FA:2,EN:-6}},right:{id:"b",label:"Let them vote in secret without threats.",tooltip:"A warning shot heard is a rebellion averted.",reveal:"You let the MPs vote freely and read the bruised result as the message it is. Your candidate squeaks in, and you act on the discontent before it grows into something you cannot whip.",effects:{GL:2,EN:3,FA:-3,MI:-3}}},{id:"party-0297",location:"party",arc:"party-t1-a142",stage:0,speaker:"General Secretary",portrait:"official",tags:["reshuffle","cabinet","balance"],prompt:"Years deep, the unresolved returns to be resolved for good. You have to switch your helpers around. You can pick the helpers who are dumb but loyal, or the very smart ones who might try to take your job.",left:{id:"a",label:"Pick the dumb, loyal helpers.",tooltip:"A loyal fool never sharpens a knife for me.",reveal:"You keep the faithful and the mediocre in post. The cabinet is safe and pliant, and the country is governed by people chosen for their harmlessness rather than their skill.",effects:{MI:2,FA:5,EN:-10,GL:-6}},right:{id:"b",label:"Pick the very smart helpers.",tooltip:"A government that cannot govern is loyal to nothing.",reveal:"You promote the capable, ambition and all. Governance sharpens and the public notices, and you accept the risk that one of your talents may grow large enough to threaten you.",effects:{EN:5,GL:5,FA:-10,MI:-3}}},{id:"party-0298",location:"party",arc:"party-t1-a143",stage:0,speaker:"Strategy Director",portrait:"official",tags:["referendum","legitimacy","gamble"],prompt:`The conflict reignites, and the world is watching this time. People don't believe you won fairly. You can ask the whole country to vote "Yes" or "No" on if they want you to stay. It's a huge gamble.`,left:{id:"a",label:'Ask the country to vote "Yes" or "No".',tooltip:"A fresh mandate silences every whisper.",reveal:"You put your rule to the people. It is a genuine gamble, and the campaign consumes the country; whatever the result, you have staked your legitimacy on a single roll of the dice.",effects:{GL:3,EN:2,MI:-3}},right:{id:"b",label:"Don't take the risk.",tooltip:"A vote I might lose is a weapon I hand my enemies.",reveal:"You decline the plebiscite. You keep the doubts unresolved rather than risk a public verdict, and the legitimacy question goes on quietly eating at your authority.",effects:{MI:3,GL:-3,EN:-3}}},{id:"party-0299",location:"party",arc:"party-t1-a143",stage:1,speaker:"Strategy Director",portrait:"official",tags:["referendum","legitimacy","gamble"],prompt:'A familiar crisis, escalated by everything you let slide. You did the "Yes" or "No" vote, but hardly anyone showed up, and the numbers are obviously fake.',left:{id:"a",label:"Brag loudly that everyone loves you.",tooltip:"A win is a win; let the doubters choke on it.",reveal:"You proclaim the implausible result a ringing endorsement. Your base cheers, but no one outside it believes a 98 percent on a 30 percent turnout, and the 'vindication' becomes a punchline.",effects:{MI:3,FA:2,GL:-13,EN:-10}},right:{id:"b",label:"Admit the vote was messy and calm down.",tooltip:"A boast no one believes is worse than silence.",reveal:"You acknowledge the weak turnout and claim only a modest mandate. The base wanted triumphalism, but the candour spares you the ridicule and salvages a sliver of credibility.",effects:{GL:3,EN:3,FA:-6,MI:-3}}},{id:"party-0300",location:"party",arc:"party-t1-a143",stage:2,speaker:"Strategy Director",portrait:"official",tags:["referendum","legitimacy","gamble"],prompt:"The fault line cracks wider; the decision can no longer wait. Because of the messy vote, your enemies demand a totally fair, watched election. If you say yes, you might lose your job.",left:{id:"a",label:"Ignore them and stay the boss.",tooltip:"I have had my plebiscite; I owe them no more.",reveal:"You refuse the clean election and hide behind the tainted referendum. The opposition's demand hardens into a movement, and your legitimacy gap, papered over, widens beneath the paper.",effects:{MI:3,GL:-13,EN:-10}},right:{id:"b",label:"Agree to the totally fair election.",tooltip:"Only a real vote ends a real doubt.",reveal:"You agree to the genuine, observed election. The hardliners call it surrender, but you gamble that a clean mandate, even a narrow one, is worth more than a hollow one defended forever.",effects:{GL:6,EN:5,MI:-13}}}];export{e as p};
